AUTOMATION_TARGET_PARAMETERS: Dict[str, List[str]] = {
    "articulation": ["mouth_open", "tongue_height", "tongue_frontness", "lip_rounding", "nasal_open"],
    "voice_box": ["breathiness", "rasp", "glottal_closure", "vocal_fold_tension"],
    "resonance": ["resonance_depth", "brightness", "darkness", "nasal_coupling"],
    "expression": ["accentuation_db", "timing_bias", "pitch_bias_cents"],
}
AUTOMATION_TARGET_TO_LANE: Dict[str, str] = {
    target: lane for lane, targets in AUTOMATION_TARGET_PARAMETERS.items() for target in targets
}
AUTOMATION_CURVES = ["linear", "hold", "smooth"]
AUTOMATION_DEFAULT_COLORS = ["#ffd166", "#5cdb95", "#24d7ff", "#f1c0e8", "#d7b9ff", "#ffadad"]
TIMELINE_TRACK_KINDS = ["automation", "pitch", "stress", "musical_grid", "marker"]
TIMELINE_BRIDGE_PREFIXES = ("stress_bridge_", "pitch_bridge_")
PERFORMANCE_TIMING_TRANSACTION_COALESCE_SECONDS = 0.75
TIMELINE_SAFE_VALUE_RANGES: Dict[str, Tuple[float, float]] = {
    "accentuation_db": (-24.0, 24.0),
    "pitch_bias_cents": (-1200.0, 1200.0),
    "timing_bias": (-1.0, 1.0),
    "normalized_articulation": (0.0, 1.0),
    "normalized_voice_box": (0.0, 1.0),
    "normalized_resonance": (0.0, 1.0),
}


def _is_timeline_bridge_track_id(track_id: str | None) -> bool:
    return str(track_id or "").startswith(TIMELINE_BRIDGE_PREFIXES)


def _deduplicated_timeline_tracks(tracks: List["TimelineParameterTrack"] | None) -> List["TimelineParameterTrack"]:
    deduped_by_id: Dict[str, TimelineParameterTrack] = {}
    for track in tracks or []:
        track_obj = track if isinstance(track, TimelineParameterTrack) else TimelineParameterTrack.from_json_dict(track)
        deduped_by_id[track_obj.track_id] = track_obj
    return sorted(deduped_by_id.values(), key=lambda item: item.lane_order)


def _timeline_value_range(target_parameter: str, track_kind: str = "automation") -> Tuple[float, float]:
    target = str(target_parameter or "")
    if target in TIMELINE_SAFE_VALUE_RANGES:
        return TIMELINE_SAFE_VALUE_RANGES[target]
    if target in AUTOMATION_TARGET_PARAMETERS.get("articulation", []):
        return TIMELINE_SAFE_VALUE_RANGES["normalized_articulation"]
    if target in AUTOMATION_TARGET_PARAMETERS.get("voice_box", []):
        return TIMELINE_SAFE_VALUE_RANGES["normalized_voice_box"]
    if target in AUTOMATION_TARGET_PARAMETERS.get("resonance", []):
        return TIMELINE_SAFE_VALUE_RANGES["normalized_resonance"]
    if track_kind == "stress":
        return (0.0, 1.0)
    if track_kind == "pitch":
        return (40.0, 2000.0)
    return (-1.0, 1.0)


@dataclass
class TimelineParameterPoint:
    """Canonical JSON-safe performance timeline point."""

    time_ms: int = 0
    value: float = 0.0
    curve: str = "linear"
    label: str = ""
    metadata: Dict[str, object] = field(default_factory=dict)

    def __post_init__(self) -> None:
        self.time_ms = int(max(0, round(float(self.time_ms))))
        self.value = float(self.value)
        if self.curve not in AUTOMATION_CURVES:
            self.curve = "linear"
        self.label = str(self.label or "")
        self.metadata = dict(self.metadata or {})

    def to_json_dict(self) -> Dict[str, object]:
        return {
            "time_ms": int(self.time_ms),
            "value": float(self.value),
            "curve": self.curve,
            "label": self.label,
            "metadata": dict(self.metadata),
        }

    @classmethod
    def from_json_dict(cls, data: Dict[str, object]) -> "TimelineParameterPoint":
        return cls(
            time_ms=int(float(data.get("time_ms", 0) or 0)),
            value=float(data.get("value", 0.0) or 0.0),
            curve=str(data.get("curve", "linear") or "linear"),
            label=str(data.get("label", "") or ""),
            metadata=dict(data.get("metadata", {}) or {}) if isinstance(data.get("metadata", {}), dict) else {},
        )

    def to_automation_point(self) -> "AutomationPoint":
        return AutomationPoint(time_ms=self.time_ms, value=self.value, curve=self.curve)


@dataclass
class TimelineParameterTrack:
    """Canonical time-based performance lane for automation, pitch, stress, grid, and marker data."""

    track_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    name: str = "Accentuation"
    track_kind: str = "automation"
    target_parameter: str = "accentuation_db"
    points: List[TimelineParameterPoint] = field(default_factory=list)
    muted: bool = False
    visible: bool = True
    color: str = "#ffd166"
    lane_order: int = 0

    def __post_init__(self) -> None:
        self.track_id = str(self.track_id or uuid.uuid4())
        self.name = str(self.name or self.target_parameter or "Timeline Track")
        self.track_kind = str(self.track_kind or "automation")
        if self.track_kind not in TIMELINE_TRACK_KINDS:
            self.track_kind = "automation"
        self.target_parameter = str(self.target_parameter or "accentuation_db")
        self.points = sorted([p if isinstance(p, TimelineParameterPoint) else TimelineParameterPoint.from_json_dict(p) for p in self.points], key=lambda p: p.time_ms)
        self.muted = bool(self.muted)
        self.visible = bool(self.visible)
        self.color = str(self.color or "#ffd166")
        self.lane_order = int(self.lane_order or 0)

    def to_json_dict(self) -> Dict[str, object]:
        return {
            "track_id": self.track_id,
            "name": self.name,
            "track_kind": self.track_kind,
            "target_parameter": self.target_parameter,
            "points": [point.to_json_dict() for point in self.points],
            "muted": self.muted,
            "visible": self.visible,
            "color": self.color,
            "lane_order": int(self.lane_order),
        }

    @classmethod
    def from_json_dict(cls, data: Dict[str, object]) -> "TimelineParameterTrack":
        return cls(
            track_id=str(data.get("track_id") or uuid.uuid4()),
            name=str(data.get("name", "Timeline Track") or "Timeline Track"),
            track_kind=str(data.get("track_kind", "automation") or "automation"),
            target_parameter=str(data.get("target_parameter", "accentuation_db") or "accentuation_db"),
            points=[TimelineParameterPoint.from_json_dict(item) for item in data.get("points", []) if isinstance(item, dict)] if isinstance(data.get("points", []), list) else [],
            muted=bool(data.get("muted", False)),
            visible=bool(data.get("visible", True)),
            color=str(data.get("color", "#ffd166") or "#ffd166"),
            lane_order=int(data.get("lane_order", 0) or 0),
        )

    @classmethod
    def from_automation_track(cls, track: "AutomationTrack", lane_order: int = 0) -> "TimelineParameterTrack":
        return cls(
            track_id=track.track_id,
            name=track.name,
            track_kind="automation",
            target_parameter=track.target_parameter,
            points=[TimelineParameterPoint(time_ms=point.time_ms, value=point.value, curve=point.curve) for point in track.points],
            muted=track.muted,
            visible=track.visible,
            color=track.color,
            lane_order=lane_order,
        )

    def to_automation_track(self) -> "AutomationTrack":
        return AutomationTrack(
            track_id=self.track_id,
            name=self.name,
            target_parameter=self.target_parameter,
            lane_type=AUTOMATION_TARGET_TO_LANE.get(self.target_parameter, "expression"),
            points=[point.to_automation_point() for point in self.points],
            muted=self.muted,
            visible=self.visible,
            color=self.color,
        )


@dataclass
class TimelineSegment:
    """Runtime segment spanning two timeline points."""

    start_ms: float = 0.0
    end_ms: float = 0.0
    start_value: float = 0.0
    end_value: float = 0.0
    curve: str = "linear"


@dataclass
class CompiledTimelineTrack:
    """Cacheable runtime representation of a TimelineParameterTrack."""

    track_id: str = ""
    target_parameter: str = "accentuation_db"
    track_kind: str = "automation"
    muted: bool = False
    points: List[TimelineParameterPoint] = field(default_factory=list)
    segments: List[TimelineSegment] = field(default_factory=list)
    value_range: Tuple[float, float] = (-1.0, 1.0)
    source_hash: str = ""


_TIMELINE_TRACK_COMPILE_CACHE: Dict[Tuple[str, str], CompiledTimelineTrack] = {}
_AUTOMATION_ENVELOPE_CACHE: "OrderedDict[Tuple[str, int, int, str], np.ndarray]" = OrderedDict()
_AUTOMATION_ENVELOPE_CACHE_BYTES = 0
_AUTOMATION_ENVELOPE_CACHE_MAX_BYTES = 24 * 1024 * 1024
_AUTOMATION_ENVELOPE_CACHE_MAX_ENTRIES = 16
_AUTOMATION_RUNTIME_DIAGNOSTICS: Dict[str, object] = {
    "compiled_track_count": 0,
    "active_compiled_track_count": 0,
    "envelope_cache_hits": 0,
    "envelope_cache_misses": 0,
    "envelope_generation_ms": 0.0,
    "timeline_tracks_hash": "",
    "automation_runtime_backend": "compiled_segments",
}


def _normalize_automation_curve(curve: str) -> str:
    curve = str(curve or "linear").lower()
    return curve if curve in AUTOMATION_CURVES else "linear"


def _timeline_track_source_dict(track: "TimelineParameterTrack") -> Dict[str, object]:
    """Stable runtime source for hashing; visible is UI-only and intentionally excluded."""
    return {
        "track_id": str(getattr(track, "track_id", "") or ""),
        "target_parameter": str(getattr(track, "target_parameter", "") or ""),
        "track_kind": str(getattr(track, "track_kind", "automation") or "automation"),
        "muted": bool(getattr(track, "muted", False)),
        "points": [
            {
                "time_ms": int(point.time_ms),
                "value": float(point.value),
                "curve": _normalize_automation_curve(point.curve),
            }
            for point in _sorted_timeline_points(track)
        ],
    }


def timeline_track_source_hash(track: "TimelineParameterTrack") -> str:
    payload = json.dumps(_timeline_track_source_dict(track), sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(payload.encode("utf-8")).hexdigest()


def timeline_tracks_hash(tracks: List["TimelineParameterTrack"] | None) -> str:
    payload = [
        _timeline_track_source_dict(track)
        for track in sorted(list(tracks or []), key=lambda item: (str(getattr(item, "track_id", "")), int(getattr(item, "lane_order", 0) or 0)))
    ]
    encoded = json.dumps(payload, sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(encoded.encode("utf-8")).hexdigest()


def compile_timeline_track(track: "TimelineParameterTrack") -> CompiledTimelineTrack:
    source_hash = timeline_track_source_hash(track)
    cache_key = (str(getattr(track, "track_id", "") or ""), source_hash)
    cached = _TIMELINE_TRACK_COMPILE_CACHE.get(cache_key)
    if cached is not None:
        return cached
    low, high = _timeline_value_range(getattr(track, "target_parameter", ""), getattr(track, "track_kind", "automation"))
    points = []
    for point in _sorted_timeline_points(track):
        points.append(
            TimelineParameterPoint(
                time_ms=point.time_ms,
                value=float(point.value),
                curve=_normalize_automation_curve(point.curve),
                label=point.label,
                metadata=dict(point.metadata),
            )
        )
    segments = [
        TimelineSegment(
            start_ms=float(left.time_ms),
            end_ms=float(right.time_ms),
            start_value=float(left.value),
            end_value=float(right.value),
            curve=_normalize_automation_curve(left.curve),
        )
        for left, right in zip(points, points[1:])
    ]
    compiled = CompiledTimelineTrack(
        track_id=str(getattr(track, "track_id", "") or ""),
        target_parameter=str(getattr(track, "target_parameter", "accentuation_db") or "accentuation_db"),
        track_kind=str(getattr(track, "track_kind", "automation") or "automation"),
        muted=bool(getattr(track, "muted", False)),
        points=points,
        segments=segments,
        value_range=(float(low), float(high)),
        source_hash=source_hash,
    )
    stale_keys = [key for key in _TIMELINE_TRACK_COMPILE_CACHE if key[0] == compiled.track_id and key != cache_key]
    for key in stale_keys:
        _TIMELINE_TRACK_COMPILE_CACHE.pop(key, None)
    _TIMELINE_TRACK_COMPILE_CACHE[cache_key] = compiled
    return compiled


def compiled_timeline_tracks(tracks: List["TimelineParameterTrack"] | None) -> List[CompiledTimelineTrack]:
    compiled = [compile_timeline_track(track) for track in (tracks or [])]
    _AUTOMATION_RUNTIME_DIAGNOSTICS["compiled_track_count"] = len(compiled)
    _AUTOMATION_RUNTIME_DIAGNOSTICS["active_compiled_track_count"] = len([track for track in compiled if not track.muted and track.points])
    _AUTOMATION_RUNTIME_DIAGNOSTICS["timeline_tracks_hash"] = timeline_tracks_hash(tracks)
    _AUTOMATION_RUNTIME_DIAGNOSTICS["automation_runtime_backend"] = "compiled_segments"
    return compiled


def evaluate_compiled_track(compiled_track: CompiledTimelineTrack, time_ms: float) -> float | None:
    if compiled_track is None or compiled_track.muted or not compiled_track.points:
        return None
    sample_ms = float(max(0.0, float(time_ms)))
    points = compiled_track.points
    low, high = compiled_track.value_range
    if sample_ms < float(points[0].time_ms):
        return None
    if len(points) == 1 or sample_ms >= float(points[-1].time_ms):
        return float(np.clip(points[-1].value, low, high))
    starts = [segment.start_ms for segment in compiled_track.segments]
    index = max(0, min(len(compiled_track.segments) - 1, bisect.bisect_right(starts, sample_ms) - 1))
    segment = compiled_track.segments[index]
    if sample_ms < segment.start_ms:
        return None
    if sample_ms > segment.end_ms:
        return float(np.clip(points[-1].value, low, high))
    if segment.curve == "hold" or segment.end_ms <= segment.start_ms:
        return float(np.clip(segment.start_value, low, high))
    ratio = float(np.clip((sample_ms - segment.start_ms) / max(1.0, segment.end_ms - segment.start_ms), 0.0, 1.0))
    if segment.curve == "smooth":
        ratio = ratio * ratio * (3.0 - 2.0 * ratio)
    value = segment.start_value + (segment.end_value - segment.start_value) * ratio
    return float(np.clip(value, low, high))


def _compiled_track_envelope(compiled: CompiledTimelineTrack, time_ms: np.ndarray) -> np.ndarray:
    frame_count = len(time_ms)
    values = np.zeros(frame_count, dtype=np.float32)
    if compiled.muted or not compiled.points or frame_count <= 0:
        return values
    points = compiled.points
    active = time_ms >= float(points[0].time_ms)
    if not np.any(active):
        return values
    if len(points) == 1:
        values[active] = float(np.clip(points[0].value, *compiled.value_range))
        return values
    for segment in compiled.segments:
        mask = (time_ms >= segment.start_ms) & (time_ms <= segment.end_ms)
        if not np.any(mask):
            continue
        if segment.curve == "hold" or segment.end_ms <= segment.start_ms:
            values[mask] = float(np.clip(segment.start_value, *compiled.value_range))
        else:
            ratio = np.clip((time_ms[mask] - segment.start_ms) / max(1.0, segment.end_ms - segment.start_ms), 0.0, 1.0)
            if segment.curve == "smooth":
                ratio = ratio * ratio * (3.0 - 2.0 * ratio)
            values[mask] = (segment.start_value + (segment.end_value - segment.start_value) * ratio).astype(np.float32)
    values[time_ms > float(points[-1].time_ms)] = float(np.clip(points[-1].value, *compiled.value_range))
    return np.clip(values, compiled.value_range[0], compiled.value_range[1]).astype(np.float32)


def _store_envelope_cache(cache_key: Tuple[str, int, int, str], envelope: np.ndarray) -> None:
    global _AUTOMATION_ENVELOPE_CACHE_BYTES
    if envelope.nbytes > _AUTOMATION_ENVELOPE_CACHE_MAX_BYTES // 2:
        return
    previous = _AUTOMATION_ENVELOPE_CACHE.pop(cache_key, None)
    if previous is not None:
        _AUTOMATION_ENVELOPE_CACHE_BYTES -= int(previous.nbytes)
    _AUTOMATION_ENVELOPE_CACHE[cache_key] = envelope.copy()
    _AUTOMATION_ENVELOPE_CACHE_BYTES += int(envelope.nbytes)
    while _AUTOMATION_ENVELOPE_CACHE and (
        len(_AUTOMATION_ENVELOPE_CACHE) > _AUTOMATION_ENVELOPE_CACHE_MAX_ENTRIES
        or _AUTOMATION_ENVELOPE_CACHE_BYTES > _AUTOMATION_ENVELOPE_CACHE_MAX_BYTES
    ):
        _old_key, old_value = _AUTOMATION_ENVELOPE_CACHE.popitem(last=False)
        _AUTOMATION_ENVELOPE_CACHE_BYTES -= int(old_value.nbytes)


def clear_automation_envelope_cache() -> None:
    global _AUTOMATION_ENVELOPE_CACHE_BYTES
    _AUTOMATION_ENVELOPE_CACHE.clear()
    _AUTOMATION_ENVELOPE_CACHE_BYTES = 0


def automation_runtime_diagnostics() -> Dict[str, object]:
    diagnostics = dict(_AUTOMATION_RUNTIME_DIAGNOSTICS)
    diagnostics["envelope_cache_entries"] = len(_AUTOMATION_ENVELOPE_CACHE)
    diagnostics["envelope_cache_bytes"] = int(_AUTOMATION_ENVELOPE_CACHE_BYTES)
    return diagnostics


def compiled_envelope_for_parameter(parameter: str, duration_ms: float, sample_rate: int, tracks: List["TimelineParameterTrack"] | None = None) -> np.ndarray:
    frame_count = max(0, int(math.ceil(max(0.0, float(duration_ms)) * float(sample_rate) / 1000.0)))
    if frame_count <= 0:
        return np.zeros(0, dtype=np.float32)
    tracks_hash = timeline_tracks_hash(tracks)
    _AUTOMATION_RUNTIME_DIAGNOSTICS["timeline_tracks_hash"] = tracks_hash
    cache_key = (str(parameter or ""), int(round(float(duration_ms))), int(sample_rate), tracks_hash)
    cached = _AUTOMATION_ENVELOPE_CACHE.get(cache_key)
    if cached is not None and len(cached) == frame_count:
        _AUTOMATION_ENVELOPE_CACHE.move_to_end(cache_key)
        _AUTOMATION_RUNTIME_DIAGNOSTICS["envelope_cache_hits"] = int(_AUTOMATION_RUNTIME_DIAGNOSTICS.get("envelope_cache_hits", 0)) + 1
        return cached.copy()
    _AUTOMATION_RUNTIME_DIAGNOSTICS["envelope_cache_misses"] = int(_AUTOMATION_RUNTIME_DIAGNOSTICS.get("envelope_cache_misses", 0)) + 1
    started = time.perf_counter()
    time_ms = (np.arange(frame_count, dtype=np.float32) * 1000.0) / float(sample_rate)
    envelope = np.zeros(frame_count, dtype=np.float32)
    compiled_tracks = compiled_timeline_tracks(tracks)
    for compiled in compiled_tracks:
        if compiled.track_kind != "automation" or compiled.target_parameter != parameter:
            continue
        envelope += _compiled_track_envelope(compiled, time_ms)
    low, high = _timeline_value_range(parameter, "automation")
    envelope = np.clip(envelope, low, high).astype(np.float32)
    _AUTOMATION_RUNTIME_DIAGNOSTICS["envelope_generation_ms"] = round((time.perf_counter() - started) * 1000.0, 3)
    _store_envelope_cache(cache_key, envelope)
    return envelope.copy()


def _clamped_timeline_point_value(track: "TimelineParameterTrack", value: float) -> float:
    low, high = _timeline_value_range(track.target_parameter, track.track_kind)
    return float(np.clip(float(value), low, high))


def _sorted_timeline_points(track: "TimelineParameterTrack") -> List["TimelineParameterPoint"]:
    return sorted(
        [point if isinstance(point, TimelineParameterPoint) else TimelineParameterPoint.from_json_dict(point) for point in (track.points or [])],
        key=lambda point: (int(point.time_ms), float(point.value)),
    )


def evaluate_timeline_track(track: "TimelineParameterTrack", time_ms: float) -> float | None:
    """Sample one canonical timeline track at a millisecond timestamp.

    Muted and empty tracks return None. Invisible tracks still evaluate because
    visibility is an editor concern; muting is the render/audition bypass.
    """
    if track is None or bool(getattr(track, "muted", False)):
        return None
    points = _sorted_timeline_points(track)
    if not points:
        return None
    sample_ms = float(max(0.0, float(time_ms)))
    if sample_ms < float(points[0].time_ms):
        return None
    if len(points) == 1 or sample_ms >= float(points[-1].time_ms):
        return _clamped_timeline_point_value(track, points[-1].value)
    for left, right in zip(points, points[1:]):
        left_ms = float(left.time_ms)
        right_ms = float(right.time_ms)
        if sample_ms < left_ms or sample_ms > right_ms:
            continue
        curve = left.curve if left.curve in AUTOMATION_CURVES else "linear"
        if curve == "hold" or right_ms <= left_ms:
            return _clamped_timeline_point_value(track, left.value)
        ratio = float(np.clip((sample_ms - left_ms) / max(1.0, right_ms - left_ms), 0.0, 1.0))
        if curve == "smooth":
            ratio = ratio * ratio * (3.0 - 2.0 * ratio)
        value = float(left.value) + (float(right.value) - float(left.value)) * ratio
        return _clamped_timeline_point_value(track, value)
    return _clamped_timeline_point_value(track, points[-1].value)


def evaluate_timeline_tracks(tracks: List["TimelineParameterTrack"], time_ms: float) -> Dict[str, float]:
    """Sample all active timeline tracks and sum values by target parameter."""
    values: Dict[str, float] = {}
    for track in tracks or []:
        if getattr(track, "track_kind", "automation") not in TIMELINE_TRACK_KINDS:
            continue
        value = evaluate_timeline_track(track, time_ms)
        if value is None:
            continue
        target = str(getattr(track, "target_parameter", "") or "")
        if not target:
            continue
        values[target] = float(values.get(target, 0.0) + value)
        low, high = _timeline_value_range(target, getattr(track, "track_kind", "automation"))
        values[target] = float(np.clip(values[target], low, high))
    return values


def automation_value_for_parameter(parameter: str, time_ms: float, tracks: List["TimelineParameterTrack"] | None = None) -> float:
    """Return the summed automation value for one parameter at a time."""
    parameter = str(parameter or "")
    if not parameter or not tracks:
        return 0.0
    value = 0.0
    found = False
    for track in tracks:
        if getattr(track, "track_kind", "automation") != "automation" or getattr(track, "target_parameter", "") != parameter:
            continue
        sample = evaluate_timeline_track(track, time_ms)
        if sample is None:
            continue
        value += float(sample)
        found = True
    if not found:
        return 0.0
    low, high = _timeline_value_range(parameter, "automation")
    return float(np.clip(value, low, high))


def automation_envelope_for_parameter(parameter: str, duration_ms: float, sample_rate: int, tracks: List["TimelineParameterTrack"] | None = None) -> np.ndarray:
    """Sample a parameter automation envelope through the compiled/cached evaluator."""
    return compiled_envelope_for_parameter(parameter, duration_ms, sample_rate, tracks)


def _timeline_evaluation_self_check() -> bool:
    """Manual/debug parity check for legacy point scanning and compiled segment evaluation."""
    cases = [
        TimelineParameterTrack(name="empty", points=[]),
        TimelineParameterTrack(name="one", points=[TimelineParameterPoint(100, 4.0, "linear")]),
        TimelineParameterTrack(name="hold", points=[TimelineParameterPoint(0, 0.0, "hold"), TimelineParameterPoint(100, 10.0, "linear")]),
        TimelineParameterTrack(name="linear", points=[TimelineParameterPoint(0, 0.0, "linear"), TimelineParameterPoint(100, 10.0, "linear")]),
        TimelineParameterTrack(name="smooth", points=[TimelineParameterPoint(0, 0.0, "smooth"), TimelineParameterPoint(100, 10.0, "linear")]),
        TimelineParameterTrack(name="muted", muted=True, points=[TimelineParameterPoint(0, 9.0, "linear")]),
        TimelineParameterTrack(name="clamped", points=[TimelineParameterPoint(0, -99.0, "linear"), TimelineParameterPoint(100, 99.0, "unknown")]),
    ]
    sample_times = [-10.0, 0.0, 25.0, 50.0, 100.0, 250.0]
    for track in cases:
        compiled = compile_timeline_track(track)
        for sample_ms in sample_times:
            expected = evaluate_timeline_track(track, sample_ms)
            actual = evaluate_compiled_track(compiled, sample_ms)
            if expected is None or actual is None:
                if expected is not None or actual is not None:
                    return False
            elif not math.isclose(float(expected), float(actual), rel_tol=1e-5, abs_tol=1e-4):
                return False
    return True


@dataclass
class AutomationPoint:
    """One editable automation value at a millisecond timestamp."""

    time_ms: int = 0
    value: float = 0.0
    curve: str = "linear"

    def __post_init__(self) -> None:
        self.time_ms = int(max(0, round(float(self.time_ms))))
        self.value = float(self.value)
        if self.curve not in AUTOMATION_CURVES:
            self.curve = "linear"

    def to_json_dict(self) -> Dict[str, object]:
        return {"time_ms": int(self.time_ms), "value": float(self.value), "curve": self.curve}

    @classmethod
    def from_json_dict(cls, data: Dict[str, object]) -> "AutomationPoint":
        return cls(
            time_ms=int(float(data.get("time_ms", 0) or 0)),
            value=float(data.get("value", 0.0) or 0.0),
            curve=str(data.get("curve", "linear") or "linear"),
        )


@dataclass
class AutomationTrack:
    """Persistent performance lane targeting one articulation, voice, resonance, or expression parameter."""

    track_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    name: str = "Accentuation"
    target_parameter: str = "accentuation_db"
    lane_type: str = "expression"
    points: List[AutomationPoint] = field(default_factory=list)
    muted: bool = False
    visible: bool = True
    color: str = "#ffd166"

    def __post_init__(self) -> None:
        self.track_id = str(self.track_id or uuid.uuid4())
        self.name = str(self.name or self.target_parameter or "Automation Track")
        self.target_parameter = str(self.target_parameter or "accentuation_db")
        self.lane_type = str(self.lane_type or AUTOMATION_TARGET_TO_LANE.get(self.target_parameter, "expression"))
        self.points = sorted([p if isinstance(p, AutomationPoint) else AutomationPoint.from_json_dict(p) for p in self.points], key=lambda p: p.time_ms)
        self.muted = bool(self.muted)
        self.visible = bool(self.visible)
        self.color = str(self.color or "#ffd166")

    def to_json_dict(self) -> Dict[str, object]:
        return {
            "track_id": self.track_id,
            "name": self.name,
            "target_parameter": self.target_parameter,
            "lane_type": self.lane_type,
            "points": [point.to_json_dict() for point in self.points],
            "muted": self.muted,
            "visible": self.visible,
            "color": self.color,
        }

    @classmethod
    def from_json_dict(cls, data: Dict[str, object]) -> "AutomationTrack":
        return cls(
            track_id=str(data.get("track_id") or uuid.uuid4()),
            name=str(data.get("name", "Automation Track") or "Automation Track"),
            target_parameter=str(data.get("target_parameter", "accentuation_db") or "accentuation_db"),
            lane_type=str(data.get("lane_type", "") or AUTOMATION_TARGET_TO_LANE.get(str(data.get("target_parameter", "accentuation_db")), "expression")),
            points=[AutomationPoint.from_json_dict(item) for item in data.get("points", []) if isinstance(item, dict)] if isinstance(data.get("points", []), list) else [],
            muted=bool(data.get("muted", False)),
            visible=bool(data.get("visible", True)),
            color=str(data.get("color", "#ffd166") or "#ffd166"),
        )


@dataclass
class PerformanceAsset:
    """Serializable performance snapshot using canonical unified timeline tracks."""

    performance_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    name: str = "Untitled Performance"
    timeline_tracks: List[TimelineParameterTrack] = field(default_factory=list)
    created_at: str = field(default_factory=_utc_now_iso)
    modified_at: str = field(default_factory=_utc_now_iso)
    version: int = 2

    @property
    def automation_tracks(self) -> List[AutomationTrack]:
        return [track.to_automation_track() for track in self.timeline_tracks if track.track_kind == "automation"]

    @automation_tracks.setter
    def automation_tracks(self, tracks: List[AutomationTrack]) -> None:
        self.timeline_tracks = [TimelineParameterTrack.from_automation_track(track, lane_order=index) for index, track in enumerate(tracks)]

    def to_json_dict(self) -> Dict[str, object]:
        return {
            "performance_id": self.performance_id,
            "name": self.name,
            "timeline_tracks": [track.to_json_dict() for track in self.timeline_tracks],
            "created_at": self.created_at,
            "modified_at": self.modified_at,
            "version": self.version,
        }

    @classmethod
    def from_json_dict(cls, data: Dict[str, object], *, fresh_uuid: bool = False) -> "PerformanceAsset":
        raw_timeline = data.get("timeline_tracks", [])
        if isinstance(raw_timeline, list) and raw_timeline:
            timeline_tracks = [TimelineParameterTrack.from_json_dict(item) for item in raw_timeline if isinstance(item, dict)]
        else:
            legacy = data.get("automation_tracks", [])
            timeline_tracks = [
                TimelineParameterTrack.from_automation_track(AutomationTrack.from_json_dict(item), lane_order=index)
                for index, item in enumerate(legacy)
                if isinstance(item, dict)
            ] if isinstance(legacy, list) else []
        return cls(
            performance_id=str(uuid.uuid4()) if fresh_uuid else str(data.get("performance_id") or uuid.uuid4()),
            name=str(data.get("name", "Untitled Performance") or "Untitled Performance"),
            timeline_tracks=timeline_tracks,
            created_at=_utc_now_iso() if fresh_uuid else str(data.get("created_at") or _utc_now_iso()),
            modified_at=_utc_now_iso(),
            version=max(2, int(data.get("version", 2) or 2)),
        )


@dataclass
class AssetLibraryRecord:
    """Human-readable asset envelope shared by global library and projects."""

    asset_type: str
    name: str
    payload: Dict[str, object]
    uuid: str = field(default_factory=lambda: str(uuid.uuid4()))
    description: str = ""
    tags: List[str] = field(default_factory=list)
    created_at: str = field(default_factory=_utc_now_iso)
    modified_at: str = field(default_factory=_utc_now_iso)
    version: int = 1
    favorite: bool = False
    notes: str = ""
    source_path: str | None = None

    def to_json_dict(self) -> Dict[str, object]:
        return {
            "uuid": self.uuid,
            "asset_type": self.asset_type,
            "name": self.name,
            "description": self.description,
            "tags": list(self.tags),
            "created_at": self.created_at,
            "modified_at": self.modified_at,
            "version": self.version,
            "favorite": self.favorite,
            "notes": self.notes,
            "source_path": self.source_path,
            "payload": self.payload,
        }

    @classmethod
    def from_json_dict(cls, data: Dict[str, object]) -> "AssetLibraryRecord":
        return cls(
            uuid=str(data.get("uuid") or uuid.uuid4()),
            asset_type=str(data.get("asset_type", "asset")),
            name=str(data.get("name", "Untitled Asset")),
            description=str(data.get("description", "")),
            tags=[str(tag) for tag in data.get("tags", [])] if isinstance(data.get("tags", []), list) else [],
            created_at=str(data.get("created_at") or _utc_now_iso()),
            modified_at=str(data.get("modified_at") or _utc_now_iso()),
            version=int(data.get("version", 1) or 1),
            favorite=bool(data.get("favorite", False)),
            notes=str(data.get("notes", "")),
            source_path=str(data.get("source_path")) if data.get("source_path") else None,
            payload=dict(data.get("payload", {})) if isinstance(data.get("payload", {}), dict) else {},
        )


class WaveToyStorage:
    """Small JSON storage foundation for persistent projects, assets, and recovery."""

    def __init__(self, root: Path | None = None) -> None:
        self.root = root or wavetoy_data_root()
        self.projects_dir = self.root / "Projects"
        self.assets_dir = self.root / "Assets"
        self.exports_dir = self.root / "Exports"
        self.cache_dir = self.root / "Cache"
        self.recovery_dir = self.root / "Recovery"
        self.metadata_path = self.root / "wavetoy_storage.json"
        self.ensure_layout()

    def ensure_layout(self) -> None:
        for path in [self.projects_dir, self.assets_dir, self.exports_dir, self.cache_dir, self.recovery_dir]:
            path.mkdir(parents=True, exist_ok=True)
        for folder in WAVETOY_ASSET_CATEGORIES.values():
            (self.assets_dir / folder).mkdir(parents=True, exist_ok=True)
        if not self.metadata_path.exists():
            self.write_json(self.metadata_path, {"version": 1, "recent_projects": [], "restore_previous_session": True})

    def asset_dir(self, asset_type: str) -> Path:
        return self.assets_dir / WAVETOY_ASSET_CATEGORIES.get(asset_type, _safe_storage_name(asset_type, "Assets"))

    def read_json(self, path: Path) -> Dict[str, object]:
        return json.loads(path.read_text(encoding="utf-8"))

    def write_json(self, path: Path, data: Dict[str, object]) -> None:
        path.parent.mkdir(parents=True, exist_ok=True)
        tmp = path.with_suffix(path.suffix + ".tmp")
        tmp.write_text(json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")
        tmp.replace(path)

    def save_asset(self, record: AssetLibraryRecord) -> Path:
        record.modified_at = _utc_now_iso()
        path = self.asset_dir(record.asset_type) / f"{_safe_storage_name(record.name)}_{record.uuid[:8]}.json"
        self.write_json(path, record.to_json_dict())
        return path

    def iter_assets(self) -> List[Tuple[Path, AssetLibraryRecord]]:
        records: List[Tuple[Path, AssetLibraryRecord]] = []
        for path in sorted(self.assets_dir.glob("*/*.json")):
            try:
                records.append((path, AssetLibraryRecord.from_json_dict(self.read_json(path))))
            except Exception as exc:
                print(f"[WaveToy Storage] Could not load asset {path}: {exc}")
        return records

    def metadata(self) -> Dict[str, object]:
        try:
            return self.read_json(self.metadata_path)
        except Exception:
            return {"version": 1, "recent_projects": [], "restore_previous_session": True}

    def update_metadata(self, **updates: object) -> None:
        metadata = self.metadata()
        metadata.update(updates)
        metadata["modified_at"] = _utc_now_iso()
        self.write_json(self.metadata_path, metadata)

    def add_recent_project(self, path: Path) -> None:
        metadata = self.metadata()
        recent = [entry for entry in metadata.get("recent_projects", []) if str(entry) != str(path)]
        recent.insert(0, str(path))
        self.update_metadata(recent_projects=recent[:10], last_project_path=str(path))

    def default_project_path(self, name: str) -> Path:
        return self.projects_dir / f"{_safe_storage_name(name, 'WaveToy_Project')}.wavetoy-project.json"

    @property
    def recovery_path(self) -> Path:
        return self.recovery_dir / "autosave_recovery.wavetoy-project.json"


class FlowLayout(QLayout):
    """Small wrapping layout for button toolbars."""

    def __init__(self, parent: QWidget | None = None, margin: int = 0, spacing: int = 8) -> None:
        super().__init__(parent)
        self._items: list = []
        self.setContentsMargins(margin, margin, margin, margin)
        self.setSpacing(spacing)

    def addItem(self, item) -> None:
        self._items.append(item)

    def count(self) -> int:
        return len(self._items)

    def itemAt(self, index: int):
        if 0 <= index < len(self._items):
            return self._items[index]
        return None

    def takeAt(self, index: int):
        if 0 <= index < len(self._items):
            return self._items.pop(index)
        return None

    def expandingDirections(self) -> Qt.Orientations:
        return Qt.Orientations(Qt.Orientation(0))

    def hasHeightForWidth(self) -> bool:
        return True

    def heightForWidth(self, width: int) -> int:
        return self._do_layout(QRect(0, 0, width, 0), test_only=True)

    def setGeometry(self, rect: QRect) -> None:
        super().setGeometry(rect)
        self._do_layout(rect, test_only=False)

    def sizeHint(self) -> QSize:
        return self.minimumSize()

    def minimumSize(self) -> QSize:
        size = QSize()
        for item in self._items:
            size = size.expandedTo(item.minimumSize())
        left, top, right, bottom = self.getContentsMargins()
        size += QSize(left + right, top + bottom)
        return size

    def _do_layout(self, rect: QRect, *, test_only: bool) -> int:
        left, top, right, bottom = self.getContentsMargins()
        effective = rect.adjusted(left, top, -right, -bottom)
        x = effective.x()
        y = effective.y()
        line_height = 0
        for item in self._items:
            space_x = self.spacing()
            space_y = self.spacing()
            item_size = item.sizeHint()
            next_x = x + item_size.width() + space_x
            if next_x - space_x > effective.right() and line_height > 0:
                x = effective.x()
                y = y + line_height + space_y
                next_x = x + item_size.width() + space_x
                line_height = 0
            if not test_only:
                item.setGeometry(QRect(QPoint(x, y), item_size))
            x = next_x
            line_height = max(line_height, item_size.height())
        return y + line_height - rect.y() + bottom

