def phoneme_pair_transition_model(left: ArticulationPhoneme, right: ArticulationPhoneme) -> PhonemePairTransitionModel:
    """Resolve the render-only transition model for a neighboring phoneme pair."""
    left = left.clamped()
    right = right.clamped()
    key = (left.name.upper(), right.name.upper())
    override = PHONEME_PAIR_TRANSITION_OVERRIDES.get(key)
    if override:
        base = PHONEME_PAIR_TRANSITION_MODELS[str(override.get("model", ""))]
        updates = {name: value for name, value in override.items() if name != "model"}
        return replace(base, **updates, from_phoneme_optional=key[0], to_phoneme_optional=key[1]).clamped()
    model = PHONEME_PAIR_TRANSITION_MODELS.get(f"{left.phoneme_family}_to_{right.phoneme_family}")
    if model is None and left.phoneme_family == "affricate":
        model = PHONEME_PAIR_TRANSITION_MODELS.get(f"fricative_to_{right.phoneme_family}")
    if model is None and right.phoneme_family == "affricate":
        model = PHONEME_PAIR_TRANSITION_MODELS.get(f"{left.phoneme_family}_to_fricative")
    if model is None:
        legacy_ms = ARTICULATION_TRANSITION_RULE_MS.get((left.phoneme_family, right.phoneme_family), ARTICULATION_DEFAULT_TRANSITION_MS)
        model = _transition_model(f"{left.phoneme_family}_to_{right.phoneme_family}_legacy", left.phoneme_family, right.phoneme_family, legacy_ms, ARTICULATION_DEFAULT_TRANSITION_CURVE, notes="Legacy fallback duration for pairs without a specific model.")
    return model.clamped()


def transition_model_diagnostics(left: ArticulationPhoneme, right: ArticulationPhoneme, explicit_ms: int | None = None, explicit_curve: str | None = None) -> Dict[str, object]:
    model = phoneme_pair_transition_model(left, right)
    duration_reason = "manual transition_to_next_ms override" if explicit_ms is not None else f"model default {model.default_transition_ms} ms for {model.from_family}→{model.to_family}"
    curve_reason = "manual transition_curve override" if explicit_curve and explicit_curve != ARTICULATION_DEFAULT_TRANSITION_CURVE else f"model curve {model.curve}"
    strength = max(
        model.formant_motion_weight,
        model.voicing_blend_weight,
        model.airflow_blend_weight,
        model.closure_preservation,
        model.burst_preservation,
        model.nasal_decay,
        model.frication_hold,
    )
    return {
        "transition_model": model.model_id,
        "transition_model_id": model.model_id,
        "transition_strength": round(float(np.clip(strength, 0.0, 1.0)), 3),
        "transition_model_duration_reason": duration_reason,
        "transition_model_curve_reason": curve_reason,
        "transition_model_notes": model.notes,
    }

@dataclass
class ArticulationBoundary:
    """Editable articulation boundary shared by timeline, renderer, and save files."""

    transition_ms: int = ARTICULATION_DEFAULT_TRANSITION_MS
    transition_curve: str = ARTICULATION_DEFAULT_TRANSITION_CURVE

    def clamped(self) -> "ArticulationBoundary":
        curve = self.transition_curve if self.transition_curve in ARTICULATION_TRANSITION_CURVES else ARTICULATION_DEFAULT_TRANSITION_CURVE
        return ArticulationBoundary(transition_ms=int(np.clip(int(self.transition_ms), 0, 250)), transition_curve=curve)


def diphthong_transition_targets(symbol: str) -> Tuple[ArticulationPhoneme, ArticulationPhoneme] | None:
    """Return non-mutating vowel targets for a diphthong symbol when defined."""
    mapping = DIPHTHONG_TRANSITION_MAP.get(str(symbol).upper())
    if mapping is None:
        return None
    start_symbol, end_symbol = mapping
    if start_symbol not in VOWEL_PRESETS or end_symbol not in VOWEL_PRESETS:
        return None
    return _phoneme_from_preset_symbol(start_symbol).clamped(), _phoneme_from_preset_symbol(end_symbol).clamped()


def diphthong_profile_for_symbol(symbol: str) -> Dict[str, object] | None:
    """Return the per-diphthong render profile without changing saved chain data."""
    profile = DIPHTHONG_PROFILES.get(str(symbol).upper())
    return dict(profile) if isinstance(profile, dict) else None


def apply_diphthong_transition_shape(phoneme: ArticulationPhoneme, progress: float, curve: str = DIPHTHONG_INTERPOLATION_CURVE) -> Tuple[ArticulationPhoneme, Dict[str, object]]:
    """Return a render-only internal vowel morph for diphthongs without splitting the timeline phoneme."""
    base = phoneme.clamped()
    targets = diphthong_transition_targets(base.name)
    if targets is None:
        return base, {}
    profile = diphthong_profile_for_symbol(base.name) or {
        "start_vowel": targets[0].name,
        "end_vowel": targets[1].name,
        "curve": curve,
        "glide_start_percent": 0,
    }
    start, end = targets
    profile_curve = str(profile.get("curve", curve))
    if profile_curve not in ARTICULATION_TRANSITION_CURVES:
        profile_curve = curve
    glide_start_percent = int(np.clip(int(profile.get("glide_start_percent", 0)), 0, 95))
    raw_progress = float(np.clip(progress, 0.0, 1.0))
    glide_start = glide_start_percent / 100.0
    glide_progress = 0.0 if raw_progress <= glide_start else (raw_progress - glide_start) / max(0.01, 1.0 - glide_start)
    t = articulation_curve_progress(glide_progress, profile_curve)
    data = base.to_json_dict()
    for field_name in DIPHTHONG_INTERPOLATED_FIELDS:
        data[field_name] = float(np.clip(float(getattr(start, field_name)) + (float(getattr(end, field_name)) - float(getattr(start, field_name))) * t, 0.0, 1.0))
    data["voice_strength"] = float(np.clip(start.voice_strength + (end.voice_strength - start.voice_strength) * t, 0.0, 1.0))
    data["noise_color"] = float(np.clip(start.noise_color + (end.noise_color - start.noise_color) * t, 0.0, 1.0))
    data["voice_pitch"] = float(np.clip(base.voice_pitch, 60.0, 880.0))
    data["name"] = base.name
    data["ipa"] = base.ipa
    data["phoneme_family"] = base.phoneme_family
    diagnostics = {
        "diphthong_profile": base.name,
        "glide_start_percent": glide_start_percent,
        "diphthong_start_vowel": start.name,
        "diphthong_end_vowel": end.name,
        "diphthong_progress": round(float(t), 3),
        "diphthong_interpolation_curve": profile_curve,
    }
    return ArticulationPhoneme.from_json_dict(data).clamped(), diagnostics


def _blend_unit_value(start: float, target: float, amount: float) -> float:
    return float(np.clip(float(start) + (float(target) - float(start)) * float(np.clip(amount, 0.0, 1.0)), 0.0, 1.0))


def apply_neighbor_coarticulation(phonemes: List[ArticulationPhoneme]) -> Tuple[List[ArticulationPhoneme], Dict[int, Dict[str, object]], Dict[Tuple[int, int], Dict[str, object]]]:
    """Return render-copy coarticulated phonemes plus diagnostics for supported neighboring pairs."""
    adjusted = [phoneme.clamped() for phoneme in phonemes]
    item_diagnostics: Dict[int, Dict[str, object]] = {}
    pair_diagnostics: Dict[Tuple[int, int], Dict[str, object]] = {}
    for index in range(len(adjusted) - 1):
        left = adjusted[index].clamped()
        right = adjusted[index + 1].clamped()
        key = (left.name.upper(), right.name.upper())
        rule = COARTICULATION_RULES.get(key)
        if rule is None:
            continue
        strength = float(np.clip(float(rule.get("strength", 0.0)), 0.0, 1.0))
        if strength <= 0.0:
            continue
        anticipatory_tongue_shift = float(rule.get("anticipatory_tongue_shift", 0.0)) * strength
        carryover_closure = float(rule.get("carryover_closure", 0.0)) * strength
        lip_rounding_carryover = float(rule.get("lip_rounding_carryover", 0.0)) * strength
        nasal_carryover = float(rule.get("nasal_carryover", 0.0)) * strength
        voicing_carryover = float(rule.get("voicing_carryover", 0.0)) * strength

        left_data = left.to_json_dict()
        right_data = right.to_json_dict()
        if anticipatory_tongue_shift > 0.0:
            left_data["tongue_frontness"] = _blend_unit_value(left.tongue_frontness, right.tongue_frontness, anticipatory_tongue_shift)
            left_data["tongue_height"] = _blend_unit_value(left.tongue_height, right.tongue_height, anticipatory_tongue_shift * 0.70)
        if lip_rounding_carryover > 0.0:
            right_data["lip_rounding"] = _blend_unit_value(right.lip_rounding, left.lip_rounding, lip_rounding_carryover)
        if nasal_carryover > 0.0:
            right_data["nasal_open"] = float(np.clip(max(float(right_data.get("nasal_open", 0.0)), left.nasal_open * nasal_carryover), 0.0, 1.0))
        if voicing_carryover > 0.0 and left.voiced and right.voiced:
            right_data["voice_strength"] = _blend_unit_value(right.voice_strength, left.voice_strength, voicing_carryover)
        if carryover_closure > 0.0:
            if right.phoneme_family == "stop":
                right_data["closure"] = float(np.clip(max(right.closure, min(1.0, left.closure + carryover_closure)), 0.0, 1.0))
            elif left.phoneme_family == "stop":
                left_data["closure"] = float(np.clip(max(left.closure, left.closure + carryover_closure * 0.20), 0.0, 1.0))

        adjusted[index] = ArticulationPhoneme.from_json_dict(left_data).clamped()
        adjusted[index + 1] = ArticulationPhoneme.from_json_dict(right_data).clamped()
        diagnostics = {
            "coarticulation_pair": f"{key[0]}-{key[1]}",
            "coarticulation_strength": round(strength, 3),
            "coarticulation_type": str(rule.get("type", "neighbor")),
            "anticipatory_tongue_shift": round(anticipatory_tongue_shift, 3),
            "carryover_closure": round(carryover_closure, 3),
            "lip_rounding_carryover": round(lip_rounding_carryover, 3),
            "nasal_carryover": round(nasal_carryover, 3),
            "voicing_carryover": round(voicing_carryover, 3),
        }
        pair_diagnostics[(index, index + 1)] = diagnostics
        item_diagnostics[index] = diagnostics
        item_diagnostics[index + 1] = diagnostics
    return adjusted, item_diagnostics, pair_diagnostics


def interpolate_articulation_phoneme(
    left: ArticulationPhoneme,
    right: ArticulationPhoneme,
    progress: float,
    curve: str = ARTICULATION_DEFAULT_TRANSITION_CURVE,
    transition_model: PhonemePairTransitionModel | None = None,
) -> ArticulationPhoneme:
    """Return a clamped non-mutating slider snapshot between two phonemes."""
    start = left.clamped()
    end = right.clamped()
    model = (transition_model or phoneme_pair_transition_model(start, end)).clamped()
    t = articulation_curve_progress(progress, curve)

    def weighted_t(weight: float) -> float:
        # A lower weight preserves more of the source articulation for the first
        # half of the transition, then lets the target arrive late and cleanly.
        weight = float(np.clip(weight, 0.0, 1.0))
        return float(np.clip(t * weight + (t * t) * (1.0 - weight), 0.0, 1.0))

    formant_t = weighted_t(model.formant_motion_weight)
    voicing_t = weighted_t(model.voicing_blend_weight)
    airflow_t = weighted_t(model.airflow_blend_weight)
    data = start.to_json_dict()
    formant_fields = {"mouth_open", "tongue_height", "tongue_frontness", "lip_rounding", "teeth_gap"}
    airflow_fields = {"air_pressure", "noise_color"}
    for field_name in ARTICULATION_INTERPOLATED_FIELDS:
        field_t = t
        if field_name in formant_fields:
            field_t = formant_t
        elif field_name in {"voice_strength"}:
            field_t = voicing_t
        elif field_name in airflow_fields:
            field_t = airflow_t
        data[field_name] = float(np.clip(float(getattr(start, field_name)) + (float(getattr(end, field_name)) - float(getattr(start, field_name))) * field_t, 0.0, 1.0))

    if model.frication_hold > 0.0 and start.phoneme_family in {"fricative", "affricate", "vowel"} and end.phoneme_family in {"stop", "fricative", "affricate"}:
        hold = model.frication_hold * (1.0 - t)
        data["air_pressure"] = float(np.clip(max(float(data["air_pressure"]), start.air_pressure * hold), 0.0, 1.0))
        data["teeth_gap"] = float(np.clip(max(float(data["teeth_gap"]), start.teeth_gap * hold), 0.0, 1.0))
        data["noise_color"] = float(np.clip(max(float(data.get("noise_color", start.noise_color)), start.noise_color * hold), 0.0, 1.0))
    if model.nasal_decay > 0.0 and start.phoneme_family == "nasal":
        nasal_hold = model.nasal_decay * (1.0 - smoothstep(t))
        data["nasal_open"] = float(np.clip(max(float(data["nasal_open"]), start.nasal_open * nasal_hold), 0.0, 1.0))
    if model.closure_preservation > 0.0 and (start.phoneme_family == "stop" or end.phoneme_family == "stop"):
        if end.phoneme_family == "stop":
            prep = model.closure_preservation * smoothstep(t)
            data["closure"] = float(np.clip(max(float(data["closure"]), end.closure * prep), 0.0, 1.0))
        else:
            carry = model.closure_preservation * (1.0 - smoothstep(t))
            data["closure"] = float(np.clip(max(float(data["closure"]), start.closure * carry), 0.0, 1.0))
    if model.burst_preservation > 0.0 and (start.phoneme_family == "stop" or end.phoneme_family == "stop"):
        burst_source = start.burst_strength if start.phoneme_family == "stop" else end.burst_strength
        preserve = model.burst_preservation * (1.0 - min(1.0, abs(t - 0.5) * 1.4))
        data["burst_strength"] = float(np.clip(max(float(data["burst_strength"]), burst_source * preserve), 0.0, 1.0))

    data["voice_pitch"] = float(np.clip(start.voice_pitch + (end.voice_pitch - start.voice_pitch) * voicing_t, 60.0, 880.0))
    data["noise_color"] = float(np.clip(start.noise_color + (end.noise_color - start.noise_color) * airflow_t, 0.0, 1.0))
    if model.frication_hold > 0.0 and start.phoneme_family in {"fricative", "affricate", "vowel"} and end.phoneme_family in {"stop", "fricative", "affricate"}:
        data["noise_color"] = float(np.clip(max(float(data["noise_color"]), start.noise_color * model.frication_hold * (1.0 - t)), 0.0, 1.0))
    data["attack_ms"] = int(round(start.attack_ms + (end.attack_ms - start.attack_ms) * t))
    data["release_ms"] = int(round(start.release_ms + (end.release_ms - start.release_ms) * t))
    data["duration_ms"] = int(round(start.duration_ms + (end.duration_ms - start.duration_ms) * t))
    data["voiced"] = bool(start.voiced if progress < 0.5 else end.voiced)
    data["phoneme_family"] = start.phoneme_family if progress < 0.5 else end.phoneme_family
    data["name"] = f"{start.name}→{end.name}"
    data["ipa"] = f"{start.ipa}→{end.ipa}"
    data["preview_color"] = start.preview_color if progress < 0.5 else end.preview_color
    if progress >= 0.5:
        data["source_mode"] = end.source_mode
        data["source_wave_id"] = end.source_wave_id
        data["source_recipe_snapshot"] = end.source_recipe_snapshot or {}
        data["source_audio_path"] = end.source_audio_path
        data["source_start_seconds"] = end.source_start_seconds
        data["source_duration_seconds"] = end.source_duration_seconds
        data["source_pitch_follow"] = end.source_pitch_follow
        data["source_loop_to_fit"] = end.source_loop_to_fit
        data["source_gain"] = end.source_gain
    return ArticulationPhoneme.from_json_dict(data).clamped()


@dataclass
class ArticulationChainItem:
    """One editable phoneme card in an Articulation Chain."""

    phoneme: ArticulationPhoneme
    id: str = field(default_factory=lambda: uuid.uuid4().hex)
    duration_ms: int | None = None
    gap_after_ms: int = 0
    crossfade_ms: int = ARTICULATION_DEFAULT_WORD_CROSSFADE_MS
    transition_to_next_ms: int | None = None
    transition_curve: str = ARTICULATION_DEFAULT_TRANSITION_CURVE
    accentuation_db: float = 0.0

    @property
    def transition_ms(self) -> int | None:
        """Backward-compatible alias for saved chains that used transition_ms."""
        return self.transition_to_next_ms

    @transition_ms.setter
    def transition_ms(self, value: int | None) -> None:
        self.transition_to_next_ms = value

    def __post_init__(self) -> None:
        self.phoneme = self.phoneme.clamped()
        if self.duration_ms is None:
            self.duration_ms = self.phoneme.duration_ms
        self.duration_ms = int(np.clip(int(self.duration_ms), 80, 5000))
        self.gap_after_ms = int(np.clip(int(self.gap_after_ms), 0, 2000))
        self.crossfade_ms = int(np.clip(int(self.crossfade_ms), 0, 250))
        if self.transition_to_next_ms is not None:
            self.transition_to_next_ms = int(np.clip(int(self.transition_to_next_ms), 0, 250))
        if self.transition_curve not in ARTICULATION_TRANSITION_CURVES:
            self.transition_curve = ARTICULATION_DEFAULT_TRANSITION_CURVE
        self.accentuation_db = float(np.clip(float(self.accentuation_db), -24.0, 24.0))

    def phoneme_for_render(self) -> ArticulationPhoneme:
        data = self.phoneme.to_json_dict()
        data["duration_ms"] = int(self.duration_ms or self.phoneme.duration_ms)
        return ArticulationPhoneme.from_json_dict(data)

    def to_json_dict(self) -> Dict[str, object]:
        phoneme = self.phoneme_for_render()
        data = phoneme.to_json_dict()
        data.update(
            {
                "id": self.id,
                "phoneme_name": phoneme.name,
                "ipa": phoneme.ipa,
                "articulation_snapshot": phoneme.to_json_dict(),
                "duration_ms": int(self.duration_ms or phoneme.duration_ms),
                "gap_after_ms": int(self.gap_after_ms),
                "crossfade_ms": int(self.crossfade_ms),
                "transition_to_next_ms": int(self.transition_to_next_ms) if self.transition_to_next_ms is not None else None,
                "transition_ms": int(self.transition_to_next_ms) if self.transition_to_next_ms is not None else None,
                "transition_curve": self.transition_curve,
                "accentuation_db": float(self.accentuation_db),
                "source_mode": phoneme.source_mode,
                "source_wave_id": phoneme.source_wave_id,
                "source_recipe_snapshot": phoneme.source_recipe_snapshot or {},
                "source_audio_path": phoneme.source_audio_path,
            }
        )
        return data

    @classmethod
    def from_json_dict(cls, data: Dict[str, object]) -> "ArticulationChainItem":
        snapshot = data.get("articulation_snapshot")
        phoneme_data = snapshot if isinstance(snapshot, dict) else data
        phoneme = ArticulationPhoneme.from_json_dict(phoneme_data)
        duration_ms = int(data.get("duration_ms", phoneme.duration_ms))
        phoneme.duration_ms = duration_ms
        return cls(
            phoneme=phoneme,
            id=str(data.get("id") or uuid.uuid4().hex),
            duration_ms=duration_ms,
            gap_after_ms=int(data.get("gap_after_ms", 0)),
            crossfade_ms=int(data.get("crossfade_ms", ARTICULATION_DEFAULT_WORD_CROSSFADE_MS)),
            transition_to_next_ms=int(data["transition_to_next_ms"]) if data.get("transition_to_next_ms") is not None else (int(data["transition_ms"]) if data.get("transition_ms") is not None else None),
            transition_curve=str(data.get("transition_curve", ARTICULATION_DEFAULT_TRANSITION_CURVE)),
            accentuation_db=float(data.get("accentuation_db", 0.0) or 0.0),
        )





@dataclass
class VoiceSourceProfile:
    """Upstream voice-box/source settings applied before mouth articulation shapes sound."""

    profile_id: str = "safe_default"
    name: str = "Safe Default"
    vocal_fold_length: float = 0.50
    vocal_fold_thickness: float = 0.50
    vocal_fold_tension: float = 0.50
    glottal_closure: float = 0.55
    breathiness: float = 0.18
    rasp: float = 0.05
    jitter: float = 0.02
    shimmer: float = 0.02
    larynx_height: float = 0.50
    vocal_tract_length: float = 0.50
    age_looseness: float = 0.20
    notes: str = "Neutral upstream source; mouth articulation remains responsible for phoneme shaping."

    def to_json_dict(self) -> Dict[str, object]:
        data = asdict(self)
        for key, value in list(data.items()):
            if isinstance(value, float):
                data[key] = float(np.clip(value, 0.0, 1.0))
        return data

    @classmethod
    def from_json_dict(cls, data: Dict[str, object]) -> "VoiceSourceProfile":
        profile = cls(**{field_name: data[field_name] for field_name in cls.__dataclass_fields__ if field_name in data})
        return VoiceSourceProfile(**profile.to_json_dict())


