    def _build_speech_diagnostics_dock(self) -> None:
        """Create the optional speech diagnostics and compact voice-box dock."""
        self.speech_diagnostics_dock = QDockWidget("Speech Diagnostics", self)
        self.speech_diagnostics_dock.setObjectName("speechDiagnosticsDock")
        dock_body = QWidget()
        dock_layout = QVBoxLayout(dock_body)
        dock_layout.setContentsMargins(8, 8, 8, 8)
        dock_layout.setSpacing(8)

        self.speech_diagnostics_text = QTextEdit()
        self.speech_diagnostics_text.setReadOnly(True)
        self.speech_diagnostics_text.setMinimumWidth(340)
        self.speech_diagnostics_text.setMinimumHeight(260)
        dock_layout.addWidget(self.speech_diagnostics_text)

        voice_box = QWidget()
        voice_box_layout = QVBoxLayout(voice_box)
        voice_box_layout.setContentsMargins(0, 0, 0, 0)
        voice_box_layout.setSpacing(6)
        preset_row = QHBoxLayout()
        preset_row.addWidget(QLabel("Character preset"))
        self.voice_box_character_combo = QComboBox()
        self.voice_box_character_combo.addItems(list(VOICE_BOX_CHARACTER_PRESETS.keys()))
        self.voice_box_character_combo.setToolTip("Updates VoiceBoxState defaults only; direct phoneme articulation remains editable.")
        self.voice_box_character_combo.currentTextChanged.connect(self._apply_voice_box_character_preset)
        preset_row.addWidget(self.voice_box_character_combo, 1)
        voice_box_layout.addLayout(preset_row)

        basic = QWidget()
        basic_layout = QGridLayout(basic)
        basic_layout.setContentsMargins(0, 0, 0, 0)
        basic_layout.setHorizontalSpacing(6)
        basic_layout.setVerticalSpacing(3)
        basic_fields = ["vocal_fold_tension", "glottal_closure", "breathiness", "rasp", "age_looseness"]
        for row, field_name in enumerate(basic_fields):
            self._add_voice_box_slider_row(basic_layout, row, field_name)
        voice_box_layout.addWidget(basic)

        advanced = QWidget()
        advanced_layout = QGridLayout(advanced)
        advanced_layout.setContentsMargins(0, 0, 0, 0)
        advanced_layout.setHorizontalSpacing(6)
        advanced_layout.setVerticalSpacing(3)
        advanced_fields = [
            "vocal_fold_length", "vocal_fold_thickness", "vocal_fold_mass", "vocal_fold_symmetry",
            "glottal_leak", "jitter", "shimmer", "vocal_damage", "larynx_height", "vocal_tract_length", "resonance_depth",
        ]
        for row, field_name in enumerate(advanced_fields):
            self._add_voice_box_slider_row(advanced_layout, row, field_name)
        voice_box_layout.addWidget(CollapsibleSection("Advanced Voice Box", advanced, expanded=False))

        reset_button = QPushButton("Reset Voice Box")
        reset_button.clicked.connect(self._reset_voice_box_state)
        voice_box_layout.addWidget(reset_button)
        dock_layout.addWidget(CollapsibleSection("Voice Box / Larynx Controls", voice_box, expanded=True))

        resonance = QWidget()
        resonance_layout = QVBoxLayout(resonance)
        resonance_layout.setContentsMargins(0, 0, 0, 0)
        resonance_layout.setSpacing(6)
        resonance_basic = QWidget()
        resonance_basic_layout = QGridLayout(resonance_basic)
        resonance_basic_layout.setContentsMargins(0, 0, 0, 0)
        resonance_basic_layout.setHorizontalSpacing(6)
        resonance_basic_layout.setVerticalSpacing(3)
        resonance_basic_fields = ["vocal_tract_length", "larynx_height", "resonance_depth", "chest_resonance", "head_resonance", "nasal_coupling"]
        for row, field_name in enumerate(resonance_basic_fields):
            self._add_resonance_slider_row(resonance_basic_layout, row, field_name)
        resonance_layout.addWidget(resonance_basic)
        resonance_advanced = QWidget()
        resonance_advanced_layout = QGridLayout(resonance_advanced)
        resonance_advanced_layout.setContentsMargins(0, 0, 0, 0)
        resonance_advanced_layout.setHorizontalSpacing(6)
        resonance_advanced_layout.setVerticalSpacing(3)
        resonance_advanced_fields = [
            "oral_cavity_length", "oral_cavity_width", "oral_cavity_height", "pharyngeal_volume", "pharyngeal_tension",
            "brightness", "darkness", "formant_scale", "formant_shift_f1", "formant_shift_f2", "formant_shift_f3",
        ]
        for row, field_name in enumerate(resonance_advanced_fields):
            self._add_resonance_slider_row(resonance_advanced_layout, row, field_name)
        resonance_layout.addWidget(CollapsibleSection("Advanced Resonance", resonance_advanced, expanded=False))
        reset_resonance_button = QPushButton("Reset Resonance")
        reset_resonance_button.clicked.connect(self._reset_resonance_state)
        resonance_layout.addWidget(reset_resonance_button)
        dock_layout.addWidget(CollapsibleSection("Resonance Tract Controls", resonance, expanded=True))

        self.speech_diagnostics_dock.setWidget(dock_body)
        self.addDockWidget(Qt.RightDockWidgetArea, self.speech_diagnostics_dock)
        self.speech_diagnostics_dock.hide()
        self._sync_voice_box_controls()
        self._sync_resonance_controls()
        self._update_speech_diagnostics_panel(self.current_phoneme)

    def _project_status_text(self) -> str:
        if self.current_project_path is None:
            return "Project: Unsaved — no project file yet"
        marker = " *" if self.project_dirty else ""
        return f"Project: {self.current_project_path}{marker}"

    def _mark_project_dirty(self, reason: str = "project change") -> None:
        if not self.project_dirty:
            print(f"[WaveToy Project] dirty: {reason}")
        self.project_dirty = True
        self._update_project_path_label()

    def _confirm_discard_dirty_project(self, action: str) -> bool:
        if not self.project_dirty:
            return True
        result = QMessageBox.question(
            self,
            "Unsaved Project",
            f"Save changes before {action}?",
            QMessageBox.Save | QMessageBox.Discard | QMessageBox.Cancel,
            QMessageBox.Save,
        )
        if result == QMessageBox.Cancel:
            return False
        if result == QMessageBox.Save:
            self._save_project()
            return not self.project_dirty
        return True

    def _update_project_path_label(self) -> None:
        if self.project_path_label is not None:
            self.project_path_label.setText(self._project_status_text())
        marker = "*" if self.project_dirty else ""
        self.setWindowTitle(f"{marker}WaveToy - Visual Sound and Articulation Lab — {self.current_project_name}")

    def _project_snapshot(self) -> Dict[str, object]:
        """Collect persistent, JSON-safe workstation state without embedding audio arrays."""
        return {
            "format": "wavetoy_project",
            "version": 1,
            "name": self.current_project_name,
            "uuid": str(uuid.uuid4()) if self.current_project_path is None else self._project_uuid_for_path(self.current_project_path),
            "saved_at": _utc_now_iso(),
            "storage_root": str(self.storage.root),
            "settings": self._settings_to_recipe(self.current_project_name),
            "articulation_chain": ArticulationChain(
                items=self.articulation_chain_items,
                last_word_render_path=str(self.articulation_last_word_render_path) if self.articulation_last_word_render_path else None,
                last_word_render_created_at=self.articulation_last_word_render_created_at,
                word_render_settings=dict(self.articulation_word_render_settings),
                syllable_markers=list(self.articulation_syllable_markers),
                phrase_markers=list(self.articulation_phrase_markers),
            ).to_json_dict() | {"selected_chain_index": self.articulation_selected_chain_index},
            "phoneme_assets": [phoneme.to_json_dict() for phoneme in self.saved_phonemes],
            "performance": self._performance_asset_snapshot().to_json_dict(),
            "profiles": {
                "voice_source_profile": self.voice_source_profile.to_json_dict(),
                "voice_box_state": self.voice_box_state.to_json_dict(),
                "resonance_tract_state": self.resonance_tract_state.to_json_dict(),
                "character_voice_profile": self.character_voice_profile.to_json_dict(),
            },
            "timing": {
                "musical_timing_settings": self.musical_timing_settings.to_json_dict(),
                "note_events": self._note_events_json(),
                "pitch_curve": self._pitch_curve_json(),
                "stress_markers": self._syllable_stress_json(),
            },
            "timeline": {
                "lane_names": list(self.timeline_lane_names),
                "snap_enabled": self.timeline_snap_enabled,
                "snap_seconds": self.timeline_snap_seconds,
                "audio_palette": [item.metadata() for item in self.timeline_audio_palette],
                "speech_bin": [item.metadata() for item in self.timeline_speech_bin],
                "clips": [clip.metadata() for clip in self.timeline_clips],
                "last_mix_path": str(self.timeline_last_mix_path) if self.timeline_last_mix_path else None,
            },
            "exports": {
                "last_word_render_path": str(self.articulation_last_word_render_path) if self.articulation_last_word_render_path else None,
                "last_timeline_mix_path": str(self.timeline_last_mix_path) if self.timeline_last_mix_path else None,
            },
            "window": {
                "size": [self.width(), self.height()],
                "active_tab": self.tabs.currentIndex() if self.tabs is not None else 0,
            },
        }

    def _project_uuid_for_path(self, path: Path) -> str:
        return str(uuid.uuid5(uuid.NAMESPACE_URL, str(path.resolve())))

    def _apply_project_snapshot(self, data: Dict[str, object]) -> None:
        self.current_project_name = str(data.get("name") or Path(str(self.current_project_path or "Untitled")).stem)
        chain = data.get("articulation_chain", {})
        if isinstance(chain, dict):
            self.articulation_chain_items = [ArticulationChainItem.from_json_dict(item) for item in chain.get("items", []) if isinstance(item, dict)]
            selected_index = chain.get("selected_chain_index")
            self.articulation_selected_chain_index = int(selected_index) if isinstance(selected_index, int) and 0 <= selected_index < len(self.articulation_chain_items) else (0 if self.articulation_chain_items else None)
            self.articulation_syllable_markers = list(chain.get("syllable_markers", [])) if isinstance(chain.get("syllable_markers", []), list) else []
            self.articulation_phrase_markers = list(chain.get("phrase_markers", [])) if isinstance(chain.get("phrase_markers", []), list) else []
            if isinstance(chain.get("word_render_settings"), dict):
                self.articulation_word_render_settings.update(chain["word_render_settings"])
        performance = data.get("performance", {})
        if isinstance(performance, dict):
            self.performance_asset = PerformanceAsset.from_json_dict(performance)
            self.timeline_tracks = list(self.performance_asset.timeline_tracks)
        else:
            self.performance_asset = PerformanceAsset(name="Current Performance")
            self.timeline_tracks = []
        self.performance_timeline_engine.set_tracks(self.timeline_tracks)
        self.timeline_tracks = self.performance_timeline_engine.timeline_tracks
        if not self.timeline_tracks and isinstance(data.get("automation_tracks", []), list):
            self.timeline_tracks = [
                TimelineParameterTrack.from_automation_track(AutomationTrack.from_json_dict(item), lane_order=index)
                for index, item in enumerate(data.get("automation_tracks", []))
                if isinstance(item, dict)
            ]
            self.performance_asset.timeline_tracks = self.timeline_tracks
            self.performance_timeline_engine.set_tracks(self.timeline_tracks)
            self.timeline_tracks = self.performance_timeline_engine.timeline_tracks
        self._sync_automation_tracks_from_timeline()
        self.performance_undo_stack.clear()
        self.performance_redo_stack.clear()
        self.performance_last_undo_redo_label = "Undo/redo idle"
        self._update_performance_undo_actions()
        self.performance_timeline_engine.set_selected_track(self.timeline_tracks[0].track_id if self.timeline_tracks else None)
        self._sync_performance_state_from_engine()
        profiles = data.get("profiles", {})
        if isinstance(profiles, dict):
            if isinstance(profiles.get("voice_source_profile"), dict):
                self.voice_source_profile = VoiceSourceProfile.from_json_dict(profiles["voice_source_profile"])
            if isinstance(profiles.get("voice_box_state"), dict):
                self.voice_box_state = VoiceBoxState.from_json_dict(profiles["voice_box_state"])
            if isinstance(profiles.get("resonance_tract_state"), dict):
                self.resonance_tract_state = ResonanceTractState.from_json_dict(profiles["resonance_tract_state"])
            if isinstance(profiles.get("character_voice_profile"), dict):
                self.character_voice_profile = CharacterVoiceProfile.from_json_dict(profiles["character_voice_profile"])
        timing = data.get("timing", {})
        if isinstance(timing, dict):
            if isinstance(timing.get("musical_timing_settings"), dict):
                self.musical_timing_settings = MusicalTimingSettings.from_json_dict(timing["musical_timing_settings"])
            self.note_events = [NoteEvent.from_json_dict(item) for item in timing.get("note_events", []) if isinstance(item, dict)] if isinstance(timing.get("note_events", []), list) else []
            self.pitch_automation_points = [PitchAutomationPoint.from_json_dict(item) for item in timing.get("pitch_curve", []) if isinstance(item, dict)] if isinstance(timing.get("pitch_curve", []), list) else []
            self.syllable_stress_markers = [SyllableStressMarker.from_json_dict(item) for item in timing.get("stress_markers", []) if isinstance(item, dict)] if isinstance(timing.get("stress_markers", []), list) else []
            self._sync_timeline_bridges()
        timeline = data.get("timeline", {})
        if isinstance(timeline, dict):
            self.timeline_lane_names = list(timeline.get("lane_names", self.timeline_lane_names)) if isinstance(timeline.get("lane_names", []), list) else self.timeline_lane_names
            self.timeline_lane_count = max(1, len(self.timeline_lane_names))
            self.timeline_snap_enabled = bool(timeline.get("snap_enabled", self.timeline_snap_enabled))
            self.timeline_snap_seconds = float(timeline.get("snap_seconds", self.timeline_snap_seconds) or self.timeline_snap_seconds)
            self.timeline_audio_palette = self._rehydrate_audio_palette(timeline.get("audio_palette", []))
            self.timeline_clips = self._rehydrate_timeline_clips(timeline.get("clips", []))
            self.timeline_next_palette_item_id = max([item.item_id for item in self.timeline_audio_palette] or [0]) + 1
            self.timeline_next_clip_id = max([clip.clip_id for clip in self.timeline_clips] or [0]) + 1
        window = data.get("window", {})
        if isinstance(window, dict) and self.tabs is not None:
            index = int(window.get("active_tab", self.tabs.currentIndex()) or 0)
            if 0 <= index < self.tabs.count():
                self.tabs.setCurrentIndex(index)
        self.articulation_word_render_audio = np.zeros((0, 2), dtype=np.float32)
        self.articulation_word_render_signature = None
        self._refresh_articulation_chain_cards()
        self._refresh_articulation_motion_timeline()
        self._refresh_performance_tables()
        self._timeline_refresh_palette_cards()
        self._timeline_update_duration()
        if self.timeline_canvas is not None:
            self.timeline_canvas._refresh_size()
            self.timeline_canvas.update()
        self._sync_voice_box_controls()
        self._sync_resonance_controls()
        self._update_project_path_label()

    def _new_project(self, checked: bool = False) -> None:
        del checked
        if not self._confirm_discard_dirty_project("creating a new project"):
            return
        name, ok = QInputDialog.getText(self, "New Project", "Project name:", text="Untitled WaveToy Project")
        if not ok:
            return
        self.current_project_name = name.strip() or "Untitled WaveToy Project"
        self.current_project_path = self.storage.default_project_path(self.current_project_name)
        self.articulation_chain_items = []
        self.timeline_clips = []
        self.timeline_audio_palette = []
        self.timeline_speech_bin = []
        self.project_dirty = True
        self._save_project_to_path(self.current_project_path)
        self._refresh_articulation_chain_cards()
        self._timeline_refresh_palette_cards()
        self._timeline_refresh_speech_bin_cards()
        self._update_project_path_label()

    def _open_project(self, checked: bool = False, path: str | None = None) -> None:
        del checked
        if not self._confirm_discard_dirty_project("opening another project"):
            return
        filename = path
        if not filename:
            filename, _ = QFileDialog.getOpenFileName(self, "Open WaveToy Project", str(self.storage.projects_dir), "WaveToy Project (*.wavetoy-project.json *.json);;All Files (*)")
        if not filename:
            return
        project_path = Path(filename)
        try:
            data = self.storage.read_json(project_path)
            self.current_project_path = project_path
            self._apply_project_snapshot(data)
            self.storage.add_recent_project(project_path)
            self._refresh_recent_project_menu()
            self.storage.update_metadata(last_project_path=str(project_path))
            self.project_dirty = False
            self._update_project_path_label()
            QMessageBox.information(self, "Project Opened", f"Opened project:\n{project_path}")
        except Exception as exc:
            QMessageBox.warning(self, "Could not open project", str(exc))

    def _save_project(self, checked: bool = False) -> None:
        del checked
        if self.current_project_path is None:
            self._save_project_as()
            return
        self._save_project_to_path(self.current_project_path, show_message=True)

    def _save_project_as(self, checked: bool = False) -> None:
        del checked
        filename, _ = QFileDialog.getSaveFileName(self, "Save WaveToy Project As", str(self.storage.default_project_path(self.current_project_name)), "WaveToy Project (*.wavetoy-project.json);;JSON (*.json)")
        if not filename:
            return
        path = Path(filename)
        if not path.name.endswith(".wavetoy-project.json"):
            path = path.with_suffix(".wavetoy-project.json")
        self.current_project_path = path
        self._save_project_to_path(path, show_message=True)

    def _save_project_to_path(self, path: Path, *, show_message: bool = False) -> None:
        data = self._project_snapshot()
        data["name"] = self.current_project_name
        self.storage.write_json(path, data)
        self.current_project_path = path
        self.project_dirty = False
        self.storage.add_recent_project(path)
        self._refresh_recent_project_menu()
        self.storage.update_metadata(last_project_path=str(path), last_session=data)
        self._update_project_path_label()
        if show_message:
            QMessageBox.information(self, "Project Saved", f"Saved project:\n{path}")

    def _auto_save_project_recovery(self) -> None:
        try:
            data = self._project_snapshot()
            data["autosave"] = {"created_at": _utc_now_iso(), "source_project_path": str(self.current_project_path) if self.current_project_path else None}
            self.storage.write_json(self.storage.recovery_path, data)
            if self.current_project_path is not None:
                metadata = self.storage.metadata()
                recent = metadata.get("recent_projects", [])
                self.storage.update_metadata(last_project_path=str(self.current_project_path), recent_projects=recent)
        except Exception as exc:
            print(f"[WaveToy Storage] Auto-save failed: {exc}")

    def _restore_startup_project_if_enabled(self) -> None:
        metadata = self.storage.metadata()
        recovery_path = self.storage.recovery_path
        if recovery_path.exists():
            try:
                recovery_data = self.storage.read_json(recovery_path)
                autosave = recovery_data.get("autosave", {}) if isinstance(recovery_data.get("autosave", {}), dict) else {}
                timestamp = str(autosave.get("created_at") or recovery_data.get("saved_at") or "unknown")
                source_project = str(autosave.get("source_project_path") or "Unsaved project")
                box = QMessageBox(self)
                box.setWindowTitle("Recovery Available")
                box.setText("A WaveToy recovery file is available.")
                box.setInformativeText(f"Recovery timestamp: {timestamp}\nSource project: {source_project}\n\nChoose whether to restore it without overwriting your current project.")
                restore_button = box.addButton("Restore Recovery", QMessageBox.AcceptRole)
                ignore_button = box.addButton("Ignore This Time", QMessageBox.RejectRole)
                delete_button = box.addButton("Delete Recovery", QMessageBox.DestructiveRole)
                box.setDefaultButton(restore_button)
                box.exec()
                clicked = box.clickedButton()
                if clicked == delete_button:
                    recovery_path.unlink(missing_ok=True)
                elif clicked == restore_button:
                    self.current_project_path = None
                    self._apply_project_snapshot(recovery_data)
                    self.project_dirty = True
                    self._update_project_path_label()
                    default_path = self.storage.default_project_path(f"{self.current_project_name} Recovery")
                    filename, _ = QFileDialog.getSaveFileName(self, "Save Restored Recovery As", str(default_path), "WaveToy Project (*.wavetoy-project.json);;JSON (*.json)")
                    if filename:
                        path = Path(filename)
                        if not path.name.endswith(".wavetoy-project.json"):
                            path = path.with_suffix(".wavetoy-project.json")
                        self.current_project_path = path
                        self._save_project_to_path(path, show_message=True)
                    return
                else:
                    del ignore_button
            except Exception as exc:
                print(f"[WaveToy Storage] Recovery prompt failed: {exc}")
        if not bool(metadata.get("restore_previous_session", True)):
            return
        last_path = metadata.get("last_project_path")
        if last_path and Path(str(last_path)).exists():
            try:
                self.current_project_path = Path(str(last_path))
                self._apply_project_snapshot(self.storage.read_json(self.current_project_path))
                self.project_dirty = False
                self._update_project_path_label()
            except Exception as exc:
                print(f"[WaveToy Storage] Startup restore failed: {exc}")

    def _refresh_recent_project_menu(self) -> None:
        if not hasattr(self, "recent_projects_menu"):
            return
        self.recent_projects_menu.clear()
        recent = [Path(str(path)) for path in self.storage.metadata().get("recent_projects", []) if Path(str(path)).exists()]
        if not recent:
            disabled = QAction("No recent projects", self)
            disabled.setEnabled(False)
            self.recent_projects_menu.addAction(disabled)
            return
        for project_path in recent[:10]:
            action = QAction(project_path.name, self)
            action.setToolTip(str(project_path))
            action.triggered.connect(lambda _checked=False, p=str(project_path): self._open_project(path=p))
            self.recent_projects_menu.addAction(action)

    def _save_library_asset(self, asset_type: str, name: str, payload: Dict[str, object], *, description: str = "", tags: List[str] | None = None, notes: str = "", source_path: str | None = None) -> Path:
        record = AssetLibraryRecord(asset_type=asset_type, name=name, payload=payload, description=description, tags=list(tags or []), notes=notes, source_path=source_path)
        path = self.storage.save_asset(record)
        self._refresh_asset_library_view()
        self._mark_project_dirty("library asset saved")
        return path

    def _selected_library_entry(self) -> Tuple[Path, AssetLibraryRecord] | None:
        if self.asset_library_table is None:
            return None
        row = self.asset_library_table.currentRow()
        if row < 0 or row >= len(self.asset_library_rows):
            QMessageBox.information(self, "Speech Asset Library", "Select a library row first.")
            return None
        return self.asset_library_rows[row]

    def _delete_library_path_for_record(self, current_path: Path, record: AssetLibraryRecord) -> None:
        if current_path.exists():
            current_path.unlink()
        for path, loaded in self.storage.iter_assets():
            if path != current_path and loaded.uuid == record.uuid:
                try:
                    path.unlink()
                except OSError:
                    pass

    def _update_library_record(self, current_path: Path, record: AssetLibraryRecord) -> Path:
        old_uuid = record.uuid
        self._delete_library_path_for_record(current_path, record)
        record.uuid = old_uuid
        return self.storage.save_asset(record)

    def _source_status_for_record(self, record: AssetLibraryRecord) -> str:
        source = record.source_path or str(record.payload.get("source_path") or record.payload.get("audio_path") or "") if isinstance(record.payload, dict) else ""
        if not source:
            return "—"
        return "OK" if Path(source).exists() else "Missing"

    def _load_selected_library_entry(self, checked: bool = False) -> None:
        del checked
        selected = self._selected_library_entry()
        if selected is None:
            return
        _path, record = selected
        try:
            self._load_library_record(record)
            self._mark_project_dirty(f"loaded library asset {record.name}")
        except Exception as exc:
            QMessageBox.warning(self, "Load Library Asset", str(exc))

    def _load_library_record(self, record: AssetLibraryRecord) -> None:
        payload = dict(record.payload or {})
        if record.asset_type == "phoneme":
            phoneme = ArticulationPhoneme.from_json_dict(payload)
            self._set_articulation_ui_from_phoneme(phoneme)
            if all(saved.name.lower() != phoneme.name.lower() for saved in self.saved_phonemes):
                self.saved_phonemes.append(phoneme)
                self._refresh_phoneme_cards()
            if self.tabs is not None:
                self.tabs.setCurrentIndex(1)
            return
        if record.asset_type in {"articulation_chain", "word"}:
            chain_payload = payload.get("articulation_metadata") if record.asset_type == "word" and isinstance(payload.get("articulation_metadata"), dict) else payload
            if self.articulation_chain_items:
                result = QMessageBox.question(self, "Replace Articulation Chain", "Replace the current articulation chain with this library asset?", QMessageBox.Yes | QMessageBox.No, QMessageBox.No)
                if result != QMessageBox.Yes:
                    return
            self.articulation_chain_items = [ArticulationChainItem.from_json_dict(item) for item in chain_payload.get("items", []) if isinstance(item, dict)]
            self.articulation_selected_chain_index = 0 if self.articulation_chain_items else None
            if isinstance(chain_payload.get("word_render_settings"), dict):
                self.articulation_word_render_settings.update(chain_payload["word_render_settings"])
            self.articulation_syllable_markers = list(chain_payload.get("syllable_markers", [])) if isinstance(chain_payload.get("syllable_markers", []), list) else []
            self.articulation_phrase_markers = list(chain_payload.get("phrase_markers", [])) if isinstance(chain_payload.get("phrase_markers", []), list) else []
            self._mark_articulation_word_dirty()
            self._refresh_articulation_chain_cards()
            self._refresh_articulation_motion_timeline()
            return
        if record.asset_type == "performance":
            performance = PerformanceAsset.from_json_dict(payload, fresh_uuid=True)
            self.performance_asset = performance
            self.performance_timeline_engine.set_tracks(list(performance.timeline_tracks))
            self.timeline_tracks = self.performance_timeline_engine.timeline_tracks
            self._sync_automation_tracks_from_timeline()
            self.performance_timeline_engine.set_selected_track(self.timeline_tracks[0].track_id if self.timeline_tracks else None)
            self._sync_performance_state_from_engine()
            self._refresh_performance_tables()
            return
        if record.asset_type == "automation_curve":
            track_payload = payload.get("track") if isinstance(payload.get("track"), dict) else payload
            if isinstance(track_payload, dict) and "track_kind" in track_payload:
                track = TimelineParameterTrack.from_json_dict(track_payload)
            else:
                track = TimelineParameterTrack.from_automation_track(AutomationTrack.from_json_dict(track_payload), lane_order=len(self.timeline_tracks))
            track.track_id = str(uuid.uuid4())
            track.name = f"{track.name} Import"
            track.lane_order = len(self.timeline_tracks)
            self.timeline_tracks.append(track)
            self.performance_asset.timeline_tracks = self.timeline_tracks
            self.performance_timeline_engine.set_tracks(self.timeline_tracks, reason="automation curve imported")
            self.performance_timeline_engine.set_selected_track(track.track_id)
            self._sync_automation_tracks_from_timeline()
            self._sync_performance_state_from_engine()
            self._refresh_performance_tables()
            return
        if record.asset_type == "voice_source":
            self.voice_source_profile = VoiceSourceProfile.from_json_dict(payload)
            return
        if record.asset_type == "voice_box":
            self.voice_box_state = VoiceBoxState.from_json_dict(payload); self._sync_voice_box_controls(); return
        if record.asset_type == "resonance_profile":
            self.resonance_tract_state = ResonanceTractState.from_json_dict(payload); self._sync_resonance_controls(); return
        if record.asset_type == "character_profile":
            self.character_voice_profile = CharacterVoiceProfile.from_json_dict(payload); return
        if record.asset_type in {"imported_wav", "generated_wav"}:
            source = record.source_path or str(payload.get("source_path") or payload.get("audio_path") or "")
            if not source or not Path(source).exists():
                QMessageBox.warning(self, "Missing Audio Source", f"The source audio file is missing:\n{source or '(no source_path)'}")
                return
            item = self._audio_palette_item_from_source(Path(source), record.name)
            self.timeline_audio_palette.append(item)
            self.timeline_selected_palette_item_id = item.item_id
            self._timeline_refresh_palette_cards()
            return
        QMessageBox.information(self, "Load Library Asset", f"Loading is not yet defined for {record.asset_type} assets.")

    def _rename_selected_library_entry(self, checked: bool = False) -> None:
        del checked
        selected = self._selected_library_entry()
        if selected is None:
            return
        path, record = selected
        new_name, ok = QInputDialog.getText(self, "Rename Asset", "New asset name:", text=record.name)
        if not ok or not new_name.strip():
            return
        record.name = new_name.strip(); record.modified_at = _utc_now_iso()
        self._update_library_record(path, record)
        self._refresh_asset_library_view(); self._mark_project_dirty("library asset renamed")

    def _duplicate_selected_library_entry(self, checked: bool = False) -> None:
        del checked
        selected = self._selected_library_entry()
        if selected is None:
            return
        _path, record = selected
        duplicate = AssetLibraryRecord.from_json_dict(record.to_json_dict())
        duplicate.uuid = str(uuid.uuid4()); duplicate.name = f"{record.name} Copy"; duplicate.created_at = _utc_now_iso()
        self.storage.save_asset(duplicate)
        self._refresh_asset_library_view(); self._mark_project_dirty("library asset duplicated")

    def _delete_selected_library_entry(self, checked: bool = False) -> None:
        del checked
        selected = self._selected_library_entry()
        if selected is None:
            return
        path, record = selected
        result = QMessageBox.question(self, "Delete Asset", f"Delete library metadata for '{record.name}'?\n\nSource audio files are not deleted.", QMessageBox.Yes | QMessageBox.No, QMessageBox.No)
        if result != QMessageBox.Yes:
            return
        self._delete_library_path_for_record(path, record)
        self._refresh_asset_library_view(); self._mark_project_dirty("library asset deleted")

    def _toggle_selected_library_favorite(self, checked: bool = False) -> None:
        del checked
        selected = self._selected_library_entry()
        if selected is None:
            return
        path, record = selected
        record.favorite = not record.favorite
        self._update_library_record(path, record)
        self._refresh_asset_library_view(); self._mark_project_dirty("library asset favorite changed")

    def _edit_selected_library_tags_notes(self, checked: bool = False) -> None:
        del checked
        selected = self._selected_library_entry()
        if selected is None:
            return
        path, record = selected
        tags, ok = QInputDialog.getText(self, "Edit Tags", "Comma-separated tags:", text=", ".join(record.tags))
        if not ok:
            return
        notes, ok = QInputDialog.getMultiLineText(self, "Edit Notes", "Notes:", text=record.notes)
        if not ok:
            return
        record.tags = [tag.strip() for tag in tags.split(",") if tag.strip()]
        record.notes = notes
        self._update_library_record(path, record)
        self._refresh_asset_library_view(); self._mark_project_dirty("library asset tags/notes changed")

    def _refresh_asset_library_view(self) -> None:
        if self.asset_library_summary is None:
            return
        query = self.asset_library_search.text().strip().lower() if self.asset_library_search is not None else ""
        category = self.asset_library_category_combo.currentData() if self.asset_library_category_combo is not None else "all"
        sort_key = self.asset_library_sort_combo.currentData() if self.asset_library_sort_combo is not None else "modified"
        records = self.storage.iter_assets()
        filtered: List[Tuple[Path, AssetLibraryRecord]] = []
        for path, record in records:
            haystack = " ".join([record.name, record.asset_type, record.description, " ".join(record.tags), record.notes]).lower()
            if query and query not in haystack:
                continue
            if category != "all" and record.asset_type != category:
                continue
            filtered.append((path, record))
        if sort_key == "name":
            filtered.sort(key=lambda entry: entry[1].name.lower())
        elif sort_key == "type":
            filtered.sort(key=lambda entry: (entry[1].asset_type, entry[1].name.lower()))
        else:
            filtered.sort(key=lambda entry: entry[1].modified_at, reverse=True)
        self.asset_library_rows = filtered
        if self.asset_library_table is not None:
            self.asset_library_table.setRowCount(len(filtered))
            for row, (path, record) in enumerate(filtered):
                values = ["★" if record.favorite else "☆", record.name, record.asset_type, record.modified_at, ", ".join(record.tags), self._source_status_for_record(record)]
                for column, value in enumerate(values):
                    item = QTableWidgetItem(value)
                    item.setToolTip(str(path))
                    self.asset_library_table.setItem(row, column, item)
            self.asset_library_table.resizeColumnsToContents()
        lines = ["Speech Asset Library", f"Storage root: {self.storage.root}", f"Assets shown: {len(filtered)} of {len(records)}"]
        if not filtered:
            lines.append("No matching library assets yet. Save a phoneme, chain, word, profile, imported wav, generated wav, analysis, or export to populate the persistent library.")
        self.asset_library_summary.setPlainText("\n".join(lines))

    def _export_library_entry(self, checked: bool = False) -> None:
        del checked
        records = self.storage.iter_assets()
        if not records:
            QMessageBox.information(self, "Export Library Entry", "No saved library entries are available yet.")
            return
        names = [f"{record.name} [{record.asset_type}]" for _path, record in records]
        selected, ok = QInputDialog.getItem(self, "Export Library Entry", "Entry:", names, 0, False)
        if not ok or selected not in names:
            return
        source_path, _record = records[names.index(selected)]
        filename, _ = QFileDialog.getSaveFileName(self, "Export Library Entry", str(Path.home() / source_path.name), "WaveToy Asset (*.json)")
        if not filename:
            return
        shutil.copy2(source_path, filename)
        QMessageBox.information(self, "Export Library Entry", f"Exported:\n{filename}")

    def _import_library_entry(self, checked: bool = False) -> None:
        del checked
        filename, _ = QFileDialog.getOpenFileName(self, "Import Library Entry", str(Path.home()), "WaveToy Asset (*.json);;All Files (*)")
        if not filename:
            return
        try:
            record = AssetLibraryRecord.from_json_dict(json.loads(Path(filename).read_text(encoding="utf-8")))
            record.uuid = str(uuid.uuid4())
            record.created_at = _utc_now_iso()
            path = self.storage.save_asset(record)
            self._refresh_asset_library_view()
            QMessageBox.information(self, "Import Library Entry", f"Imported as:\n{path}")
        except Exception as exc:
            QMessageBox.warning(self, "Could not import library entry", str(exc))

    def _save_profile_assets(self, checked: bool = False) -> None:
        del checked
        self._save_library_asset("voice_source", getattr(self.voice_source_profile, "name", "Voice Source"), self.voice_source_profile.to_json_dict(), description="Voice Source profile snapshot")
        self._save_library_asset("voice_box", "Voice Box", self.voice_box_state.to_json_dict(), description="Voice Box profile snapshot")
        self._save_library_asset("resonance_profile", "Resonance Profile", self.resonance_tract_state.to_json_dict(), description="Resonance tract profile snapshot")
        self._save_library_asset("character_profile", getattr(self.character_voice_profile, "name", "Character Profile"), self.character_voice_profile.to_json_dict(), description="Character Voice Profile snapshot")
        QMessageBox.information(self, "Profile Library", "Saved current Voice Source, Voice Box, Resonance, and Character profiles to the Speech Asset Library.")

    def _build_actions(self) -> None:
        file_menu = self.menuBar().addMenu("File")
        for label, callback, shortcut in (
            ("New Project", self._new_project, QKeySequence.New),
            ("Open Project", self._open_project, QKeySequence.Open),
            ("Save Project", self._save_project, QKeySequence.Save),
            ("Save Project As", self._save_project_as, QKeySequence.SaveAs),
        ):
            action = QAction(label, self)
            action.triggered.connect(callback)
            action.setShortcut(shortcut)
            file_menu.addAction(action)
        self.recent_projects_menu = file_menu.addMenu("Recent Projects")
        self._refresh_recent_project_menu()
        file_menu.addSeparator()
        export_entry_action = QAction("Export Library Entry", self)
        export_entry_action.triggered.connect(self._export_library_entry)
        file_menu.addAction(export_entry_action)
        import_entry_action = QAction("Import Library Entry", self)
        import_entry_action.triggered.connect(self._import_library_entry)
        file_menu.addAction(import_entry_action)

        library_menu = self.menuBar().addMenu("Library")
        save_profiles_action = QAction("Save Current Profiles", self)
        save_profiles_action.triggered.connect(self._save_profile_assets)
        library_menu.addAction(save_profiles_action)
        refresh_library_action = QAction("Refresh Speech Asset Library", self)
        refresh_library_action.triggered.connect(self._refresh_asset_library_view)
        library_menu.addAction(refresh_library_action)

        edit_menu = self.menuBar().addMenu("Edit")
        self.performance_undo_action = QAction("Undo Performance Edit", self)
        self.performance_undo_action.setShortcut(QKeySequence.Undo)
        self.performance_undo_action.triggered.connect(self._undo_performance_edit)
        edit_menu.addAction(self.performance_undo_action)
        self.performance_redo_action = QAction("Redo Performance Edit", self)
        self.performance_redo_action.setShortcut(QKeySequence("Ctrl+Shift+Z"))
        self.performance_redo_action.triggered.connect(self._redo_performance_edit)
        edit_menu.addAction(self.performance_redo_action)
        self._update_performance_undo_actions()

        view_menu = self.menuBar().addMenu("View")
        diagnostics_action = QAction("Speech Diagnostics", self)
        diagnostics_action.triggered.connect(lambda _checked=False: self.speech_diagnostics_dock.show() if self.speech_diagnostics_dock is not None else None)
        view_menu.addAction(diagnostics_action)

        about = QAction("About WaveToy", self)
        about.triggered.connect(self._show_about)
        self.menuBar().addMenu("Help").addAction(about)

    def _build_shortcuts(self) -> None:
        """Install application-level shortcuts so focused sliders/buttons do not swallow Space."""
        play_shortcut = QShortcut(QKeySequence(Qt.Key_Space), self)
        play_shortcut.setContext(Qt.ApplicationShortcut)
        play_shortcut.setAutoRepeat(False)
        play_shortcut.activated.connect(self._handle_spacebar_playback)

        loop_shortcut = QShortcut(QKeySequence(Qt.SHIFT | Qt.Key_Space), self)
        loop_shortcut.setContext(Qt.ApplicationShortcut)
        loop_shortcut.setAutoRepeat(False)
        loop_shortcut.activated.connect(self._global_loop)

