        self._add_precise_slider_row(pitch_layout, 3, "Tiny Wiggle", self.cents_label, self.cents_slider, 100.0, suffix="¢", decimals=2, presets=[("Flat", -25.0), ("Center", 0.0), ("Sharp", 25.0)])
        tuning_title = QLabel("🎼 Tuning Playground")
