        self._add_precise_slider_row(motion_layout, 2, "Start Pitch", self.pitch_start_label, self.pitch_start, MIDI_SLIDER_SCALE, suffix=" MIDI", decimals=2, presets=[("C3", 48.0), ("A4", 69.0), ("C6", 84.0)])
