        self._add_precise_slider_row(motion_layout, 8, "End Wiggle", self.loud_end_label, self.loud_end, PERCENT_SLIDER_SCALE, suffix="%", decimals=2, presets=[("Quiet", 15.0), ("Medium", 45.0), ("Full", 100.0)])
