    def _import_voice_font_recording(self, checked: bool = False) -> None:
        del checked
        filenames, _selected_filter = QFileDialog.getOpenFileNames(self, "Import Voice Font Recording", "", "Audio Files (*.wav *.ogg *.flac *.mp3);;All Files (*)")
        if not filenames:
            return
        imported = []
        for filename in filenames:
            try:
                audio, sample_rate = load_audio_file(Path(filename))
                imported.append({"path": filename, "sample_rate": sample_rate, "duration_seconds": len(audio) / float(sample_rate), "status": "recorded"})
            except Exception as exc:
                imported.append({"path": filename, "status": "import_failed", "error": str(exc)})
        print(f"[WaveToy Voice Font] imported recordings consent_required=True files={json.dumps(imported, ensure_ascii=False)}")
        QMessageBox.information(self, "Voice Font Import", "Imported recording metadata for consent-first workflow. Record/Analyze remain disabled placeholders; no voice cloning is implemented.")


    def _sync_musical_timing_to_timeline(self) -> None:
        self.musical_timing_settings = self.musical_timing_settings.clamped()
        self.performance_timeline_engine.set_musical_timing_settings(self.musical_timing_settings)
        self.performance_timeline_engine.mark_timing_dirty("musical timing changed")
        self.articulation_word_render_settings["musical_timing_settings"] = self.musical_timing_settings.to_json_dict()
        self._refresh_musical_timing_controls()
        if self.articulation_timeline_canvas is not None:
            self.articulation_timeline_canvas.set_musical_timing_settings(self.musical_timing_settings)
        self._mark_articulation_word_dirty()
        self._update_speech_diagnostics_panel(self.current_phoneme)

    def _set_musical_timing_enabled(self, enabled: bool) -> None:
        before = self._performance_edit_snapshot()
        self.musical_timing_settings.enabled = bool(enabled)
        self._sync_musical_timing_to_timeline()
        self._push_performance_transaction("Musical Timing Change", "musical timing changed", before)

    def _set_musical_bpm(self, bpm: float) -> None:
        before = self._performance_edit_snapshot()
        self.musical_timing_settings.bpm = float(bpm)
        self._sync_musical_timing_to_timeline()
        self._push_performance_transaction("Musical Timing Change", "musical timing changed", before)

    def _set_musical_time_signature(self, text: str) -> None:
        before = self._performance_edit_snapshot()
        try:
            numerator_text, denominator_text = str(text).split("/", 1)
            self.musical_timing_settings.time_signature_numerator = int(numerator_text)
            self.musical_timing_settings.time_signature_denominator = int(denominator_text)
        except Exception:
            self.musical_timing_settings.time_signature_numerator = 4
            self.musical_timing_settings.time_signature_denominator = 4
        self._sync_musical_timing_to_timeline()
        self._push_performance_transaction("Musical Timing Change", "musical timing changed", before)

    def _set_musical_snap_subdivision(self, text: str) -> None:
        before = self._performance_edit_snapshot()
        self.musical_timing_settings.snap_subdivision = str(text)
        self.musical_timing_settings.snap_enabled = str(text) != "Off"
        self._sync_musical_timing_to_timeline()
        self._push_performance_transaction("Musical Timing Change", "musical timing changed", before)

    def _set_musical_count_in_enabled(self, enabled: bool) -> None:
        before = self._performance_edit_snapshot()
        self.musical_timing_settings.count_in_enabled = bool(enabled)
        self._sync_musical_timing_to_timeline()
        self._push_performance_transaction("Musical Timing Change", "musical timing changed", before)

    def _set_musical_grid_visible(self, enabled: bool) -> None:
        before = self._performance_edit_snapshot()
        self.musical_timing_settings.grid_visible = bool(enabled)
        self._sync_musical_timing_to_timeline()
        self._push_performance_transaction("Musical Timing Change", "musical timing changed", before)

    def _set_singing_mode_enabled(self, enabled: bool) -> None:
        self.articulation_word_render_settings["singing_mode_enabled"] = bool(enabled)
        self._mark_articulation_word_dirty()
        self._update_speech_diagnostics_panel(self.current_phoneme)

    def _singing_mode_enabled(self) -> bool:
        if self.singing_mode_checkbox is not None:
            return bool(self.singing_mode_checkbox.isChecked())
        return bool(self.articulation_word_render_settings.get("singing_mode_enabled", False))

    def _note_events_json(self) -> List[Dict[str, object]]:
        return [note.to_json_dict() for note in self.note_events]

    def _syllable_stress_json(self) -> List[Dict[str, object]]:
        return [marker.to_json_dict() for marker in self.syllable_stress_markers]

    def _ensure_default_note_event(self) -> None:
        if self.note_events or not self.articulation_chain_items:
            return
        duration_ms = max(1.0, float(self._articulation_motion_timeline()[1]))
        voiced_indices = [i for i, item in enumerate(self.articulation_chain_items) if item.phoneme_for_render().voiced and item.phoneme_for_render().phoneme_family not in {"fricative", "affricate", "stop"}]
        self.note_events.append(NoteEvent(start_ms=0.0, duration_ms=duration_ms, midi_note=60, note_name="C4", target_pitch_hz=midi_note_to_hz(60), lyric="preview", phoneme_indices=voiced_indices).clamped())
        self.articulation_word_render_settings["note_events"] = self._note_events_json()

    def _pitch_curve_from_note_events(self, duration_ms: float | None = None) -> List[PitchAutomationPoint]:
        del duration_ms
        notes = [note.clamped() for note in self.note_events]
        if not notes:
            self.pitch_automation_points = []
            if hasattr(self, "performance_timeline_engine"):
                self._sync_timeline_bridges()
            return []
        points: List[PitchAutomationPoint] = []
        for note in sorted(notes, key=lambda event: event.start_ms):
            pitch = float(note.target_pitch_hz or midi_note_to_hz(note.midi_note, note.pitch_bend_cents))
            start = note.start_ms
            # Safety pass: keep pitch automation lightweight. Vibrato and portamento
            # values remain serialized on NoteEvent for future tasks, but the active
            # preview/export curve exposes only stable note targets for now.
            points.append(PitchAutomationPoint(start, pitch, "hold", "note_event"))
            points.append(PitchAutomationPoint(start + note.duration_ms, pitch, "hold", "note_event"))
        self.pitch_automation_points = sorted(points, key=lambda point: point.time_ms)
        if hasattr(self, "performance_timeline_engine"):
            self._sync_timeline_bridges()
        return self.pitch_automation_points

    def _pitch_curve_json(self, duration_ms: float | None = None) -> List[Dict[str, object]]:
        return [point.to_json_dict() for point in self._pitch_curve_from_note_events(duration_ms)]

    def _pitch_at_ms(self, elapsed_ms: float) -> float | None:
        curve = self._pitch_curve_from_note_events()
        if not curve:
            return None
        before = curve[0]
        for point in curve:
            if point.time_ms > elapsed_ms:
                break
            before = point
        return max(20.0, before.pitch_hz)

    def _active_note_at_ms(self, elapsed_ms: float) -> NoteEvent | None:
        for note in self.note_events:
            n = note.clamped()
            if n.start_ms <= elapsed_ms <= n.start_ms + n.duration_ms:
                return n
        return None

    def _beat_grid_json(self, duration_ms: float) -> List[Dict[str, object]]:
        self.performance_timeline_engine.set_musical_timing_settings(self.musical_timing_settings)
        return self.performance_timeline_engine.beat_grid(duration_ms)

    def _tempo_map_json(self) -> List[Dict[str, object]]:
        timing = self.musical_timing_settings.clamped()
        return [{"start_ms": 0.0, "bpm": timing.bpm, "time_signature": f"{timing.time_signature_numerator}/{timing.time_signature_denominator}", "beat_unit_ms": timing.beat_unit_ms}]

    def _refresh_pitch_lane_preview(self) -> None:
        if self.pitch_lane_preview_label is None:
            return
        curve = self._pitch_curve_from_note_events()
        if not curve:
            self.pitch_lane_preview_label.setText("Pitch lane preview: no note events yet; Singing Preview stays vowel-anchored and default off.")
            return
        preview = ", ".join(f"{point.time_ms:.0f} ms → {point.pitch_hz:.1f} Hz" for point in curve[:6])
        if len(curve) > 6:
            preview += ", …"
        self.pitch_lane_preview_label.setText(f"Read-only pitch lane: {preview}")


    def _articulation_smooth_transitions_enabled(self) -> bool:
        if self.articulation_smooth_transitions_checkbox is not None:
            return bool(self.articulation_smooth_transitions_checkbox.isChecked())
        return bool(self.articulation_word_render_settings.get("smooth_mouth_transitions", True))

    def _chain_transition_duration_ms(self, left: ArticulationChainItem, right: ArticulationChainItem) -> int:
        if left.transition_to_next_ms is not None:
            return int(left.transition_to_next_ms)
        model = phoneme_pair_transition_model(left.phoneme_for_render(), right.phoneme_for_render())
        return int(model.default_transition_ms)

    def _chain_transition_curve(self, left: ArticulationChainItem, right: ArticulationChainItem) -> str:
        # Existing chains saved Smoothstep as the neutral default. Non-default
        # user-selected curves still override the model curve.
        if left.transition_curve in ARTICULATION_TRANSITION_CURVES and left.transition_curve != ARTICULATION_DEFAULT_TRANSITION_CURVE:
            return left.transition_curve
        return phoneme_pair_transition_model(left.phoneme_for_render(), right.phoneme_for_render()).curve

    def _articulation_motion_timeline(self, include_word_gaps: bool = False) -> Tuple[List[Dict[str, object]], int]:
        del include_word_gaps
        segments, total_ms, _stop_events, _burst_events = self._build_articulation_envelope_timeline()
        return segments, total_ms

    def _refresh_articulation_motion_timeline(self) -> None:
        segments, total_ms = self._articulation_motion_timeline()
        self.articulation_playhead_ms = float(np.clip(self.articulation_playhead_ms, 0.0, total_ms))
        blocks: List[Tuple[str, float, float, str]] = []
        for segment in segments:
            start = float(segment["start"]) / total_ms
            end = float(segment["end"]) / total_ms
            if segment["kind"] == "transition":
                blocks.append(("→", start, end, "#ffffff"))
            elif segment["kind"] == "hold":
                phoneme = segment["from"]
                blocks.append((phoneme.name, start, end, phoneme.preview_color))
        if self.articulation_motion_canvas is not None:
            self.articulation_motion_canvas.set_motion_timeline(blocks)
        if self.articulation_timeline_canvas is not None:
            self.articulation_timeline_canvas.set_musical_timing_settings(self.musical_timing_settings)
            self.articulation_timeline_canvas.set_zoom(self.articulation_timeline_zoom)
            self.articulation_timeline_canvas.set_timeline(self.articulation_chain_items, total_ms, self.articulation_playhead_ms)
            selected_index = self.articulation_selected_chain_index
            self.articulation_timeline_canvas.selected_index = selected_index if isinstance(selected_index, int) and 0 <= selected_index < len(self.articulation_chain_items) else None
            self.articulation_timeline_canvas.update()
        self._refresh_pitch_lane_preview()
        if self.articulation_envelope_canvas is not None:
            self.articulation_envelope_canvas.set_timeline(segments, total_ms, self.articulation_playhead_ms)
        if self.articulation_formant_canvas is not None:
            self.articulation_formant_canvas.set_timeline(segments, total_ms, self.articulation_playhead_ms)
        if self.articulation_boundary_curve_combo is not None:
            boundary_index = min(self.articulation_selected_chain_index or 0, max(0, len(self.articulation_chain_items) - 2))
            curve = self.articulation_chain_items[boundary_index].transition_curve if boundary_index < len(self.articulation_chain_items) - 1 else ARTICULATION_DEFAULT_TRANSITION_CURVE
            self.articulation_boundary_curve_combo.blockSignals(True)
            self.articulation_boundary_curve_combo.setCurrentText(curve if curve in ARTICULATION_TRANSITION_CURVES else ARTICULATION_DEFAULT_TRANSITION_CURVE)
            self.articulation_boundary_curve_combo.blockSignals(False)
        self._refresh_graphical_chain_editor()

    def _motion_state_at_ms(self, elapsed_ms: float) -> Tuple[ArticulationPhoneme, str, str, float, float, int, bool]:
        segments, total_ms = self._articulation_motion_timeline()
        if not segments:
            phoneme = self.current_phoneme.clamped()
            return phoneme, phoneme.name, "—", 0.0, 0.0, 0, False
        elapsed_ms = float(np.clip(elapsed_ms, 0.0, total_ms))
        active = segments[-1]
        for segment in segments:
            if float(segment["start"]) <= elapsed_ms <= float(segment["end"]):
                active = segment
                break
        start = float(active["start"])
        end = max(start + 1.0, float(active["end"]))
        local = float(np.clip((elapsed_ms - start) / (end - start), 0.0, 1.0))
        left = active["from"]
        right = active["to"]
        transition_duration_ms = self._chain_transition_duration_ms(self.articulation_chain_items[int(active["index"])], self.articulation_chain_items[int(active["index"]) + 1]) if int(active["index"]) < len(self.articulation_chain_items) - 1 else 0
        in_transition = active["kind"] == "transition"
        if in_transition:
            model = active.get("transition_model_object")
            phoneme = interpolate_articulation_phoneme(left, right, local, str(active.get("curve", ARTICULATION_DEFAULT_TRANSITION_CURVE)), model if isinstance(model, PhonemePairTransitionModel) else None)
            next_name = right.name
            transition_progress = articulation_curve_progress(local, str(active.get("curve", ARTICULATION_DEFAULT_TRANSITION_CURVE)))
        else:
            phoneme, _diphthong_diagnostics = apply_diphthong_transition_shape(left, local)
            next_index = int(active["index"]) + 1
            next_name = self.articulation_chain_items[next_index].phoneme.name if next_index < len(self.articulation_chain_items) else "—"
            transition_progress = float(_diphthong_diagnostics.get("diphthong_progress", 0.0)) if _diphthong_diagnostics else 0.0
        return phoneme, left.name, next_name, transition_progress, elapsed_ms / total_ms, transition_duration_ms, in_transition

    def _set_articulation_motion_elapsed(self, elapsed_ms: float) -> None:
        if self.articulation_motion_canvas is None:
            return
        phoneme, current_name, next_name, transition_progress, playhead, transition_ms, in_transition = self._motion_state_at_ms(elapsed_ms)
        _segments_for_total, total_for_scrub = self._articulation_motion_timeline()
        self.articulation_playhead_ms = float(np.clip(elapsed_ms, 0.0, max(1, total_for_scrub)))
        self.articulation_motion_canvas.set_motion_state(phoneme, current_name, next_name, transition_progress, playhead, transition_ms, in_transition)
        if self.articulation_motion_side_canvas is not None:
            self.articulation_motion_side_canvas.set_motion_state(phoneme, current_name, next_name, transition_progress, playhead, transition_ms, in_transition)
        self._refresh_articulation_motion_timeline()
        f1, f2, f3 = formants_from_articulation(phoneme)
        values = ", ".join(f"{name} {getattr(phoneme, name):.2f}" for name in ("mouth_open", "tongue_height", "tongue_frontness", "lip_rounding"))
        voiced_level = self._continuous_voiced_gain(phoneme)
        airflow_level = float(np.clip(phoneme.air_pressure, 0.0, 1.0))
        active_model_text = ""
        segments, _total_ms = self._articulation_motion_timeline()
        for segment in segments:
            if float(segment["start"]) <= self.articulation_playhead_ms <= float(segment["end"]):
                if segment.get("kind") == "transition":
                    active_model_text = f" • model {segment.get('transition_model_id', 'legacy')} strength {segment.get('transition_strength', 0.0)}"
                break
        status = (
            f"Active phoneme {current_name} → target {next_name} • transition {transition_ms} ms • {'active' if in_transition else 'holding'} • "
            f"progress {int(transition_progress * 100)}%{active_model_text} • voiced level {voiced_level:.2f} • airflow level {airflow_level:.2f} • "
            f"playhead {int(playhead * 100)}% • {values} • F1/F2/F3 {f1:.0f}/{f2:.0f}/{f3:.0f} Hz"
        )
        if self.articulation_motion_status_label is not None:
            self.articulation_motion_status_label.setText(status)
        if self.articulation_scrub_label is not None:
            self.articulation_scrub_label.setText(status)
        transition_model = "transition" if in_transition else "hold"
        if active_model_text:
            transition_model = active_model_text.strip(" •")
        self._update_speech_diagnostics_panel(phoneme, next_name, transition_model, transition_progress)

    def _start_articulation_motion(self, *, loop: bool = False, speed: float = 1.0, audio: np.ndarray | None = None) -> None:
        if not self.articulation_chain_items:
            QMessageBox.information(self, "Word Motion Preview", "Add at least one phoneme to the Articulation Chain first.")
            return
        self.articulation_motion_loop = bool(loop)
        self.articulation_motion_speed = max(0.05, float(speed))
        self.word_motion_play_audio = audio is not None and audio.size > 0 and abs(self.articulation_motion_speed - 1.0) < 1e-6
        _segments, timeline_total_ms = self._articulation_motion_timeline(include_word_gaps=False)
        self.word_motion_timeline_total_ms = max(1, int(timeline_total_ms))
        if audio is not None and audio.size > 0:
            self.word_motion_duration_seconds = max(0.001, len(audio) / SAMPLE_RATE) / self.articulation_motion_speed
        else:
            self.word_motion_duration_seconds = max(0.001, self.word_motion_timeline_total_ms / 1000.0) / self.articulation_motion_speed
        self.articulation_motion_total_ms = max(1, int(round(self.word_motion_duration_seconds * 1000.0)))
        self.word_motion_start_monotonic = time.monotonic()
        self.articulation_motion_started_at = self.word_motion_start_monotonic
        if self.word_motion_play_audio and audio is not None:
            self._play_audio_array(audio)
        self._refresh_articulation_motion_timeline()
        self.articulation_motion_timer.start(16)
        self._articulation_motion_tick()

    def _current_gapless_word_audio(self) -> np.ndarray:
        if not self._current_word_audio_is_fresh():
            return self._render_word_audio_for_current_chain()
        return self.articulation_word_render_audio

    def _play_articulation_motion(self, checked: bool = False) -> None:
        del checked
        if not self._can_start_playback():
            return
        audio = self._current_gapless_word_audio()
        if audio.size == 0:
            return
        self._start_articulation_motion(loop=False, speed=1.0, audio=audio)

    def _loop_articulation_motion(self, checked: bool = False) -> None:
        del checked
        if self.articulation_motion_loop and self.articulation_motion_timer.isActive():
            self._stop_articulation_motion()
            return
        audio = self._current_gapless_word_audio()
        if audio.size == 0:
            return
        self._start_articulation_motion(loop=True, speed=1.0, audio=audio)

    def _slow_articulation_motion(self, checked: bool = False) -> None:
        del checked
        self._start_articulation_motion(loop=False, speed=0.35, audio=None)
        if self.articulation_motion_status_label is not None:
            self.articulation_motion_status_label.setText("Slow Motion Visual Only • audio is not time-stretched.")

    def _stop_articulation_motion(self, checked: bool = False) -> None:
        del checked
        self.articulation_motion_started_at = None
        self.word_motion_start_monotonic = None
        self.word_motion_play_audio = False
        self.articulation_motion_loop = False
        self.articulation_motion_timer.stop()
        if sd is not None:
            try:
                sd.stop()
            except Exception:
                pass
        self._stop_fallback_playback()
        if self.articulation_motion_status_label is not None:
            self.articulation_motion_status_label.setText("Motion stopped • audio stopped.")

    def _articulation_motion_tick(self) -> None:
        if self.articulation_motion_started_at is None or self.articulation_motion_total_ms <= 0:
            self.articulation_motion_timer.stop()
            return
        elapsed_ms = (time.monotonic() - self.articulation_motion_started_at) * 1000.0 * self.articulation_motion_speed
        if elapsed_ms >= self.articulation_motion_total_ms:
            if self.articulation_motion_loop:
                self.articulation_motion_started_at = time.monotonic()
                self.word_motion_start_monotonic = self.articulation_motion_started_at
                elapsed_ms = 0.0
                if self.word_motion_play_audio and self.articulation_word_render_audio.size:
                    self._play_audio_array(self.articulation_word_render_audio)
            else:
                elapsed_ms = float(self.articulation_motion_total_ms)
                self.articulation_motion_timer.stop()
                self.articulation_motion_started_at = None
                self.word_motion_start_monotonic = None
        progress = 0.0 if self.articulation_motion_total_ms <= 0 else float(np.clip(elapsed_ms / self.articulation_motion_total_ms, 0.0, 1.0))
        timeline_elapsed_ms = progress * float(max(1, self.word_motion_timeline_total_ms))
        self._set_articulation_motion_elapsed(timeline_elapsed_ms)
        self._set_performance_playhead_ms(int(round(timeline_elapsed_ms)), scrub=False)

    def _mark_articulation_word_dirty(self) -> None:
        self._mark_project_dirty("articulation chain changed")
        self.articulation_word_render_audio = np.zeros((0, 2), dtype=np.float32)
        self.articulation_word_render_signature = None
        self.articulation_last_word_render_path = None
        self.articulation_last_word_render_created_at = None
        self._update_articulation_word_status()

    def _chain_custom_transition_summary(self) -> str:
        custom = [
            f"{item.phoneme.name}→{self.articulation_chain_items[index + 1].phoneme.name} {int(item.transition_to_next_ms)} ms"
            for index, item in enumerate(self.articulation_chain_items[:-1])
            if item.transition_to_next_ms is not None
        ]
        if not custom:
            return "family transition rules"
        preview = ", ".join(custom[:3])
        extra = f", +{len(custom) - 3} more" if len(custom) > 3 else ""
        return f"custom transitions: {preview}{extra}"

    def _update_articulation_word_status(self) -> None:
        if self.articulation_word_status_label is None:
            return
        transition_text = self._chain_custom_transition_summary()
        if self.articulation_word_render_audio.size:
            duration = len(self.articulation_word_render_audio) / SAMPLE_RATE
            path_text = f" • exported: {self.articulation_last_word_render_path}" if self.articulation_last_word_render_path else ""
            mode = self._articulation_word_render_mode()
            self.articulation_word_status_label.setText(
                f"Word ready • {duration:.2f}s • {len(self.articulation_chain_items)} phoneme(s) • render mode: {mode} • {transition_text}{path_text}"
            )
        elif self.articulation_chain_items:
            mode = self._articulation_word_render_mode()
            self.articulation_word_status_label.setText(
                f"{len(self.articulation_chain_items)} phoneme(s) in chain • render mode: {mode} • {transition_text}."
            )
        else:
            self.articulation_word_status_label.setText("Create Word makes a smoothed render without changing the editable chain.")

    def _chain_boundary_crossfade_ms(self, left: ArticulationChainItem, right: ArticulationChainItem) -> int:
        left_family = left.phoneme_for_render().phoneme_family
        right_family = right.phoneme_for_render().phoneme_family
        if left_family == "stop" and right_family == "vowel":
            return 8
        if left_family in {"fricative", "affricate"} and right_family == "vowel":
            return 30
        if left_family == "nasal" and right_family == "vowel":
            return 40
        if left_family in {"glide", "liquid"} and right_family == "vowel":
            return 55
        if left_family == "vowel" and right_family == "vowel":
            return 60
        if left_family == "vowel" and right_family != "vowel":
            return ARTICULATION_DEFAULT_WORD_CROSSFADE_MS
        return int(self.articulation_word_render_settings.get("crossfade_ms", ARTICULATION_DEFAULT_WORD_CROSSFADE_MS))

    def _word_crossfade_ms(self, requested_ms: int, left: ArticulationChainItem | None = None, right: ArticulationChainItem | None = None) -> int:
        rule_ms = self._chain_boundary_crossfade_ms(left, right) if left is not None and right is not None else ARTICULATION_DEFAULT_WORD_CROSSFADE_MS
        requested_ms = int(requested_ms)
        if requested_ms <= 0 or requested_ms in {12, ARTICULATION_DEFAULT_WORD_CROSSFADE_MS}:
            requested_ms = rule_ms
        minimum_ms = int(self.articulation_word_render_settings.get("minimum_crossfade_ms", ARTICULATION_MIN_WORD_CROSSFADE_MS))
        return max(minimum_ms, requested_ms)

    def _word_gap_after_ms(self, item: ArticulationChainItem, index: int) -> int:
        requested = int(item.gap_after_ms) if index < len(self.articulation_chain_items) - 1 else 0
        if requested > 0 and not bool(self.articulation_word_render_settings.get("allow_word_gaps", False)):
            print(f"[WaveToy Word] requested gap ignored after {item.phoneme.name}: {requested} ms")
            return 0
        return max(0, requested)

    def _fade_word_edges(self, audio: np.ndarray) -> np.ndarray:
        if audio.size == 0:
            return audio.astype(np.float32)
        audio = np.array(audio, dtype=np.float32, copy=True)
        fade_in = int(float(self.articulation_word_render_settings.get("word_fade_in_ms", 5)) * SAMPLE_RATE / 1000.0)
        fade_out = int(float(self.articulation_word_render_settings.get("word_fade_out_ms", 8)) * SAMPLE_RATE / 1000.0)
        if fade_in > 0:
            fade_in = min(fade_in, len(audio))
            audio[:fade_in] *= np.linspace(0.0, 1.0, fade_in, dtype=np.float32)[:, None]
        if fade_out > 0:
            fade_out = min(fade_out, len(audio))
            audio[-fade_out:] *= np.linspace(1.0, 0.0, fade_out, dtype=np.float32)[:, None]
        return audio

    def _smooth_word_boundaries(self, audio: np.ndarray, boundaries: List[int]) -> np.ndarray:
        if audio.size == 0:
            return audio.astype(np.float32)
        radius = int(float(self.articulation_word_render_settings.get("boundary_smoothing_ms", 8)) * SAMPLE_RATE / 1000.0)
        if radius <= 1:
            return audio.astype(np.float32)
        smoothed = np.array(audio, dtype=np.float32, copy=True)
        kernel_size = max(3, min(radius, 801))
        if kernel_size % 2 == 0:
            kernel_size += 1
        kernel = np.ones(kernel_size, dtype=np.float32) / float(kernel_size)
        for boundary in boundaries:
            start = max(0, int(boundary) - radius)
            end = min(len(smoothed), int(boundary) + radius)
            if end - start <= kernel_size:
                continue
            window = smoothed[start:end]
            filtered = np.column_stack([np.convolve(window[:, channel], kernel, mode="same") for channel in range(window.shape[1])])
            blend = np.sin(np.linspace(0.0, math.pi, end - start, dtype=np.float32))[:, None] * 0.35
            smoothed[start:end] = window * (1.0 - blend) + filtered * blend
        return smoothed.astype(np.float32)

    def _append_word_clip(self, word: np.ndarray, clip: np.ndarray, crossfade_ms: int, gap_after_ms: int, boundaries: List[int]) -> np.ndarray:
        if clip.size == 0:
            return word.astype(np.float32)
        clip = np.array(clip, dtype=np.float32, copy=True)
        if word.size == 0:
            combined = clip
        else:
            crossfade = int(max(0, crossfade_ms) * SAMPLE_RATE / 1000.0)
            crossfade = min(crossfade, len(word) - 1, len(clip) - 1, int(0.50 * min(len(word), len(clip))))
            if crossfade > 1:
                fade_out = np.cos(np.linspace(0.0, math.pi / 2.0, crossfade, dtype=np.float32))[:, None]
                fade_in = np.sin(np.linspace(0.0, math.pi / 2.0, crossfade, dtype=np.float32))[:, None]
                overlap = word[-crossfade:] * fade_out + clip[:crossfade] * fade_in
                boundary = len(word) - crossfade // 2
                boundaries.append(boundary)
                print(f"[WaveToy Word] boundary crossfade duration {crossfade * 1000.0 / SAMPLE_RATE:.1f} ms at sample {boundary}")
                combined = np.vstack([word[:-crossfade], overlap, clip[crossfade:]])
            else:
                boundaries.append(len(word))
                combined = np.vstack([word, clip])
        gap_samples = int(max(0, gap_after_ms) * SAMPLE_RATE / 1000.0)
        if gap_samples:
            combined = np.vstack([combined, np.zeros((gap_samples, 2), dtype=np.float32)])
        return combined.astype(np.float32)

    def _effective_transition_samples(self, left_clip: np.ndarray, right_clip: np.ndarray, requested_ms: int, left: ArticulationChainItem, right: ArticulationChainItem) -> int:
        requested_samples = int(max(0, requested_ms) * SAMPLE_RATE / 1000.0)
        if requested_samples <= 0 or left_clip.size == 0 or right_clip.size == 0:
            return 0
        shorter = max(1, min(len(left_clip), len(right_clip)))
        left_family = left.phoneme_for_render().phoneme_family
        right_family = right.phoneme_for_render().phoneme_family
        fraction = 0.45
        if left_family == "stop" or right_family == "stop":
            fraction = 0.30
        if left_family == "stop" and right_family == "vowel":
            fraction = 0.22
        maximum_samples = max(1, int(shorter * fraction))
        return int(min(requested_samples, maximum_samples))

    def _overlap_word_clip(self, word: np.ndarray, clip: np.ndarray, overlap_samples: int, boundaries: List[int]) -> np.ndarray:
        if clip.size == 0:
            return word.astype(np.float32)
        clip = np.array(clip, dtype=np.float32, copy=True)
        if word.size == 0:
            return clip.astype(np.float32)
        overlap_samples = int(min(max(0, overlap_samples), len(word) - 1, len(clip) - 1))
        if overlap_samples <= 1:
            boundaries.append(len(word))
            return np.vstack([word, clip]).astype(np.float32)
        fade_out = np.cos(np.linspace(0.0, math.pi / 2.0, overlap_samples, dtype=np.float32))[:, None]
        fade_in = np.sin(np.linspace(0.0, math.pi / 2.0, overlap_samples, dtype=np.float32))[:, None]
        overlap = word[-overlap_samples:] * fade_out + clip[:overlap_samples] * fade_in
        boundary = len(word) - overlap_samples // 2
        boundaries.append(boundary)
        return np.vstack([word[:-overlap_samples], overlap, clip[overlap_samples:]]).astype(np.float32)

    def _transition_gain_snapshot(self, phoneme: ArticulationPhoneme) -> Dict[str, float]:
        debug = articulation_synthesis_debug(phoneme)
        return {
            "voiced_gain": float(debug.get("voiced_gain", 0.0)),
            "noise_gain": float(debug.get("noise_gain", 0.0)),
            "tonal_gain": float(debug.get("tonal_gain", 0.0)),
        }

    def _log_transition_boundary(self, left: ArticulationChainItem, right: ArticulationChainItem, requested_ms: int, effective_samples: int, inserted_silence_samples: int = 0, transition_render_samples: int = 0, interpolated_articulation_used: bool = False) -> None:
        left_phoneme = left.phoneme_for_render()
        right_phoneme = right.phoneme_for_render()
        start_gain = self._transition_gain_snapshot(left_phoneme)
        end_gain = self._transition_gain_snapshot(right_phoneme)
        effective_ms = effective_samples * 1000.0 / SAMPLE_RATE
        print(
            "[WaveToy Transition] "
            f"{left_phoneme.name}->{right_phoneme.name} "
            f"families={left_phoneme.phoneme_family}->{right_phoneme.phoneme_family} "
            f"requested_transition_ms={int(requested_ms)} "
            f"effective_transition_ms={effective_ms:.1f} "
            f"crossfade_samples={int(effective_samples)} "
            f"inserted_silence_samples={int(inserted_silence_samples)} "
            f"transition_render_samples={int(transition_render_samples)} "
            f"interpolated_articulation_used={bool(interpolated_articulation_used)} "
            f"voiced_gain_start={start_gain['voiced_gain']:.3f} "
            f"voiced_gain_end={end_gain['voiced_gain']:.3f} "
            f"noise_gain_start={start_gain['noise_gain']:.3f} "
            f"noise_gain_end={end_gain['noise_gain']:.3f} "
            f"tonal_gain_start={start_gain['tonal_gain']:.3f} "
            f"tonal_gain_end={end_gain['tonal_gain']:.3f}"
        )
        if bool(self.articulation_word_render_settings.get("transition_debug_verbose", False)):
            print(
                "[WaveToy Transition] verbose "
                f"left_duration_ms={left_phoneme.duration_ms} right_duration_ms={right_phoneme.duration_ms} "
                f"left_source={left_phoneme.source_mode} right_source={right_phoneme.source_mode}"
            )

    def _log_word_render_debug(self, render_mode: str, audio: np.ndarray) -> None:
        gains = [self._transition_gain_snapshot(item.phoneme_for_render()) for item in self.articulation_chain_items]
        voiced_gain = max((float(gain.get("voiced_gain", 0.0)) for gain in gains), default=0.0)
        noise_gain = max((float(gain.get("noise_gain", 0.0)) for gain in gains), default=0.0)
        source_modes = ",".join(dict.fromkeys(item.phoneme_for_render().source_mode for item in self.articulation_chain_items)) or ARTICULATION_SOURCE_DEFAULT
        final_peak = float(np.max(np.abs(audio))) if audio.size else 0.0
        print(
            "[WaveToy Word Debug] "
            f"render_mode={render_mode} "
            f"voiced_gain={voiced_gain:.3f} "
            f"noise_gain={noise_gain:.3f} "
            f"source_mode={source_modes} "
            f"final_peak={final_peak:.3f}"
        )

    def _log_play_word_render_path(self, render_mode: str, audio: np.ndarray, cached_reused: bool, fresh_render_created: bool) -> None:
        duration = float(len(audio)) / float(SAMPLE_RATE) if audio.size else 0.0
        peak = float(np.max(np.abs(audio))) if audio.size else 0.0
        phoneme_sequence = " + ".join(item.phoneme.name for item in self.articulation_chain_items) or "<empty>"
        print(
            "[WaveToy Play Word] "
            f"render_mode={render_mode} "
            f"duration={duration:.3f}s "
            f"peak={peak:.3f} "
            f"phonemes={phoneme_sequence} "
            f"cached_reused={cached_reused} "
            f"fresh_render_created={fresh_render_created}"
        )


    def _accentuation_gain_for_db(self, accentuation_db: float) -> float:
        return float(np.clip(10.0 ** (float(accentuation_db) / 20.0), 0.05, 4.0))

    def _accentuation_gain_for_item(self, item: ArticulationChainItem) -> float:
        return self._accentuation_gain_for_db(float(getattr(item, "accentuation_db", 0.0)))

    def _apply_chain_item_accentuation(self, audio: np.ndarray, item: ArticulationChainItem) -> np.ndarray:
        if audio.size == 0:
            return audio
        gain = self._accentuation_gain_for_item(item)
        if abs(gain - 1.0) <= 1.0e-6:
            return audio.astype(np.float32, copy=False)
        accented = audio.astype(np.float32, copy=False) * np.float32(gain)
        peak = float(np.max(np.abs(accented))) if accented.size else 0.0
        if peak > 0.98:
            accented = np.tanh(accented.astype(np.float64))
            limited_peak = float(np.max(np.abs(accented))) if accented.size else 0.0
            if limited_peak > 0.98:
                accented = accented / limited_peak * 0.98
        return accented.astype(np.float32)

    def _accentuation_summary(self) -> Dict[str, float]:
        values = [float(getattr(item, "accentuation_db", 0.0)) for item in self.articulation_chain_items]
        if not values:
            return {"active_phoneme_accentuation_db": 0.0, "max_accentuation_db": 0.0, "gain_applied": 1.0}
        selected = self._selected_chain_item()
        active_db = float(getattr(selected, "accentuation_db", 0.0)) if selected is not None else values[0]
        max_db = max(values, key=lambda value: abs(value))
        return {
            "active_phoneme_accentuation_db": round(active_db, 3),
            "max_accentuation_db": round(float(max_db), 3),
            "gain_applied": round(self._accentuation_gain_for_db(active_db), 6),
        }


    def _singing_pitch_follow_strength(self, phoneme: ArticulationPhoneme) -> float:
        family = str(phoneme.phoneme_family)
        if family == "vowel":
            return 1.0
        if family == "glide" and phoneme.voiced:
            return 0.75
        if family == "liquid" and phoneme.voiced:
            return 0.70
        if family == "nasal" and phoneme.voiced:
            return 0.55
        if family == "fricative" and phoneme.voiced:
            return 0.25
        return 0.0


    def _chain_item_start_times_ms(self) -> List[float]:
        starts: List[float] = []
        cursor = 0.0
        for index, item in enumerate(self.articulation_chain_items):
            starts.append(cursor)
            cursor += int(item.duration_ms or item.phoneme.duration_ms)
            if index < len(self.articulation_chain_items) - 1:
                cursor += self._chain_transition_duration_ms(item, self.articulation_chain_items[index + 1])
        return starts

    def _phoneme_with_singing_pitch(self, item: ArticulationChainItem, start_ms: float) -> ArticulationPhoneme:
        phoneme = item.phoneme_for_render().clamped()
        if not self._singing_mode_enabled():
            return phoneme
        strength = self._singing_pitch_follow_strength(phoneme)
        if strength <= 0.0:
            return phoneme
        target_pitch = self._pitch_at_ms(start_ms + max(0.0, phoneme.duration_ms * 0.5))
        if target_pitch is None:
            return phoneme
        target_pitch = float(np.clip(target_pitch, 55.0, 1400.0))
        anchored_pitch = float(phoneme.voice_pitch + (target_pitch - phoneme.voice_pitch) * strength)
        return replace(phoneme, voice_pitch=anchored_pitch)

    def _render_articulation_word_singing_preview(self) -> np.ndarray:
        self._ensure_default_note_event()
        starts = self._chain_item_start_times_ms()
        original_items = self.articulation_chain_items
        adjusted_items: List[ArticulationChainItem] = []
        for item, start_ms in zip(original_items, starts):
            adjusted_items.append(replace(item, phoneme=self._phoneme_with_singing_pitch(item, start_ms)))
        self.articulation_chain_items = adjusted_items
        try:
            return self._render_articulation_word_clip_crossfade()
        finally:
            self.articulation_chain_items = original_items

    def _render_articulation_word_plain(self) -> np.ndarray:
        word = np.zeros((0, 2), dtype=np.float32)
        print(f"[WaveToy Word] word render started • mode {ARTICULATION_WORD_RENDER_PLAIN} • phoneme count {len(self.articulation_chain_items)}")
        for index, item in enumerate(self.articulation_chain_items):
            clip = self._apply_chain_item_accentuation(self._render_articulation_with_source(item.phoneme_for_render()), item)
            if clip.size == 0:
                continue
            word = clip if word.size == 0 else np.vstack([word, clip])
            gap_samples = int(self._word_gap_after_ms(item, index) * SAMPLE_RATE / 1000.0)
            if gap_samples:
                word = np.vstack([word, np.zeros((gap_samples, 2), dtype=np.float32)])
        word = self._fade_word_edges(word)
        word = normalize_audio(word).astype(np.float32)
        print(f"[WaveToy Word] final word duration {len(word) / SAMPLE_RATE:.3f} s")
        self._log_word_render_debug(ARTICULATION_WORD_RENDER_PLAIN, word)
        return word

    def _render_articulation_word_simple(self) -> np.ndarray:
        word = np.zeros((0, 2), dtype=np.float32)
        boundaries: List[int] = []
        print(f"[WaveToy Word] word render started • mode simple crossfade • phoneme count {len(self.articulation_chain_items)}")
        for index, item in enumerate(self.articulation_chain_items):
            clip = self._apply_chain_item_accentuation(self._render_articulation_with_source(item.phoneme_for_render()), item)
            gap_after_ms = self._word_gap_after_ms(item, index)
            if index < len(self.articulation_chain_items) - 1:
                crossfade_ms = self._word_crossfade_ms(int(item.crossfade_ms), item, self.articulation_chain_items[index + 1])
            else:
                crossfade_ms = 0
            word = self._append_word_clip(word, clip, crossfade_ms, gap_after_ms, boundaries)
        word = self._smooth_word_boundaries(word, boundaries)
        word = self._fade_word_edges(word)
        word = normalize_audio(word).astype(np.float32)
        self._diagnose_word_boundaries(word, boundaries)
        print(f"[WaveToy Word] final word duration {len(word) / SAMPLE_RATE:.3f} s")
        self._log_word_render_debug("simple crossfade", word)
        return word

    def _render_interpolated_transition_clip(self, left: ArticulationChainItem, right: ArticulationChainItem, transition_ms: int) -> np.ndarray:
        transition_ms = int(np.clip(transition_ms, 0, 250))
        if transition_ms <= 0:
            return np.zeros((0, 2), dtype=np.float32)
        frame_ms = ARTICULATION_MOTION_FRAME_MS
        frames = max(1, int(math.ceil(transition_ms / frame_ms)))
        frame_samples = max(1, int(frame_ms * SAMPLE_RATE / 1000.0))
        clips: List[np.ndarray] = []
        left_phoneme = left.phoneme_for_render()
        right_phoneme = right.phoneme_for_render()
        model = phoneme_pair_transition_model(left_phoneme, right_phoneme)
        curve = self._chain_transition_curve(left, right)
        for frame in range(frames):
            progress = (frame + 0.5) / frames
            phoneme = interpolate_articulation_phoneme(left_phoneme, right_phoneme, progress, curve, model)
            phoneme.duration_ms = max(80, frame_ms)
            rendered = self._render_articulation_with_source(phoneme)
            if rendered.size:
                accent_db = float(left.accentuation_db) + (float(right.accentuation_db) - float(left.accentuation_db)) * articulation_curve_progress(progress, curve)
                rendered = (rendered * np.float32(self._accentuation_gain_for_db(accent_db))).astype(np.float32)
                start = min(max(0, len(rendered) // 3), max(0, len(rendered) - frame_samples))
                clips.append(rendered[start:start + frame_samples])
        if not clips:
            return np.zeros((0, 2), dtype=np.float32)
        transition = np.vstack(clips).astype(np.float32)
        target_samples = max(1, int(transition_ms * SAMPLE_RATE / 1000.0))
        transition = transition[:target_samples]
        return transition.astype(np.float32)

    def _build_articulation_envelope_timeline(
        self,
        render_phonemes: List[ArticulationPhoneme] | None = None,
        coarticulation_item_diagnostics: Dict[int, Dict[str, object]] | None = None,
        coarticulation_pair_diagnostics: Dict[Tuple[int, int], Dict[str, object]] | None = None,
    ) -> Tuple[List[Dict[str, object]], int, List[Dict[str, object]], List[Dict[str, object]]]:
        """Create the shared hold/transition timeline used by motion and continuous audio."""
        segments: List[Dict[str, object]] = []
        stop_events: List[Dict[str, object]] = []
        burst_events: List[Dict[str, object]] = []
        item_diagnostics = coarticulation_item_diagnostics or {}
        pair_diagnostics = coarticulation_pair_diagnostics or {}
        cursor = 0
        for index, item in enumerate(self.articulation_chain_items):
            phoneme = (render_phonemes[index] if render_phonemes is not None and index < len(render_phonemes) else self._apply_voice_source_to_phoneme(item.phoneme_for_render())).clamped()
            hold_ms = max(1, int(item.duration_ms or phoneme.duration_ms))
            hold_start = cursor
            hold_end = cursor + hold_ms
            hold_segment = {"kind": "hold", "index": index, "start": hold_start, "end": hold_end, "from": phoneme, "to": phoneme, "accentuation_db": float(item.accentuation_db)}
            if index in item_diagnostics:
                hold_segment.update(item_diagnostics[index])
            segments.append(hold_segment)
            if phoneme.phoneme_family == "stop" or phoneme.closure > 0.75:
                stop_params = _stop_burst_parameters(phoneme)
                closure_ms = int(np.clip(hold_ms * (0.18 + phoneme.closure * 0.54), 8, max(9, hold_ms - 1)))
                closure_end = max(hold_start + 1, min(hold_end - 1, hold_start + closure_ms))
                stop_events.append({"index": index, "phoneme": phoneme.name, "start": hold_start, "end": closure_end, "closure": phoneme.closure})
                if stop_params["burst_gain"] > 0.0:
                    burst_ms = int(np.clip(stop_params["burst_ms"], 8, 60))
                    burst_start = max(closure_end, min(hold_end - 1, closure_end))
                    burst_end = min(hold_end, burst_start + burst_ms)
                    burst_events.append({
                        "index": index,
                        "phoneme": phoneme.name,
                        "start": burst_start,
                        "end": burst_end,
                        "strength": phoneme.burst_strength,
                        "gain": stop_params["burst_gain"],
                        "brightness": stop_params["burst_brightness"],
                        "voiced_onset_gain": stop_params["voiced_onset_gain"],
                    })
            cursor = hold_end
            if index < len(self.articulation_chain_items) - 1:
                transition_ms = max(0, int(self._chain_transition_duration_ms(item, self.articulation_chain_items[index + 1])))
                if transition_ms > 0:
                    next_phoneme = (render_phonemes[index + 1] if render_phonemes is not None and index + 1 < len(render_phonemes) else self._apply_voice_source_to_phoneme(self.articulation_chain_items[index + 1].phoneme_for_render())).clamped()
                    model = phoneme_pair_transition_model(phoneme, next_phoneme)
                    explicit_ms = item.transition_to_next_ms
                    curve = self._chain_transition_curve(item, self.articulation_chain_items[index + 1])
                    explicit_curve = item.transition_curve if item.transition_curve != ARTICULATION_DEFAULT_TRANSITION_CURVE else None
                    transition_segment = {"kind": "transition", "index": index, "start": cursor, "end": cursor + transition_ms, "from": phoneme, "to": next_phoneme, "curve": curve, "transition_model_object": model, "accentuation_db": float(item.accentuation_db), "next_accentuation_db": float(self.articulation_chain_items[index + 1].accentuation_db)}
                    transition_segment.update(transition_model_diagnostics(phoneme, next_phoneme, explicit_ms, explicit_curve))
                    if (index, index + 1) in pair_diagnostics:
                        transition_segment.update(pair_diagnostics[(index, index + 1)])
                    segments.append(transition_segment)
                    cursor += transition_ms
        return segments, max(cursor, 1), stop_events, burst_events

    def _envelope_state_at_ms(self, elapsed_ms: float, segments: List[Dict[str, object]]) -> Tuple[ArticulationPhoneme, float, float, float, Dict[str, object]]:
        active = segments[-1]
        for segment in segments:
            if float(segment["start"]) <= elapsed_ms <= float(segment["end"]):
                active = segment
                break
        start = float(active["start"])
        end = max(start + 1.0, float(active["end"]))
        local = float(np.clip((elapsed_ms - start) / (end - start), 0.0, 1.0))
        left = active["from"]
        right = active["to"]
        if active["kind"] == "transition":
            curve = str(active.get("curve", ARTICULATION_DEFAULT_TRANSITION_CURVE))
            model = active.get("transition_model_object")
            model = model if isinstance(model, PhonemePairTransitionModel) else phoneme_pair_transition_model(left, right)
            phoneme = interpolate_articulation_phoneme(left, right, local, curve, model)
            t = articulation_curve_progress(local, curve)
            left_voiced = _articulation_voiced_gain(left)
            right_voiced = _articulation_voiced_gain(right)
            voice_t = float(np.clip(t * model.voicing_blend_weight + (t * t) * (1.0 - model.voicing_blend_weight), 0.0, 1.0))
            air_t = float(np.clip(t * model.airflow_blend_weight + (t * t) * (1.0 - model.airflow_blend_weight), 0.0, 1.0))
            voiced_gain = float(left_voiced + (right_voiced - left_voiced) * voice_t)
            left_noise = float(articulation_synthesis_debug(left).get("noise_gain", 0.0))
            right_noise = float(articulation_synthesis_debug(right).get("noise_gain", 0.0))
            noise_gain = float(left_noise + (right_noise - left_noise) * air_t)
            if model.frication_hold > 0.0:
                noise_gain = max(noise_gain, left_noise * model.frication_hold * (1.0 - t))
        else:
            phoneme, diphthong_diagnostics = apply_diphthong_transition_shape(left, local)
            if diphthong_diagnostics:
                active = {**active, **diphthong_diagnostics}
            voiced_gain = _articulation_voiced_gain(phoneme)
            noise_gain = float(articulation_synthesis_debug(phoneme).get("noise_gain", 0.0))
        closure = float(np.clip(phoneme.closure, 0.0, 1.0))
        return phoneme, float(np.clip(voiced_gain, 0.0, 1.0)), float(np.clip(noise_gain, 0.0, 1.8)), closure, active

    def _continuous_formant_intensity(self) -> float:
        if bool(self.articulation_word_render_settings.get("continuous_debug_bypass_formants", False)):
            return 0.0
        return float(np.clip(float(self.articulation_word_render_settings.get("continuous_formant_intensity", 0.45)), 0.0, 1.0))

    def _shape_continuous_frame(self, mono: np.ndarray, phoneme: ArticulationPhoneme) -> np.ndarray:
        """Apply subtle tract coloration without moving the excitation pitch."""
        intensity = self._continuous_formant_intensity()
        if mono.size <= 4 or intensity <= 0.0:
            return mono
        spectrum = np.fft.rfft(mono)
        freqs = np.fft.rfftfreq(mono.size, 1.0 / SAMPLE_RATE)
        formants = self._formant_metrics_for_phoneme(phoneme)
        f1, f2, f3 = formants["f1"], formants["f2"], formants["f3"]
        target = np.ones_like(freqs, dtype=np.float64)
        for center, width, gain in ((f1, 220.0, 0.16), (f2, 420.0, 0.11), (f3, 680.0, 0.06)):
            target += gain * np.exp(-0.5 * ((freqs - center) / width) ** 2)
        if phoneme.nasal_open > 0.0:
            nasal = float(np.clip(max(phoneme.nasal_open, formants.get("nasal_coupling", 0.0) * 0.75), 0.0, 1.0))
            nasal_center = 260.0 + (1.0 - phoneme.tongue_frontness) * 180.0
            target += nasal * 0.08 * np.exp(-0.5 * ((freqs - nasal_center) / 220.0) ** 2)
            target *= 1.0 / (1.0 + nasal * 0.12 * (freqs / 3200.0) ** 2)
        target *= 1.0 - 0.05 * phoneme.lip_rounding * np.clip((freqs - 2000.0) / 5600.0, 0.0, 1.0)
        resonance_safety = float(np.clip(1.0 - abs(formants.get("resonance_formant_scale", 1.0) - 1.0) * 0.45, 0.82, 1.0))
        envelope = 1.0 + (np.clip(target, 0.74, 1.08) - 1.0) * intensity * resonance_safety
        shaped = np.fft.irfft(spectrum * envelope, n=mono.size)
        input_rms = float(np.sqrt(np.mean(np.square(mono)))) if mono.size else 0.0
        shaped_rms = float(np.sqrt(np.mean(np.square(shaped)))) if shaped.size else 0.0
        if input_rms > 1.0e-8 and shaped_rms > 1.0e-8:
            shaped *= float(np.clip(input_rms / shaped_rms, 0.92, 1.04))
        return shaped

    def _estimate_continuous_pitch_hz(self, mono: np.ndarray, intended_pitch_hz: float) -> float:
        if mono.size < int(0.035 * SAMPLE_RATE) or intended_pitch_hz <= 0.0:
            return 0.0
        centered = mono.astype(np.float64) - float(np.mean(mono))
        rms = float(np.sqrt(np.mean(np.square(centered))))
        if rms <= 1.0e-5:
            return 0.0
        min_lag = max(1, int(SAMPLE_RATE / min(880.0, max(120.0, intended_pitch_hz * 1.65))))
        max_lag = min(len(centered) - 1, int(SAMPLE_RATE / max(60.0, intended_pitch_hz * 0.55)))
        if max_lag <= min_lag:
            return 0.0
        window = centered * np.hanning(len(centered))
        correlations = np.array([float(np.dot(window[:-lag], window[lag:])) for lag in range(min_lag, max_lag + 1)], dtype=np.float64)
        if correlations.size == 0 or float(np.max(correlations)) <= 1.0e-9:
            return 0.0
        lag = min_lag + int(np.argmax(correlations))
        return float(SAMPLE_RATE / lag)

    def _continuous_pitch_debug_frames(self, mono: np.ndarray, frame_debug: List[Dict[str, object]], frame_samples: int) -> List[Dict[str, object]]:
        """Compare intended vs estimated pitch in coarse voiced windows for the waveform editor."""
        frames: List[Dict[str, object]] = []
        if mono.size == 0 or not frame_debug:
            return frames
        window = max(int(0.040 * SAMPLE_RATE), frame_samples * 3)
        stride = max(1, len(frame_debug) // 80)
        for item in frame_debug[::stride]:
            intended = float(item.get("intended_pitch_hz", 0.0) or 0.0)
            voiced_gain = float(item.get("voiced_gain", 0.0) or 0.0)
            if intended <= 0.0 or voiced_gain <= 0.05:
                continue
            center = int(item.get("frame_index", 0) or 0) * frame_samples + frame_samples // 2
            start = max(0, center - window // 2)
            end = min(len(mono), start + window)
            if end - start < max(64, window // 3):
                continue
            estimated = self._estimate_continuous_pitch_hz(mono[start:end], intended)
            error = abs((estimated - intended) / intended * 100.0) if estimated > 0.0 else 0.0
            frames.append({
                "frame_index": int(item.get("frame_index", 0) or 0),
                "start_sample": start,
                "end_sample": end,
                "center_sample": center,
                "intended_pitch_hz": round(intended, 3),
                "measured_pitch_estimate_hz": round(estimated, 3),
                "pitch_error_percent": round(error, 3),
                "active_phoneme": item.get("active_phoneme", ""),
            })
        return frames[:120]

    def _continuous_waveform_overlay_regions(
        self,
        mono: np.ndarray,
        segments: List[Dict[str, object]],
        burst_events: List[Dict[str, object]],
        pitch_frames: List[Dict[str, object]],
        stop_debug_events: List[Dict[str, object]],
    ) -> List[Dict[str, object]]:
        """Build optional waveform-editor regions without changing audio playback."""
        regions: List[Dict[str, object]] = []
        for segment in segments:
            start_ms = float(segment.get("start", 0.0) or 0.0)
            end_ms = float(segment.get("end", start_ms) or start_ms)
            if segment.get("kind") == "transition":
                left = segment.get("from")
                right = segment.get("to")
                label = f"transition {getattr(left, 'name', '?')}→{getattr(right, 'name', '?')}"
                regions.append({"kind": "transition", "start_ms": start_ms, "end_ms": end_ms, "label": "transition", "tooltip": f"Continuous transition window: {label}; curve {segment.get('curve')}"})
            elif "diphthong_start_vowel" in segment or diphthong_profile_for_symbol(getattr(segment.get("from"), "name", "")):
                left = str(segment.get("diphthong_start_vowel") or "start")
                right = str(segment.get("diphthong_end_vowel") or "end")
                regions.append({"kind": "diphthong_glide", "start_ms": start_ms, "end_ms": end_ms, "label": f"{left}→{right}", "tooltip": f"Diphthong glide region: {left} to {right}; one timeline item is preserved."})
            phoneme = segment.get("from")
            if isinstance(phoneme, ArticulationPhoneme) and self._continuous_formant_intensity() > 0.0:
                formants = self._formant_metrics_for_phoneme(phoneme)
                regions.append({
                    "kind": "formant_processing", "start_ms": start_ms, "end_ms": end_ms, "label": "F1/F2/F3",
                    "tooltip": f"Formant region {phoneme.name}: base F1/F2/F3 {formants['base_f1']:.0f}/{formants['base_f2']:.0f}/{formants['base_f3']:.0f} Hz → resonance {formants['f1']:.0f}/{formants['f2']:.0f}/{formants['f3']:.0f} Hz.",
                })
        debug_by_name: Dict[str, Dict[str, object]] = {str(e.get("stop_name")): e for e in stop_debug_events}
        for event in burst_events:
            name = str(event.get("phoneme", "stop"))
            details = debug_by_name.get(name, {})
            regions.append({
                "kind": "stop_burst", "start_ms": float(event.get("start", 0.0) or 0.0), "end_ms": float(event.get("end", 0.0) or 0.0),
                "label": f"burst {name}",
                "tooltip": f"Stop burst {name}: burst_peak={details.get('burst_peak', 0.0)}, burst_rms={details.get('burst_rms', 0.0)}, burst_duration_ms={details.get('burst_duration_ms', 0.0)}, burst_status={'present' if float(details.get('burst_peak', 0.0) or 0.0) > 0.003 else 'low'}.",
            })
        if mono.size:
            clipped = np.flatnonzero(np.abs(mono) >= 0.985)
            if clipped.size:
                groups = np.split(clipped, np.where(np.diff(clipped) > max(1, int(0.002 * SAMPLE_RATE)))[0] + 1)
                for group in groups[:24]:
                    regions.append({"kind": "clipping", "start_sample": int(group[0]), "end_sample": int(group[-1] + 1), "label": "clip", "tooltip": f"High-peak/clipping risk: {len(group)} samples near full scale."})
            peak_window = max(1, int(0.012 * SAMPLE_RATE))
            if len(mono) > peak_window:
                for start in range(0, len(mono), peak_window):
                    chunk = mono[start:start + peak_window]
                    if chunk.size and float(np.max(np.abs(chunk))) >= 0.90:
                        regions.append({"kind": "clipping", "start_sample": start, "end_sample": min(len(mono), start + peak_window), "label": "peak", "tooltip": f"High peak region: peak={float(np.max(np.abs(chunk))):.3f}; safer limiter protects against harsh clipping."})
        for frame in pitch_frames:
            if float(frame.get("pitch_error_percent", 0.0) or 0.0) > 8.0:
                regions.append({"kind": "pitch_instability", "start_sample": int(frame.get("start_sample", 0) or 0), "end_sample": int(frame.get("end_sample", 0) or 0), "label": "pitch", "tooltip": f"Pitch instability: intended {frame.get('intended_pitch_hz')} Hz vs estimated {frame.get('measured_pitch_estimate_hz')} Hz ({frame.get('pitch_error_percent')}% error)."})
        return regions[:220]

    def _continuous_soft_limit(self, mono: np.ndarray, target_peak: float = 0.86) -> np.ndarray:
        if mono.size == 0:
            return mono
        peak = float(np.max(np.abs(mono)))
        if peak <= target_peak or peak <= 1.0e-8:
            return mono
        knee = target_peak * 0.72
        sign = np.sign(mono)
        abs_mono = np.abs(mono)
        limited_abs = abs_mono.copy()
        over = abs_mono > knee
        if np.any(over):
            span = max(1.0e-9, peak - knee)
            amount = (abs_mono[over] - knee) / span
            limited_abs[over] = knee + (target_peak - knee) * np.tanh(amount * 1.55) / np.tanh(1.55)
        limited = sign * limited_abs
        limited_peak = float(np.max(np.abs(limited))) if limited.size else 0.0
        if limited_peak > target_peak and limited_peak > 1.0e-8:
            limited = limited / limited_peak * target_peak
        return limited

    def _continuous_voiced_gain(self, phoneme: ArticulationPhoneme) -> float:
        voiced_gain = _articulation_voiced_gain(phoneme)
        if voiced_gain > 0.0:
            return voiced_gain
        profile = str(self.articulation_word_render_settings.get("voice_profile", "Neutral"))
        naturally_voiced = phoneme.phoneme_family in {"vowel", "nasal", "liquid", "glide"} or phoneme.name.upper() in {"B", "D", "G", "JH", "V", "Z", "ZH", "DH"}
        if profile == "Whisper":
            if naturally_voiced and phoneme.voice_strength > 0.0:
                return float(np.clip(phoneme.voice_strength * 0.22, 0.025, 0.16))
            return 0.0
        if naturally_voiced and phoneme.voice_strength > 0.0:
            return float(np.clip(phoneme.voice_strength, 0.0, 1.0))
        return 0.0

    def _continuous_status_for_metrics(self, metrics: Dict[str, object]) -> Tuple[str, str]:
        if metrics.get("exception"):
            return "EXCEPTION", "#b00020"
        output_peak = float(metrics.get("output_peak", 0.0) or 0.0)
        final_buffer_length = int(metrics.get("final_buffer_length", 0) or 0)
        voiced_rms = float(metrics.get("voiced_rms", 0.0) or 0.0)
        voiced_phoneme_count = int(metrics.get("voiced_phoneme_count", 0) or 0)
        clipped_count = int(metrics.get("clipped_sample_count", metrics.get("clipped_samples", 0)) or 0)
        pitch_error = abs(float(metrics.get("pitch_error_percent", metrics.get("pitch_error", 0.0)) or 0.0))
        crest_factor = float(metrics.get("crest_factor", 0.0) or 0.0)
        dc_offset = abs(float(metrics.get("dc_offset", 0.0) or 0.0))
        if final_buffer_length == 0:
            return "SILENT", "#b00020"
        if output_peak <= 0.000001:
            return "SILENT", "#b00020"
        if output_peak <= 0.001:
            return "LOW_OUTPUT", "#b36b00"
        if clipped_count > max(4, int(final_buffer_length * 0.0002)):
            return "CLIPPING", "#b00020"
        if voiced_phoneme_count > 0 and voiced_rms <= 0.000001:
            return "LOW_OUTPUT", "#b36b00"
        if int(metrics.get("burst_event_count", 0) or 0) > 0 and float(metrics.get("burst_peak", 0.0) or 0.0) <= 0.003:
            return "LOW_OUTPUT", "#b36b00"
        if pitch_error > 8.0:
            return "PITCH_UNSTABLE", "#b00020"
        if dc_offset > 0.035 or (crest_factor > 0.0 and crest_factor < 2.2 and output_peak > 0.35):
            return "DISTORTED", "#b00020"
        return "PASS_AUDIO_PRESENT", "#0b7a2a"

    def _toggle_continuous_waveform_overlays(self, visible: bool) -> None:
        if self.articulation_waveform_diagnostics_canvas is not None:
            self.articulation_waveform_diagnostics_canvas.set_overlays_visible(bool(visible))

    def _update_articulation_waveform_diagnostics_canvas(self) -> None:
        if self.articulation_waveform_diagnostics_canvas is None:
            return
        self.articulation_waveform_diagnostics_canvas.set_render(
            self.articulation_word_render_audio,
            self.continuous_diagnostics_latest if self._articulation_word_render_mode() == ARTICULATION_WORD_RENDER_CONTINUOUS else {"active_render_mode": self._articulation_word_render_mode()},
        )
        track = self._selected_timeline_track() if hasattr(self, "performance_timeline_engine") else None
        points = [
            {"time_ms": point.time_ms, "value": point.value, "color": track.color}
            for point in (track.points if track is not None else [])
        ]
        playhead_ms = self.performance_timeline_engine.playhead_ms if hasattr(self, "performance_timeline_engine") else 0.0
        self.articulation_waveform_diagnostics_canvas.set_performance_overlay(points, track.name if track is not None else "", playhead_ms)

