    def _validate_continuous_render_chains(self, checked: bool = False) -> None:
        del checked
        saved_items = [ArticulationChainItem.from_json_dict(item.to_json_dict()) for item in self.articulation_chain_items]
        saved_selected = self.articulation_selected_chain_index
        saved_settings = dict(self.articulation_word_render_settings)
        saved_mode = self._articulation_word_render_mode()
        saved_audio = self.articulation_word_render_audio.copy()
        saved_signature = self.articulation_word_render_signature
        saved_path = self.articulation_last_word_render_path
        saved_created = self.articulation_last_word_render_created_at
        rows: List[Dict[str, object]] = []
        print("[WaveToy Continuous Validation] starting built-in test chains")
        try:
            self.articulation_word_render_settings["word_render_mode"] = ARTICULATION_WORD_RENDER_CONTINUOUS
            if self.articulation_word_render_mode_combo is not None:
                self.articulation_word_render_mode_combo.blockSignals(True)
                self.articulation_word_render_mode_combo.setCurrentText(ARTICULATION_WORD_RENDER_CONTINUOUS)
                self.articulation_word_render_mode_combo.blockSignals(False)
            for chain in CONTINUOUS_RENDER_TEST_CHAINS:
                label = " ".join(chain)
                self.articulation_chain_items = [
                    ArticulationChainItem(phoneme=_phoneme_from_preset_symbol(symbol), duration_ms=_phoneme_from_preset_symbol(symbol).duration_ms)
                    for symbol in chain
                ]
                if chain == ("M", "OO", "N") and len(self.articulation_chain_items) > 1:
                    self.articulation_chain_items[1].accentuation_db = 3.0
                    label = f"{label} (+3 dB OO accent)"
                print(f"[WaveToy Continuous Validation] render chain={label}")
                audio = self._render_articulation_word_continuous()
                metrics = dict(self.continuous_diagnostics_latest or {})
                status = str(metrics.get("status") or self._continuous_status_for_metrics(metrics)[0])
                notes = []
                if float(metrics.get("voiced_rms", 0.0) or 0.0) <= 0.000001 and int(metrics.get("voiced_phoneme_count", 0) or 0) > 0:
                    notes.append("voicing absent")
                if float(metrics.get("noise_rms", 0.0) or 0.0) <= 0.000001:
                    notes.append("noise low")
                if float(metrics.get("output_duration", 0.0) or 0.0) <= 0.0:
                    notes.append("duration absent")
                if int(metrics.get("burst_event_count", 0) or 0) > 0 and float(metrics.get("burst_peak", 0.0) or 0.0) <= 0.003:
                    notes.append("stop burst low")
                row = {
                    "chain_label": label,
                    "rendered_duration": round(len(audio) / SAMPLE_RATE, 4) if audio.size else 0.0,
                    "output_peak": metrics.get("output_peak", 0.0),
                    "voiced_rms": metrics.get("voiced_rms", 0.0),
                    "noise_rms": metrics.get("noise_rms", 0.0),
                    "burst_peak": metrics.get("burst_peak", 0.0),
                    "pitch_error": metrics.get("pitch_error", 0.0),
                    "clipped_samples": metrics.get("clipped_samples", 0),
                    "result": status,
                    "notes": ", ".join(notes) if notes else "ok",
                }
                rows.append(row)
                print(f"[WaveToy Continuous Validation] result {row}")
        except Exception as exc:
            rows.append({"chain_label": "validation", "rendered_duration": 0.0, "output_peak": 0.0, "pitch_error": 0.0, "clipped_samples": 0, "burst_peak": 0.0, "voiced_rms": 0.0, "noise_rms": 0.0, "result": "EXCEPTION", "notes": str(exc)})
            self._report_continuous_render_debug({
                "active_render_mode": ARTICULATION_WORD_RENDER_CONTINUOUS,
                "chain_length": len(self.articulation_chain_items),
                "phoneme_count": len(self.articulation_chain_items),
                "output_duration": 0.0,
                "output_peak": 0.0,
                "voiced_rms": 0.0,
                "noise_rms": 0.0,
                "source_rms": 0.0,
                "burst_peak": 0.0,
                "burst_rms": 0.0,
                "burst_event_count": 0,
                "stop_burst_status": "none",
                "transition_count": 0,
                "transition_duration_total": 0,
                "final_buffer_length": 0,
                "voiced_phoneme_count": 0,
                "exception": str(exc),
            })
            print(f"[WaveToy Continuous Validation] exception {exc}")
        finally:
            self.articulation_chain_items = saved_items
            self.articulation_selected_chain_index = saved_selected
            self.articulation_word_render_settings = saved_settings
            if self.articulation_word_render_mode_combo is not None:
                self.articulation_word_render_mode_combo.blockSignals(True)
                self.articulation_word_render_mode_combo.setCurrentText(saved_mode)
                self.articulation_word_render_mode_combo.blockSignals(False)
            if self.continuous_debug_bypass_formants_checkbox is not None:
                self.continuous_debug_bypass_formants_checkbox.blockSignals(True)
                self.continuous_debug_bypass_formants_checkbox.setChecked(bool(saved_settings.get("continuous_debug_bypass_formants", False)))
                self.continuous_debug_bypass_formants_checkbox.blockSignals(False)
            if self.continuous_formant_intensity_spin is not None:
                self.continuous_formant_intensity_spin.blockSignals(True)
                self.continuous_formant_intensity_spin.setValue(float(saved_settings.get("continuous_formant_intensity", 0.45)))
                self.continuous_formant_intensity_spin.blockSignals(False)
            if self.continuous_pitch_smoothing_spin is not None:
                self.continuous_pitch_smoothing_spin.blockSignals(True)
                self.continuous_pitch_smoothing_spin.setValue(int(saved_settings.get("continuous_pitch_smoothing_ms", 20)))
                self.continuous_pitch_smoothing_spin.blockSignals(False)
            self.articulation_word_render_audio = saved_audio
            self.articulation_word_render_signature = saved_signature
            self.articulation_last_word_render_path = saved_path
            self.articulation_last_word_render_created_at = saved_created
            self._refresh_articulation_chain_cards()
            self._refresh_articulation_motion_timeline()
            self._update_articulation_word_status()
        lines = ["chain        duration  peak     pitch err  clipped  burst    voiced   noise    status              notes"]
        for row in rows:
            lines.append(
                f"{str(row['chain_label']):<12} {row['rendered_duration']!s:<8} {row['output_peak']!s:<8} "
                f"{row.get('pitch_error', 0.0)!s:<10} {row.get('clipped_samples', 0)!s:<8} {row.get('burst_peak', 0.0)!s:<8} "
                f"{row['voiced_rms']!s:<8} {row['noise_rms']!s:<8} {row['result']:<19} {row['notes']}"
            )
        if self.continuous_validation_results_label is not None:
            self.continuous_validation_results_label.setText("Validation results:\n" + "\n".join(lines))

    def _render_articulation_word_continuous(self) -> np.ndarray:
        base_render_phonemes = [self._apply_voice_source_to_phoneme(item.phoneme_for_render()).clamped() for item in self.articulation_chain_items]
        voice_source_applied_counts = [1 for _item in self.articulation_chain_items]
        render_phonemes, coarticulation_item_diagnostics, coarticulation_pair_diagnostics = apply_neighbor_coarticulation(base_render_phonemes)
        segments, total_ms, stop_events, burst_events = self._build_articulation_envelope_timeline(render_phonemes, coarticulation_item_diagnostics, coarticulation_pair_diagnostics)
        frame_ms = ARTICULATION_MOTION_FRAME_MS
        frame_samples = max(1, int(round(frame_ms * SAMPLE_RATE / 1000.0)))
        total_samples = max(1, int(round(total_ms * SAMPLE_RATE / 1000.0)))
        frame_count = max(1, int(math.ceil(total_samples / frame_samples)))
        transition_count = sum(1 for segment in segments if segment["kind"] == "transition")
        transition_duration_total = sum(int(segment["end"]) - int(segment["start"]) for segment in segments if segment["kind"] == "transition")
        voiced_phoneme_count = sum(1 for phoneme in render_phonemes if self._continuous_voiced_gain(phoneme) > 0.0)
        initial_voiced = [phoneme for phoneme in render_phonemes if self._continuous_voiced_gain(phoneme) > 0.0]
        last_voiced_pitch = float(np.clip(initial_voiced[0].voice_pitch if initial_voiced else 220.0, 60.0, 880.0))
        print(f"[WaveToy Envelope] render mode={ARTICULATION_WORD_RENDER_CONTINUOUS} phoneme_count={len(self.articulation_chain_items)} total_envelope_ms={total_ms} frame_count={frame_count}")
        for segment in segments:
            if segment["kind"] == "transition":
                print(
                    f"[WaveToy Envelope] transition {segment['from'].name}->{segment['to'].name} "
                    f"start_ms={segment['start']} end_ms={segment['end']} duration_ms={int(segment['end']) - int(segment['start'])} "
                    f"model={segment.get('transition_model_id')} strength={segment.get('transition_strength')}"
                )
        for event in stop_events:
            print(f"[WaveToy Envelope] stop event phoneme={event['phoneme']} start_ms={event['start']} end_ms={event['end']} closure={event['closure']:.2f}")
        for event in burst_events:
            print(
                f"[WaveToy Envelope] burst event phoneme={event['phoneme']} start_ms={event['start']} "
                f"end_ms={event['end']} strength={event['strength']:.2f} "
                f"gain={float(event.get('gain', 0.0)):.3f} brightness={float(event.get('brightness', 0.0)):.3f}"
            )

        rng = np.random.default_rng(33033)
        mono = np.zeros(total_samples, dtype=np.float64)
        voiced_trace = np.zeros(total_samples, dtype=np.float32)
        noise_trace = np.zeros(total_samples, dtype=np.float32)
        closure_trace = np.zeros(total_samples, dtype=np.float32)
        voiced_bus = np.zeros(total_samples, dtype=np.float64)
        noise_bus = np.zeros(total_samples, dtype=np.float64)
        source_bus = np.zeros(total_samples, dtype=np.float64)
        burst_bus = np.zeros(total_samples, dtype=np.float64)
        final_mix_bus = np.zeros(total_samples, dtype=np.float64)
        frame_debug: List[Dict[str, object]] = []
        source_cache: Dict[int, np.ndarray | None] = {}
        for index, item in enumerate(self.articulation_chain_items):
            phoneme = render_phonemes[index].clamped()
            if phoneme.source_mode == ARTICULATION_SOURCE_DEFAULT:
                source_cache[index] = None
                continue
            source_audio = self._resolve_articulation_source_audio(phoneme)
            if source_audio is None:
                source_cache[index] = None
                continue
            source_cache[index] = prepare_articulation_source_audio(source_audio, phoneme, max(0.08, item.duration_ms / 1000.0))
        phase = 0.0
        previous_tail = 0.0
        smoothed_pitch_hz = last_voiced_pitch
        pitch_smoothing_ms = float(np.clip(float(self.articulation_word_render_settings.get("continuous_pitch_smoothing_ms", 20)), 0.0, 120.0))
        pitch_alpha = 1.0 if pitch_smoothing_ms <= 0.0 else float(np.clip(frame_ms / max(frame_ms, pitch_smoothing_ms), 0.02, 1.0))
        formant_input_energy = 0.0
        formant_output_energy = 0.0
        formant_sample_count = 0
        transition_progress = 0.0
        diphthong_debug_frames: List[Dict[str, object]] = []
        stop_debug_events: List[Dict[str, object]] = []
        for frame_index in range(frame_count):
            start_sample = frame_index * frame_samples
            end_sample = min(total_samples, start_sample + frame_samples)
            count = end_sample - start_sample
            if count <= 0:
                continue
            center_ms = ((start_sample + end_sample) * 0.5) * 1000.0 / SAMPLE_RATE
            phoneme, voiced_gain, noise_gain, closure, active = self._envelope_state_at_ms(center_ms, segments)
            voiced_gain = self._continuous_voiced_gain(phoneme)
            if voiced_gain > 0.0:
                if active.get("kind") == "transition":
                    left = active.get("from")
                    right = active.get("to")
                    start_ms = float(active.get("start", 0.0))
                    end_ms = float(active.get("end", start_ms + 1.0))
                    local = float(np.clip((center_ms - start_ms) / max(1.0, end_ms - start_ms), 0.0, 1.0))
                    curve = str(active.get("curve", ARTICULATION_DEFAULT_TRANSITION_CURVE))
                    pitch_t = articulation_curve_progress(local, curve)
                    transition_progress = pitch_t
                    left_voiced = isinstance(left, ArticulationPhoneme) and self._continuous_voiced_gain(left.clamped()) > 0.0
                    right_voiced = isinstance(right, ArticulationPhoneme) and self._continuous_voiced_gain(right.clamped()) > 0.0
                    left_pitch = float(np.clip(left.voice_pitch, 60.0, 880.0)) if left_voiced else last_voiced_pitch
                    right_pitch = float(np.clip(right.voice_pitch, 60.0, 880.0)) if right_voiced else left_pitch
                    last_voiced_pitch = float(left_pitch + (right_pitch - left_pitch) * pitch_t)
                else:
                    last_voiced_pitch = float(np.clip(phoneme.voice_pitch, 60.0, 880.0))
                    transition_progress = float(active.get("diphthong_progress", 0.0) or 0.0)
            smoothed_pitch_hz += (last_voiced_pitch - smoothed_pitch_hz) * pitch_alpha
            intended_pitch_hz = smoothed_pitch_hz
            source_excitation = np.zeros(count, dtype=np.float64)
            source_audio = source_cache.get(int(active.get("index", 0)))
            if source_audio is not None and source_audio.size:
                local_start_sample = max(0, int(round((center_ms - float(active.get("start", 0.0))) * SAMPLE_RATE / 1000.0)) - count // 2)
                local_end_sample = local_start_sample + count
                source_slice = source_audio[local_start_sample:local_end_sample]
                if len(source_slice) < count:
                    source_slice = np.vstack([source_slice, np.zeros((count - len(source_slice), 2), dtype=np.float32)])
                source_excitation = source_slice[:count].mean(axis=1).astype(np.float64)
                source_peak = float(np.max(np.abs(source_excitation))) if source_excitation.size else 0.0
                if source_peak > 1.0e-8:
                    source_excitation = source_excitation / source_peak
                source_bus[start_sample:end_sample] = source_excitation[:count]
            phase_step = 2.0 * math.pi * intended_pitch_hz / SAMPLE_RATE
            phases = phase + phase_step * np.arange(count, dtype=np.float64)
            phase = float((phases[-1] + phase_step) % (2.0 * math.pi))
            voice_strength = float(np.clip(phoneme.voice_strength, 0.0, 1.0))
            harmonic = np.sin(phases) + 0.18 * np.sin(phases * 2.0) + 0.07 * np.sin(phases * 3.0)
            tone = harmonic * voiced_gain * 0.46
            source_tone = source_excitation * voiced_gain * (0.16 + 0.24 * voice_strength)
            raw_noise = rng.normal(0.0, 1.0, count)
            brightness = float(np.clip((phoneme.noise_color + phoneme.tongue_frontness + (1.0 - phoneme.lip_rounding)) / 3.0, 0.0, 1.0))
            diff_noise = np.concatenate([[previous_tail], raw_noise[:-1]])
            previous_tail = float(raw_noise[-1])
            noise = raw_noise * (0.50 - 0.30 * brightness) + (raw_noise - diff_noise) * (0.18 + 0.34 * brightness)
            if phoneme.phoneme_family == "stop":
                stop_params = _stop_burst_parameters(phoneme)
                noise *= noise_gain * (0.025 + 0.12 * stop_params["air_pressure"]) * (0.25 + 0.75 * (1.0 - stop_params["teeth_gap"]))
                closure_gate = float(np.clip(1.0 - closure * 0.97, 0.02, 1.0))
                voice_gate = float(np.clip(1.0 - closure * 0.78, 0.08, 1.0)) if voiced_gain > 0.0 else closure_gate
                voiced_component = (tone + source_tone * 0.50) * voice_gate
                noise_component = noise * 0.075 * closure_gate
            else:
                noise *= noise_gain * (0.12 + 0.64 * phoneme.air_pressure) * (0.24 + 0.56 * phoneme.teeth_gap)
                closure_gate = float(np.clip(1.0 - closure * 0.94, 0.04, 1.0))
                voiced_noise_duck = float(np.clip(1.0 - voiced_gain * 0.72, 0.22, 1.0))
                voiced_component = (tone * (0.92 + 0.20 * voice_strength) + source_tone) * closure_gate
                noise_component = noise * 0.16 * voiced_noise_duck * closure_gate
            dry_frame = voiced_component + noise_component
            frame = self._shape_continuous_frame(dry_frame, phoneme)
            if active.get("kind") == "transition":
                curve = str(active.get("curve", ARTICULATION_DEFAULT_TRANSITION_CURVE))
                start_ms = float(active.get("start", 0.0))
                end_ms = float(active.get("end", start_ms + 1.0))
                local = float(np.clip((center_ms - start_ms) / max(1.0, end_ms - start_ms), 0.0, 1.0))
                accent_t = articulation_curve_progress(local, curve)
                accent_db = float(active.get("accentuation_db", 0.0)) + (float(active.get("next_accentuation_db", active.get("accentuation_db", 0.0))) - float(active.get("accentuation_db", 0.0))) * accent_t
            else:
                accent_db = float(active.get("accentuation_db", 0.0))
            gain_applied = self._accentuation_gain_for_db(accent_db)
            frame = frame * gain_applied
            formant_input_energy += float(np.sum(np.square(dry_frame)))
            formant_output_energy += float(np.sum(np.square(frame)))
            formant_sample_count += int(dry_frame.size)
            voiced_bus[start_sample:end_sample] += voiced_component
            noise_bus[start_sample:end_sample] += noise_component
            mono[start_sample:end_sample] += frame
            voiced_trace[start_sample:end_sample] = voiced_gain
            noise_trace[start_sample:end_sample] = noise_gain
            closure_trace[start_sample:end_sample] = closure
            diphthong_frame = {key: active.get(key) for key in ("diphthong_profile", "glide_start_percent", "diphthong_start_vowel", "diphthong_end_vowel", "diphthong_progress", "diphthong_interpolation_curve") if key in active}
            if diphthong_frame:
                diphthong_frame["frame_index"] = frame_index
                diphthong_frame["active_phoneme"] = phoneme.name
                diphthong_debug_frames.append(diphthong_frame)
            coarticulation_frame = {key: active.get(key) for key in ("coarticulation_pair", "coarticulation_strength", "coarticulation_type", "anticipatory_tongue_shift", "carryover_closure", "lip_rounding_carryover", "nasal_carryover", "voicing_carryover") if key in active}
            transition_model_frame = {key: active.get(key) for key in ("transition_model", "transition_model_id", "transition_strength", "transition_model_duration_reason", "transition_model_curve_reason") if key in active}
            frame_debug.append({
                "frame_index": frame_index,
                "active_phoneme": phoneme.name,
                "voice_source_applied_count": int(voice_source_applied_counts[int(active.get("index", 0))]) if voice_source_applied_counts else 0,
                "intended_pitch_hz": round(intended_pitch_hz, 3),
                "measured_pitch_estimate_hz": 0.0,
                "pitch_error_percent": 0.0,
                "transition_progress": round(transition_progress, 3),
                "voiced_gain": round(voiced_gain, 3),
                "active_phoneme_accentuation_db": round(accent_db, 3),
                "gain_applied": round(gain_applied, 6),
                **diphthong_frame,
                **coarticulation_frame,
                **transition_model_frame,
            })

        smooth_samples = max(3, int(0.0015 * SAMPLE_RATE))
        if smooth_samples % 2 == 0:
            smooth_samples += 1
        smoothing_region_count = 0
        if len(mono) > smooth_samples:
            transition_mask = np.zeros(len(mono), dtype=np.float64)
            edge_margin = max(1, smooth_samples // 2)
            for segment in segments:
                if segment.get("kind") != "transition":
                    continue
                start_sample = max(0, int(round(float(segment["start"]) * SAMPLE_RATE / 1000.0)) - edge_margin)
                end_sample = min(len(mono), int(round(float(segment["end"]) * SAMPLE_RATE / 1000.0)) + edge_margin)
                if end_sample > start_sample:
                    transition_mask[start_sample:end_sample] = 1.0
                    smoothing_region_count += 1
            if np.any(transition_mask > 0.0):
                kernel = np.hanning(smooth_samples)
                kernel = kernel / max(1.0e-9, float(np.sum(kernel)))
                smoothed_mono = np.convolve(mono, kernel, mode="same")
                mask_kernel = np.hanning(max(3, smooth_samples * 2 + 1))
                mask_kernel = mask_kernel / max(1.0e-9, float(np.max(mask_kernel)))
                transition_mask = np.convolve(transition_mask, mask_kernel, mode="same")
                transition_mask = np.clip(transition_mask, 0.0, 1.0) * 0.12
                mono = mono * (1.0 - transition_mask) + smoothed_mono * transition_mask

        for event in burst_events:
            start_sample = int(round(float(event["start"]) * SAMPLE_RATE / 1000.0))
            end_sample = min(total_samples, int(round(float(event["end"]) * SAMPLE_RATE / 1000.0)))
            if end_sample <= start_sample:
                continue
            phoneme = render_phonemes[int(event["index"])].clamped()
            count = end_sample - start_sample
            params = _stop_burst_parameters(phoneme)
            burst = _stop_burst_noise(count, phoneme)
            env = np.exp(-np.linspace(0.0, 5.5, count, dtype=np.float64))
            env *= np.linspace(1.0, 0.18, count, dtype=np.float64)
            gain = float(event.get("gain", params["burst_gain"]))
            _log_stop_render(phoneme, {**params, "burst_samples": float(count), "burst_gain": gain}, count)
            burst_component = burst * env * gain * 0.55
            stop_debug_events.append({
                "stop_name": phoneme.name,
                "closure_duration_ms": round(float(params["closure_samples"]) / SAMPLE_RATE * 1000.0, 3),
                "release_start_ms": round(float(event["start"]), 3),
                "burst_duration_ms": round(count / SAMPLE_RATE * 1000.0, 3),
                "burst_peak": round(float(np.max(np.abs(burst_component))) if burst_component.size else 0.0, 9),
                "burst_rms": round(float(np.sqrt(np.mean(np.square(burst_component)))) if burst_component.size else 0.0, 9),
                "voicing_overlap_ms": round(float(params.get("voiced_onset_gain", 0.0)) * float(params["closure_samples"]) / SAMPLE_RATE * 1000.0, 3),
                "burst_status": "present" if (float(np.max(np.abs(burst_component))) if burst_component.size else 0.0) > 0.003 else "low",
            })
            burst_bus[start_sample:end_sample] += burst_component
            noise_bus[start_sample:end_sample] += burst_component
            mono[start_sample:end_sample] += burst_component

        pre_normalize_peak = float(np.max(np.abs(mono))) if mono.size else 0.0
        clipped_before_limiter = int(np.count_nonzero(np.abs(mono) >= 1.0)) if mono.size else 0
        if pre_normalize_peak > 1.0e-8 and pre_normalize_peak < 0.32:
            mono *= min(1.75, 0.48 / pre_normalize_peak)
        mono = self._continuous_soft_limit(mono, 0.86)
        mono -= float(np.mean(mono)) if mono.size else 0.0
        mono = self._continuous_soft_limit(mono, 0.86)
        post_normalize_peak = float(np.max(np.abs(mono))) if mono.size else 0.0
        final_mix_bus[:] = mono
        audio = np.column_stack([mono, mono]).astype(np.float32) if mono.size else np.zeros((0, 2), dtype=np.float32)
        audio = self._fade_word_edges(audio)
        final_peak = float(np.max(np.abs(audio))) if audio.size else 0.0
        final_mono = audio.mean(axis=1).astype(np.float64) if audio.size else np.zeros(0, dtype=np.float64)
        final_rms = float(np.sqrt(np.mean(np.square(final_mono)))) if final_mono.size else 0.0
        crest_factor = float(final_peak / final_rms) if final_rms > 1.0e-9 else 0.0
        dc_offset = float(np.mean(final_mono)) if final_mono.size else 0.0
        clipped_sample_count = int(np.count_nonzero(np.abs(final_mono) >= 0.999)) + clipped_before_limiter
        voiced_indices = np.flatnonzero(voiced_trace > 0.35)
        measured_pitch = 0.0
        pitch_error = 0.0
        active_phoneme = ""
        diagnostic_frames: List[Dict[str, object]] = []
        if voiced_indices.size and final_mono.size:
            first = int(voiced_indices[0])
            last = int(voiced_indices[-1])
            intended_samples = [float(item["intended_pitch_hz"]) for item in frame_debug if float(item.get("intended_pitch_hz", 0.0) or 0.0) > 0.0]
            intended_pitch = float(np.median(intended_samples)) if intended_samples else last_voiced_pitch
            window_radius = int(0.055 * SAMPLE_RATE)
            pitch_estimates: List[float] = []
            for item in frame_debug:
                idx = int(item["frame_index"])
                frame_start = idx * frame_samples
                if frame_start < first or frame_start > last or len(diagnostic_frames) >= 24:
                    continue
                lo = max(0, frame_start - window_radius)
                hi = min(len(final_mono), frame_start + frame_samples + window_radius)
                estimate = self._estimate_continuous_pitch_hz(final_mono[lo:hi], float(item["intended_pitch_hz"]))
                if estimate > 0.0:
                    err = abs(estimate - float(item["intended_pitch_hz"])) / max(1.0, float(item["intended_pitch_hz"])) * 100.0
                    item["measured_pitch_estimate_hz"] = round(estimate, 3)
                    item["pitch_error_percent"] = round(err, 3)
                    pitch_estimates.append(estimate)
                    diagnostic_frames.append(dict(item))
            if pitch_estimates:
                measured_pitch = float(np.median(pitch_estimates))
                pitch_error = abs(measured_pitch - intended_pitch) / max(1.0, intended_pitch) * 100.0
            active_phoneme = str(diagnostic_frames[0]["active_phoneme"] if diagnostic_frames else frame_debug[0]["active_phoneme"] if frame_debug else "")
        distortion_status = "ok"
        if clipped_sample_count > max(4, int(len(final_mono) * 0.0002)):
            distortion_status = "clipping"
        elif abs(dc_offset) > 0.035 or (crest_factor > 0.0 and crest_factor < 2.2 and final_peak > 0.35):
            distortion_status = "distorted"
        formant_input_rms = math.sqrt(formant_input_energy / formant_sample_count) if formant_sample_count > 0 else 0.0
        formant_output_rms = math.sqrt(formant_output_energy / formant_sample_count) if formant_sample_count > 0 else 0.0
        resonance_debug = self._resonance_formant_metadata(self.current_phoneme)
        waveform_pitch_frames = self._continuous_pitch_debug_frames(final_mono, frame_debug, frame_samples)
        pitch_debug_frames = waveform_pitch_frames or diagnostic_frames
        waveform_overlay_regions = self._continuous_waveform_overlay_regions(final_mono, segments, burst_events, pitch_debug_frames, stop_debug_events)
        metrics = {
            "active_render_mode": ARTICULATION_WORD_RENDER_CONTINUOUS,
            "chain_length": len(self.articulation_chain_items),
            "phoneme_count": len(self.articulation_chain_items),
            "output_duration": round(len(audio) / SAMPLE_RATE, 6) if audio.size else 0.0,
            "output_peak": round(final_peak, 9),
            "pre_normalize_peak": round(pre_normalize_peak, 9),
            "post_normalize_peak": round(post_normalize_peak, 9),
            "pre_peak": round(pre_normalize_peak, 9),
            "post_peak": round(post_normalize_peak, 9),
            "clipped_sample_count": clipped_sample_count,
            "clipped_samples": clipped_sample_count,
            "rms": round(final_rms, 9),
            "crest_factor": round(crest_factor, 6),
            "dc_offset": round(dc_offset, 9),
            "intended_pitch_hz": round(last_voiced_pitch, 3),
            "measured_pitch_estimate_hz": round(measured_pitch, 3),
            "pitch_estimate": round(measured_pitch, 3),
            "pitch_error_percent": round(pitch_error, 3),
            "pitch_error": round(pitch_error, 3),
            "transition_progress": round(float(diagnostic_frames[0].get("transition_progress", 0.0)) if diagnostic_frames else transition_progress, 3),
            "voiced_gain": round(float(np.max(voiced_trace)) if voiced_trace.size else 0.0, 3),
            "continuous_pitch_smoothing_ms": round(pitch_smoothing_ms, 3),
            "formant_intensity": round(self._continuous_formant_intensity(), 3),
            "formant_input_rms": round(formant_input_rms, 9),
            "formant_output_rms": round(formant_output_rms, 9),
            "formant_gain_ratio": round(formant_output_rms / max(1.0e-9, formant_input_rms), 6),
            **{key: round(float(value), 6) for key, value in resonance_debug.items()},
            "frame_index": int(diagnostic_frames[0]["frame_index"]) if diagnostic_frames else 0,
            "active_phoneme": active_phoneme,
            "pitch_debug_frames": pitch_debug_frames,
            "waveform_overlay_regions": waveform_overlay_regions,
            "waveform_overlay_region_count": len(waveform_overlay_regions),
            "distortion_status": distortion_status,
            "continuous_debug_bypass_formants": bool(self.articulation_word_render_settings.get("continuous_debug_bypass_formants", False)),
            "voiced_rms": round(float(np.sqrt(np.mean(np.square(voiced_bus)))) if voiced_bus.size else 0.0, 9),
            "noise_rms": round(float(np.sqrt(np.mean(np.square(noise_bus)))) if noise_bus.size else 0.0, 9),
            "source_rms": round(float(np.sqrt(np.mean(np.square(source_bus)))) if source_bus.size else 0.0, 9),
            "burst_peak": round(float(np.max(np.abs(burst_bus))) if burst_bus.size else 0.0, 9),
            "burst_rms": round(float(np.sqrt(np.mean(np.square(burst_bus)))) if burst_bus.size else 0.0, 9),
            "burst_event_count": len(burst_events),
            "stop_debug_events": stop_debug_events,
            "stop_debug_summary": "; ".join(f"{e['stop_name']} peak={e['burst_peak']} rms={e['burst_rms']}" for e in stop_debug_events[:4]),
            "stop_burst_status": "none" if len(burst_events) == 0 else "present" if (float(np.max(np.abs(burst_bus))) if burst_bus.size else 0.0) > 0.003 else "low",
            "smoothing_region_count": smoothing_region_count,
            "final_mix_rms": round(float(np.sqrt(np.mean(np.square(final_mix_bus)))) if final_mix_bus.size else 0.0, 9),
            "transition_count": transition_count,
            "transition_duration_total": transition_duration_total,
            "final_buffer_length": int(len(audio)),
            "voiced_phoneme_count": voiced_phoneme_count,
            "active_phoneme_accentuation_db": round(float(diagnostic_frames[0].get("active_phoneme_accentuation_db", 0.0)) if diagnostic_frames else float(frame_debug[0].get("active_phoneme_accentuation_db", 0.0)) if frame_debug else 0.0, 3),
            "max_accentuation_db": self._accentuation_summary()["max_accentuation_db"],
            "gain_applied": round(float(diagnostic_frames[0].get("gain_applied", 1.0)) if diagnostic_frames else float(frame_debug[0].get("gain_applied", 1.0)) if frame_debug else 1.0, 6),
            "voice_source_applied_count": max(voice_source_applied_counts) if voice_source_applied_counts else 0,
            "diphthong_profile": diphthong_debug_frames[0].get("diphthong_profile") if diphthong_debug_frames else None,
            "glide_start_percent": diphthong_debug_frames[0].get("glide_start_percent") if diphthong_debug_frames else None,
            "diphthong_start_vowel": diphthong_debug_frames[0].get("diphthong_start_vowel") if diphthong_debug_frames else None,
            "diphthong_end_vowel": diphthong_debug_frames[0].get("diphthong_end_vowel") if diphthong_debug_frames else None,
            "diphthong_progress": diphthong_debug_frames[-1].get("diphthong_progress") if diphthong_debug_frames else None,
            "diphthong_interpolation_curve": diphthong_debug_frames[0].get("diphthong_interpolation_curve") if diphthong_debug_frames else None,
            "diphthong_debug_frames": diphthong_debug_frames[:24],
            "coarticulation_debug_frames": [item for item in frame_debug if item.get("coarticulation_pair")][:24],
            "coarticulation_pair": next((item.get("coarticulation_pair") for item in frame_debug if item.get("coarticulation_pair")), None),
            "coarticulation_strength": next((item.get("coarticulation_strength") for item in frame_debug if item.get("coarticulation_pair")), None),
            "coarticulation_type": next((item.get("coarticulation_type") for item in frame_debug if item.get("coarticulation_pair")), None),
            "transition_model_debug_frames": [item for item in frame_debug if item.get("transition_model_id")][:24],
            "transition_model": next((item.get("transition_model") for item in frame_debug if item.get("transition_model_id")), None),
            "transition_model_id": next((item.get("transition_model_id") for item in frame_debug if item.get("transition_model_id")), None),
            "transition_strength": next((item.get("transition_strength") for item in frame_debug if item.get("transition_model_id")), None),
        }
        self._report_continuous_render_debug(metrics)
        print(
            f"[WaveToy Envelope] max_voiced_gain={float(np.max(voiced_trace)):.3f} "
            f"max_noise_gain={float(np.max(noise_trace)):.3f} max_closure={float(np.max(closure_trace)):.3f} "
            f"pre_peak={pre_normalize_peak:.3f} final_peak={final_peak:.3f} pitch_estimate={measured_pitch:.2f}Hz "
            f"pitch_error={pitch_error:.2f}% clipped_samples={clipped_sample_count} "
            f"final_rendered_duration={len(audio) / SAMPLE_RATE:.3f}s"
        )
        self._log_word_render_debug(ARTICULATION_WORD_RENDER_CONTINUOUS, audio)
        return audio.astype(np.float32)

    def _diagnose_word_boundaries(self, audio: np.ndarray, boundaries: List[int]) -> None:
        if audio.size == 0 or not boundaries:
            return
        threshold = 1.0e-4
        minimum_silent = max(1, int(0.005 * SAMPLE_RATE))
        radius = max(minimum_silent, int(0.012 * SAMPLE_RATE))
        envelope = np.max(np.abs(audio), axis=1)
        for boundary in boundaries:
            start = max(0, int(boundary) - radius)
            end = min(len(envelope), int(boundary) + radius)
            if end <= start:
                continue
            silent = envelope[start:end] <= threshold
            longest = current = 0
            for value in silent:
                if bool(value):
                    current += 1
                    longest = max(longest, current)
                else:
                    current = 0
            if longest > minimum_silent:
                print(f"[WaveToy Word] detected silent boundary region {longest * 1000.0 / SAMPLE_RATE:.1f} ms near sample {boundary}")

    def _render_articulation_word_coarticulated(self) -> np.ndarray:
        word = np.zeros((0, 2), dtype=np.float32)
        boundaries: List[int] = []
        print(f"[WaveToy Word] word render started • mode coarticulated overlap • phoneme count {len(self.articulation_chain_items)}")
        clips = [self._apply_chain_item_accentuation(self._render_articulation_with_source(item.phoneme_for_render()), item) for item in self.articulation_chain_items]
        for index, (item, clip) in enumerate(zip(self.articulation_chain_items, clips)):
            if index == 0:
                word = self._overlap_word_clip(word, clip, 0, boundaries)
                continue
            previous_item = self.articulation_chain_items[index - 1]
            requested_transition_ms = self._chain_transition_duration_ms(previous_item, item)
            effective_samples = self._effective_transition_samples(clips[index - 1], clip, requested_transition_ms, previous_item, item)
            self._log_transition_boundary(
                previous_item,
                item,
                requested_transition_ms,
                effective_samples,
                inserted_silence_samples=0,
                transition_render_samples=0,
                interpolated_articulation_used=False,
            )
            word = self._overlap_word_clip(word, clip, effective_samples, boundaries)
        word = self._smooth_word_boundaries(word, boundaries)
        word = self._fade_word_edges(word)
        word = normalize_audio(word).astype(np.float32)
        self._diagnose_word_boundaries(word, boundaries)
        print(f"[WaveToy Word] final word duration {len(word) / SAMPLE_RATE:.3f} s")
        return word

    def _render_articulation_word_clip_crossfade(self) -> np.ndarray:
        print(f"[WaveToy Envelope] render mode={ARTICULATION_WORD_RENDER_CLIP_CROSSFADE} phoneme_count={len(self.articulation_chain_items)}")
        if self._articulation_smooth_transitions_enabled():
            audio = self._render_articulation_word_coarticulated()
        else:
            audio = self._render_articulation_word_simple()
        self._log_word_render_debug(ARTICULATION_WORD_RENDER_CLIP_CROSSFADE, audio)
        return audio

    def _render_articulation_word(self) -> np.ndarray:
        mode = self._articulation_word_render_mode()
        print(f"[WaveToy Word] selected render_mode={mode}")
        if self._singing_mode_enabled():
            print("[WaveToy Singing] Singing Preview enabled; applying optional note pitch targets to voiced phonemes")
            audio = self._render_articulation_word_singing_preview()
        elif mode == ARTICULATION_WORD_RENDER_PLAIN:
            audio = self._render_articulation_word_plain()
        elif mode == ARTICULATION_WORD_RENDER_CLIP_CROSSFADE:
            audio = self._render_articulation_word_clip_crossfade()
        elif mode == ARTICULATION_WORD_RENDER_CONTINUOUS:
            try:
                audio = self._render_articulation_word_continuous()
            except Exception as exc:
                print(f"[WaveToy Envelope] error continuous renderer failed without Clip Crossfade fallback: {exc}")
                self._report_continuous_render_debug({
                    "active_render_mode": ARTICULATION_WORD_RENDER_CONTINUOUS,
                    "chain_length": len(self.articulation_chain_items),
                    "phoneme_count": len(self.articulation_chain_items),
                    "output_duration": 0.0,
                    "output_peak": 0.0,
                    "voiced_rms": 0.0,
                    "noise_rms": 0.0,
                    "source_rms": 0.0,
                    "transition_count": 0,
                    "transition_duration_total": 0,
                    "final_buffer_length": 0,
                    "voiced_phoneme_count": 0,
                    "exception": str(exc),
                })
                audio = np.zeros((0, 2), dtype=np.float32)
        else:
            audio = self._render_articulation_word_clip_crossfade()
        return self._apply_performance_automation_to_audio(audio)

    def _current_word_render_signature(self) -> str:
        payload = {
            "display_sequence": self._speech_display_sequence_for_chain(),
            "ipa_sequence": self._speech_ipa_sequence_for_chain(),
            "chain_items": [item.to_json_dict() for item in self.articulation_chain_items],
            "render_mode": self._articulation_word_render_mode(),
            "word_render_settings": dict(self.articulation_word_render_settings),
            "voice_source_profile": self.voice_source_profile.to_json_dict(),
            "voice_box_state": self.voice_box_state.to_json_dict(),
            "resonance_tract_state": self.resonance_tract_state.to_json_dict(),
            "character_voice_profile": self.character_voice_profile.to_json_dict(),
            "musical_timing_settings": self.musical_timing_settings.to_json_dict(),
            "note_events": self._note_events_json(),
            "pitch_curve": self._pitch_curve_json(),
            "syllable_stress_markers": self._syllable_stress_json(),
            "singing_mode_enabled": self._singing_mode_enabled(),
            "performance_timeline_tracks": self._timeline_tracks_json(),
        }
        return json.dumps(payload, sort_keys=True, ensure_ascii=False)

    def _current_word_audio_is_fresh(self) -> bool:
        return bool(
            self.articulation_word_render_audio.size
            and self.articulation_word_render_signature == self._current_word_render_signature()
        )

    def _render_word_audio_for_current_chain(self) -> np.ndarray:
        if not self.articulation_chain_items:
            QMessageBox.information(self, "Create Word", "Add at least one phoneme to the Articulation Chain first.")
            return np.zeros((0, 2), dtype=np.float32)
        self.articulation_word_render_audio = self._render_articulation_word()
        self.articulation_word_render_signature = self._current_word_render_signature() if self.articulation_word_render_audio.size else None
        self.articulation_last_word_render_created_at = time.time()
        self.articulation_last_word_render_path = None
        self._update_articulation_word_status()
        self._update_articulation_waveform_diagnostics_canvas()
        return self.articulation_word_render_audio

    def _create_articulation_word(self, checked: bool = False) -> np.ndarray:
        del checked
        audio = self._render_word_audio_for_current_chain()
        if audio.size == 0:
            return audio
        default_name = (self._speech_display_sequence_for_chain().replace(" + ", "").lower() or "word")
        name, ok = QInputDialog.getText(self, "Create Word", "Name this Speech Assets word:", text=default_name)
        if not ok:
            name = default_name
        name = name.strip() or default_name
        word_item = self._create_rendered_speech_bin_item("word", name=name)
        if word_item is not None:
            self._save_library_asset("word", word_item.name, word_item.metadata(), description="Created word asset with phoneme sequence, timing, transitions, stress markers, note events, and voice profile references", tags=["speech-bin"])
            self.timeline_selected_speech_item_id = word_item.id
            self._timeline_refresh_speech_bin_cards()
            message = f"Word ready: {word_item.name} • {word_item.duration_seconds:.2f}s • {self._chain_custom_transition_summary()} • saved to Speech Assets."
            self.articulation_word_status_label.setText(message)
            self._timeline_debug(message)
        return audio

    def _play_articulation_word(self, checked: bool = False) -> None:
        del checked
        if not self._can_start_playback():
            return
        cached_reused = self._current_word_audio_is_fresh()
        audio = self.articulation_word_render_audio if cached_reused else self._render_word_audio_for_current_chain()
        fresh_render_created = not cached_reused and bool(audio.size)
        self._log_play_word_render_path(self._articulation_word_render_mode(), audio, cached_reused, fresh_render_created)
        if audio.size == 0:
            QMessageBox.information(self, "Play Word", "The current articulation chain did not render any audio.")
            return
        self._start_articulation_motion(loop=False, speed=1.0, audio=audio)

    def _export_articulation_word(self, checked: bool = False) -> None:
        del checked
        if self.articulation_word_render_audio.size == 0:
            audio = self._create_articulation_word(checked=False)
            if audio.size == 0:
                return
        timestamp = time.strftime("%Y%m%d_%H%M%S")
        chain_name = "_".join(item.phoneme.name.lower() for item in self.articulation_chain_items[:6]) or "word"
        safe_name = "".join(ch if ch.isalnum() or ch in {"_", "-"} else "_" for ch in chain_name)
        filename, selected_filter = QFileDialog.getSaveFileName(
            self,
            "Export Created Word",
            f"wave_toy_word_{safe_name}_{timestamp}.wav",
            "WAV Audio (*.wav);;Ogg Vorbis (*.ogg);;MP3 Audio (*.mp3);;FLAC Audio (*.flac)",
        )
        if not filename:
            return
        path = Path(filename)
        if not path.suffix:
            if "Ogg" in selected_filter:
                path = path.with_suffix(".ogg")
            elif "MP3" in selected_filter:
                path = path.with_suffix(".mp3")
            elif "FLAC" in selected_filter:
                path = path.with_suffix(".flac")
            else:
                path = path.with_suffix(".wav")
        try:
            save_audio_file(path, self.articulation_word_render_audio)
            sidecar = path.with_suffix(path.suffix + ".wave-toy-word.json")
            data = ArticulationChain(
                items=self.articulation_chain_items,
                last_word_render_path=str(path),
                last_word_render_created_at=self.articulation_last_word_render_created_at,
                word_render_settings=dict(self.articulation_word_render_settings),
            ).to_json_dict()
            data.update(
                {
                    "version": 1,
                    "sample_rate": SAMPLE_RATE,
                    "duration_seconds": len(self.articulation_word_render_audio) / SAMPLE_RATE,
                    "notes": "Created Word metadata stores articulation snapshots and source paths only; raw audio is not embedded.",
                }
            )
            sidecar.write_text(json.dumps(data, indent=2), encoding="utf-8")
            self._save_library_asset("generated_wav", path.stem, {"audio_path": str(path), "metadata_path": str(sidecar), "duration_seconds": len(self.articulation_word_render_audio) / SAMPLE_RATE}, description="Generated word WAV export", source_path=str(path))
            self._save_library_asset("word", path.stem, data, description="Exported word metadata", source_path=str(sidecar))
            self.articulation_last_word_render_path = path
            self._update_articulation_word_status()
            QMessageBox.information(self, "Word Exported", f"Saved created word:\n{path}\n\nSaved word metadata:\n{sidecar}")
        except Exception as exc:
            QMessageBox.warning(self, "Could not export word", str(exc))

    def _play_articulation_chain(self, checked: bool = False) -> None:
        del checked
        if not self._can_start_playback():
            return
        if not self.articulation_chain_items:
            QMessageBox.information(self, "Articulation Chain", "Add at least one phoneme to the chain first.")
            return
        rendered = [self._apply_chain_item_accentuation(self._render_articulation_with_source(item.phoneme_for_render()), item) for item in self.articulation_chain_items]
        audio = np.vstack([clip for clip in rendered if clip.size]) if rendered else np.zeros((0, 2), dtype=np.float32)
        self._play_audio_array(audio)
        self._start_articulation_motion(loop=False, speed=1.0)

    def _save_articulation_chain(self, checked: bool = False) -> None:
        del checked
        data = ArticulationChain(
            items=self.articulation_chain_items,
            last_word_render_path=str(self.articulation_last_word_render_path) if self.articulation_last_word_render_path else None,
            last_word_render_created_at=self.articulation_last_word_render_created_at,
            word_render_settings=dict(self.articulation_word_render_settings),
            syllable_markers=list(self.articulation_syllable_markers),
            phrase_markers=list(self.articulation_phrase_markers),
        ).to_json_dict()
        self.articulation_chain_path.write_text(json.dumps(data, indent=2), encoding="utf-8")
        chain_name = self._speech_display_sequence_for_chain() or "Articulation Chain"
        self._save_library_asset("articulation_chain", chain_name, data, description="Saved articulation chain", tags=["favorite:false"], notes="created_date and modified_date are stored as created_at/modified_at metadata fields.", source_path=str(self.articulation_chain_path))
        QMessageBox.information(self, "Articulation Chain", f"Saved {len(self.articulation_chain_items)} chain phoneme(s) to {self.articulation_chain_path} and Speech Asset Library.")

    def _load_articulation_chain(self, checked: bool = False) -> None:
        del checked
        if not self.articulation_chain_path.exists():
            QMessageBox.information(self, "Articulation Chain", "No saved articulation_chain.json file was found yet.")
            return
        data = json.loads(self.articulation_chain_path.read_text(encoding="utf-8"))
        self.articulation_chain_items = [ArticulationChainItem.from_json_dict(item) for item in data.get("items", []) if isinstance(item, dict)]
        self.articulation_selected_chain_index = 0 if self.articulation_chain_items else None
        self.articulation_last_word_render_path = Path(data["last_word_render_path"]) if data.get("last_word_render_path") else None
        self.articulation_last_word_render_created_at = data.get("last_word_render_created_at") if isinstance(data.get("last_word_render_created_at"), (int, float)) else None
        if isinstance(data.get("word_render_settings"), dict):
            self.articulation_word_render_settings.update(data["word_render_settings"])
        loaded_mode = str(self.articulation_word_render_settings.get("word_render_mode", ARTICULATION_WORD_RENDER_CLIP_CROSSFADE))
        if loaded_mode not in ARTICULATION_WORD_RENDER_MODES:
            loaded_mode = ARTICULATION_WORD_RENDER_CLIP_CROSSFADE
        self.articulation_word_render_settings["word_render_mode"] = loaded_mode
        self.articulation_syllable_markers = list(data.get("syllable_markers", [])) if isinstance(data.get("syllable_markers", []), list) else []
        self.articulation_phrase_markers = list(data.get("phrase_markers", [])) if isinstance(data.get("phrase_markers", []), list) else []
        if self.articulation_smooth_transitions_checkbox is not None:
            self.articulation_smooth_transitions_checkbox.setChecked(bool(self.articulation_word_render_settings.get("smooth_mouth_transitions", True)))
        if self.continuous_debug_bypass_formants_checkbox is not None:
            self.continuous_debug_bypass_formants_checkbox.setChecked(bool(self.articulation_word_render_settings.get("continuous_debug_bypass_formants", False)))
        if self.continuous_formant_intensity_spin is not None:
            self.continuous_formant_intensity_spin.setValue(float(self.articulation_word_render_settings.get("continuous_formant_intensity", 0.45)))
        if self.continuous_pitch_smoothing_spin is not None:
            self.continuous_pitch_smoothing_spin.setValue(int(self.articulation_word_render_settings.get("continuous_pitch_smoothing_ms", 20)))
        if self.articulation_word_render_mode_combo is not None:
            self.articulation_word_render_mode_combo.setCurrentText(loaded_mode)
        self.articulation_word_render_audio = np.zeros((0, 2), dtype=np.float32)
        self.articulation_word_render_signature = None
        self._refresh_articulation_chain_cards()
        self._refresh_articulation_motion_timeline()
        self._refresh_performance_tables()
        self._timeline_refresh_palette_cards()
        self._timeline_update_duration()
        if self.timeline_canvas is not None:
            self.timeline_canvas._refresh_size()
            self.timeline_canvas.update()

    def _select_vowel_preset(self, preset_name: str, play: bool = False) -> None:
        data = VOWEL_PRESETS[preset_name]
        pitch = self._settings_from_ui().pitch_start_hz if hasattr(self, "pitch_start") else 220.0
        phoneme = ArticulationPhoneme.from_json_dict({**data, "name": preset_name, "phoneme_family": "vowel", "voiced": True, "voice_pitch": pitch, "voice_strength": 0.65, "duration_ms": 500})
        self._set_articulation_ui_from_phoneme(phoneme)
        if play:
            self._play_phoneme_preview()

    def _select_consonant_preset(self, preset_name: str, preset_data: Dict[str, object], play: bool = False) -> None:
        pitch = self._settings_from_ui().pitch_start_hz if hasattr(self, "pitch_start") else 220.0
        data = {**preset_data, "name": preset_name, "voice_pitch": pitch, "voice_strength": 0.62}
        phoneme = ArticulationPhoneme.from_json_dict(data)
        self._set_articulation_ui_from_phoneme(phoneme)
        if play:
            self._play_phoneme_preview()

    def _play_audio_array(self, audio: np.ndarray) -> None:
        if sd is not None:
            try:
                sd.stop()
                sd.play(audio, SAMPLE_RATE, blocking=False)
                return
            except Exception:
                pass
        old_audio = self.current_audio
        try:
            self.current_audio = audio
            ok, message = self._play_with_system_player()
        finally:
            self.current_audio = old_audio
        if not ok:
            self._show_playback_warning(message)

    def _play_phoneme_preview(self, checked: bool = False, *, rate_limit: bool = True) -> None:
        del checked
        if rate_limit and not self._can_start_playback():
            return
        self.current_phoneme = self._phoneme_from_articulation_ui()
        self.phoneme_preview_audio = self._render_articulation_with_source(self.current_phoneme)
        self._play_audio_array(self.phoneme_preview_audio)
        if self.phoneme_loop_enabled:
            duration_ms = max(100, int((len(self.phoneme_preview_audio) / SAMPLE_RATE) * 1000))
            self.phoneme_loop_timer.start(duration_ms)

    def _toggle_phoneme_loop(self, checked: bool = False) -> None:
        del checked
        self.phoneme_loop_enabled = not self.phoneme_loop_enabled
        if self.phoneme_loop_enabled:
            self._play_phoneme_preview(rate_limit=False)
        else:
            self._stop_phoneme_preview()

    def _articulation_loop_tick(self) -> None:
        if self.phoneme_loop_enabled:
            self._play_phoneme_preview(rate_limit=False)

    def _stop_phoneme_preview(self, checked: bool = False) -> None:
        del checked
        self.phoneme_loop_enabled = False
        self.phoneme_loop_timer.stop()
        self._stop_playback_tracking(clear_playheads=True)
        if sd is not None:
            try:
                sd.stop()
            except Exception:
                pass
        self._stop_fallback_playback()

    def _save_current_phoneme(self, checked: bool = False) -> None:
        del checked
        phoneme = self._phoneme_from_articulation_ui()
        name, ok = QInputDialog.getText(self, "Save Phoneme", "Friendly phoneme name:", text=phoneme.name.lower())
        if not ok or not name.strip():
            return
        phoneme.name = name.strip()
        self.current_phoneme = phoneme.clamped()
        self.phonemes_dir.mkdir(parents=True, exist_ok=True)
        path = self._phoneme_path(self.current_phoneme)
        if path.exists():
            answer = QMessageBox.question(
                self,
                "Overwrite Phoneme",
                f"A phoneme named '{self.current_phoneme.name}' already exists. Overwrite {path.name}?",
                QMessageBox.Yes | QMessageBox.No,
                QMessageBox.No,
            )
            if answer != QMessageBox.Yes:
                return
        path.write_text(json.dumps(self.current_phoneme.to_json_dict(), indent=2), encoding="utf-8")
        self._save_library_asset("phoneme", self.current_phoneme.name, self.current_phoneme.to_json_dict(), description="Saved articulation phoneme preset", source_path=str(path))
        self._load_saved_phonemes()
        self._refresh_phoneme_cards()
        self._update_articulation_preview(regenerate=True)

    def _refresh_phoneme_cards(self) -> None:
        if self.phoneme_cards_widget is None:
            return
        layout = self.phoneme_cards_widget.layout()
        if layout is None:
            layout = QVBoxLayout(self.phoneme_cards_widget)
            layout.setContentsMargins(0, 0, 0, 0)
            layout.setSpacing(10)
        else:
            while layout.count():
                item = layout.takeAt(0)
                widget = item.widget()
                if widget is not None:
                    widget.deleteLater()
        if not self.saved_phonemes:
            empty = QLabel("Save a vowel or consonant to make a reusable phoneme card.")
            empty.setWordWrap(True)
            empty.setObjectName("symbolHint")
            layout.addWidget(empty)
            layout.addStretch(1)
            return
        for phoneme in self.saved_phonemes:
            layout.addWidget(self._make_phoneme_card(phoneme))
        layout.addStretch(1)

    def _make_phoneme_card(self, phoneme: ArticulationPhoneme) -> QWidget:
        card = QWidget()
        card.setObjectName("phonemeCard")
        card.setMinimumHeight(72)
        card.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Minimum)
        card.setStyleSheet(f"QWidget#phonemeCard {{ background: {phoneme.preview_color}; border-radius: 10px; }}")
        layout = QVBoxLayout(card)
        layout.setContentsMargins(14, 12, 14, 12)
        layout.setSpacing(8)

        header = QHBoxLayout()
        header.setSpacing(10)
        ipa = QLabel(f"/{phoneme.ipa}/")
        ipa.setObjectName("phonemeCardIpa")
        ipa.setAlignment(Qt.AlignCenter)
        ipa.setMinimumWidth(66)
        title = QLabel(phoneme.name)
        title.setObjectName("phonemeCardTitle")
        title.setWordWrap(True)
        summary = QLabel(articulation_summary(phoneme))
        summary.setObjectName("phonemeCardSummary")
        summary.setWordWrap(True)
        source_badge = QLabel(articulation_source_badge(phoneme.source_mode, phoneme.source_wave_id, phoneme.source_audio_path))
        source_badge.setObjectName("articulationIpaBadge")
        source_badge.setAlignment(Qt.AlignCenter)
        title_stack = QVBoxLayout()
        title_stack.setSpacing(2)
        title_stack.addWidget(title)
        title_stack.addWidget(summary)
        title_stack.addWidget(source_badge)

        play_button = QPushButton("▶ Play")
        play_button.setObjectName("phonemeCardPrimaryAction")
        play_button.setMinimumHeight(WaveToySizing.MIN_TOUCH_TARGET)
        play_button.clicked.connect(lambda checked=False, p=phoneme: self._play_saved_phoneme(p))
        delete_button = QPushButton("🗑 Delete")
        delete_button.setObjectName("phonemeCardDangerAction")
        delete_button.setMinimumHeight(WaveToySizing.MIN_TOUCH_TARGET)
        delete_button.clicked.connect(lambda checked=False, p=phoneme: self._delete_saved_phoneme(p))

        header.addWidget(ipa)
        header.addLayout(title_stack, 1)
        header.addWidget(play_button)
        header.addWidget(delete_button)
        layout.addLayout(header)

        tools = QHBoxLayout()
        tools.setSpacing(8)
        secondary_actions = (
            ("Load", lambda checked=False, p=phoneme: self._load_saved_phoneme(p)),
            ("Rename", lambda checked=False, p=phoneme: self._rename_saved_phoneme(p)),
            ("Duplicate", lambda checked=False, p=phoneme: self._duplicate_saved_phoneme(p)),
        )
        for text, callback in secondary_actions:
            button = QPushButton(text)
            button.setObjectName("phonemeCardSecondaryAction")
            button.setMinimumHeight(WaveToySizing.MIN_TOUCH_TARGET)
            button.clicked.connect(callback)
            tools.addWidget(button)
        layout.addLayout(tools)
        return card

    def _play_saved_phoneme(self, phoneme: ArticulationPhoneme) -> None:
        if not self._can_start_playback():
            return
        self._play_audio_array(self._render_articulation_with_source(phoneme))

    def _load_saved_phoneme(self, phoneme: ArticulationPhoneme) -> None:
        self._set_articulation_ui_from_phoneme(phoneme)

    def _rename_saved_phoneme(self, phoneme: ArticulationPhoneme) -> None:
        new_name, ok = QInputDialog.getText(self, "Rename Phoneme", "New friendly name:", text=phoneme.name)
        if not ok or not new_name.strip():
            return
        old_path = self._phoneme_path(phoneme)
        phoneme.name = new_name.strip()
        new_path = self._phoneme_path(phoneme)
        self.phonemes_dir.mkdir(parents=True, exist_ok=True)
        new_path.write_text(json.dumps(phoneme.to_json_dict(), indent=2), encoding="utf-8")
        if old_path.exists() and old_path != new_path:
            old_path.unlink()
        self._load_saved_phonemes()
        self._refresh_phoneme_cards()

    def _duplicate_saved_phoneme(self, phoneme: ArticulationPhoneme) -> None:
        duplicate = ArticulationPhoneme.from_json_dict(phoneme.to_json_dict())
        duplicate.name = f"{phoneme.name}_copy"
        self.phonemes_dir.mkdir(parents=True, exist_ok=True)
        self._phoneme_path(duplicate).write_text(json.dumps(duplicate.to_json_dict(), indent=2), encoding="utf-8")
        self._load_saved_phonemes()
        self._refresh_phoneme_cards()

    def _delete_saved_phoneme(self, phoneme: ArticulationPhoneme) -> None:
        path = self._phoneme_path(phoneme)
        if path.exists():
            path.unlink()
        self._load_saved_phonemes()
        self._refresh_phoneme_cards()

    def _make_story_button(self, icon: str, label: str, color: str, callback) -> QPushButton:
        button = QPushButton(f"{icon}  {label}")
        button.setObjectName("storyTransportButton")
        button.setProperty("accent", color)
        button.setMinimumSize(QSize(108, WaveToySizing.BUTTON_HEIGHT))
        button.setCursor(Qt.PointingHandCursor)
        button.setToolTip(label)
        button.setStyleSheet(
            f"""
            QPushButton#storyTransportButton {{
                background: rgba(6, 18, 32, 0.88);
                color: #f7fbff;
                border: 1px solid rgba(190, 232, 255, 0.62);
                border-left: 4px solid {color};
                border-radius: 8px;
                font-size: 12px;
                font-weight: 900;
                min-height: 36px;
                padding: 5px 10px;
                text-align: left;
            }}
            QPushButton#storyTransportButton:hover {{
                background: rgba(13, 37, 58, 0.96);
                border-color: rgba(36, 215, 255, 0.95);
            }}
            QPushButton#storyTransportButton:pressed {{
                background: rgba(5, 12, 23, 1.0);
                padding-top: 7px;
            }}
            QPushButton#storyTransportButton:disabled {{
                background: rgba(56, 68, 82, 0.72);
                color: #b7c9d8;
                border-color: rgba(185, 199, 212, 0.42);
                border-left-color: #7d8b98;
            }}
            """
        )
        button.clicked.connect(callback)
        return button

    def _timeline_debug(self, message: str) -> None:
        print(f"[WaveToy Timeline] {message}")
        if getattr(self, "timeline_status_label", None) is not None:
            self.timeline_status_label.setText(message)

    def _timeline_stretch_debug(self, message: str) -> None:
        print(f"[WaveToy Stretch] {message}")
        if getattr(self, "timeline_status_label", None) is not None:
            self.timeline_status_label.setText(message)


    def _build_graphical_editor_tab(self) -> None:
        if self.tabs is None:
            return
        tab = WaveToyScrollArea(scroll_speed=0.92, content_drag_scroll=False)
        tab.setObjectName("graphicalEditorTab")
        tab.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
        page = QWidget()
        page.setObjectName("graphicalEditorPage")
        outer = QVBoxLayout(page)
        outer.setContentsMargins(16, 12, 16, 18)
        outer.setSpacing(12)

        title = QLabel("Graphical Editor")
        title.setObjectName("title")
        subtitle = QLabel("Visual-first sound building: drag wave layers, stereo dots, pitch points, and the mouth model. Sliders stay available as advanced fallback controls.")
        subtitle.setObjectName("subtitle")
        subtitle.setWordWrap(True)
        self.graphical_status_label = QLabel("Graphical Editor shares the same controls as Classic Controls, Wave Explorer, and Articulation Lab — no duplicate recipe state.")
        self.graphical_status_label.setObjectName("dashboardSummary")
        self.graphical_status_label.setWordWrap(True)
        self.graphical_status_label.setAlignment(Qt.AlignCenter)
        outer.addWidget(title)
        outer.addWidget(subtitle)
        outer.addWidget(self.graphical_status_label)

        outer.addWidget(self._graphical_workflow_section(
            "1. Source Wave",
            "Drag loudness handles on each layer card. Add, duplicate, mute, solo, and remove waves here; Classic Controls mix sliders update immediately.",
            self._build_graphical_wave_section(),
            "Advanced: Classic Controls",
            lambda checked=False: self._show_named_tab("Classic Controls"),
            expanded=True,
        ))
        outer.addWidget(self._graphical_workflow_section(
            "2. Stereo Field",
            "Drag start/end dots across the ears to update whole-mix Stereo Placement. Use the mouse wheel over the field for stereo width.",
            self._build_graphical_stereo_section(),
            "Advanced: Wave Explorer",
            lambda checked=False: self._show_named_tab("Wave Explorer"),
            expanded=True,
        ))
        outer.addWidget(self._graphical_workflow_section(
            "3. Pitch Motion",
            "Drag pitch start/end points on an octave grid. The curve writes to the same pitch sliders used by Classic Controls and the tuning map.",
            self._build_graphical_pitch_section(),
            "Advanced: Pitch Tools",
            lambda checked=False: self._show_named_tab("Classic Controls"),
            expanded=True,
        ))
        outer.addWidget(self._graphical_workflow_section(
            "4. Texture / Effects",
            "Preview-only blocks show the signal order for this phase. Toggle and intensity controls still use existing Sound Modules sliders.",
            self._build_graphical_sound_magic_section(),
            "Advanced: Texture / Effects",
            lambda checked=False: self._show_named_tab("Classic Controls"),
            expanded=False,
        ))
        outer.addWidget(self._graphical_workflow_section(
            "5. Vocal Tract",
            "Drag tongue, mouth/lips, airflow, click the nose, or click the voice bubble. Articulation Lab sliders and phoneme preview stay synchronized.",
            self._build_graphical_vocal_section(),
            "Advanced: Articulation Lab",
            lambda checked=False: self._show_named_tab("Articulation Lab"),
            expanded=True,
        ))
        outer.addWidget(self._graphical_workflow_section(
            "6. Articulation Timeline",
            "Drag phoneme block edges and transition zones, scrub the playhead, and preview the mouth motion. Create Word uses these edited chain values.",
            self._build_graphical_chain_section(),
            "Advanced: Articulation Timeline",
            lambda checked=False: self._show_named_tab("Articulation Timeline"),
            expanded=True,
        ))
        outer.addWidget(self._graphical_workflow_section(
            "7. Send to Timeline",
            "Preview-only handoff panel: use existing Speech Assets, Audio Assets, and Timeline buttons to place rendered sounds without changing those workflows.",
            self._build_graphical_timeline_section(),
            "Open Timeline",
            lambda checked=False: self._show_named_tab("Timeline"),
            expanded=False,
        ))
        outer.addStretch(1)
        tab.setWidget(page)
        self.tabs.insertTab(max(0, self.tabs.count() - 1), tab, "Graphical Editor")
        self._refresh_graphical_editor()

    def _graphical_workflow_section(self, title: str, body: str, content: QWidget, button_text: str, callback, *, expanded: bool) -> QWidget:
        wrapper = QWidget()
        wrapper.setObjectName("graphicalWorkflowCard")
        layout = QVBoxLayout(wrapper)
        layout.setContentsMargins(8, 6, 8, 8)
        layout.setSpacing(6)
        header = QLabel(title)
        header.setObjectName("dashboardExplorerTitle")
        header.setWordWrap(True)
        hint = QLabel(body)
        hint.setObjectName("symbolHint")
        hint.setWordWrap(True)
        shortcut = QPushButton(button_text)
        shortcut.setObjectName("workspaceToolbarButton")
        shortcut.setMinimumHeight(38)
        shortcut.clicked.connect(callback)
        top = QHBoxLayout()
        top.addWidget(header, 1)
        top.addWidget(shortcut, 0)
        box = QWidget()
        box_layout = QVBoxLayout(box)
        box_layout.setContentsMargins(0, 0, 0, 0)
        box_layout.setSpacing(8)
        box_layout.addWidget(hint)
        box_layout.addWidget(content)
        layout.addLayout(top)
        layout.addWidget(CollapsibleSection("Show / hide direct controls", box, expanded=expanded))
        return wrapper

