    def _show_named_tab(self, tab_text: str) -> None:
        if self.tabs is None:
            return
        for index in range(self.tabs.count()):
            if self.tabs.tabText(index) == tab_text:
                self.tabs.setCurrentIndex(index)
                return

    def _refresh_graphical_editor(self) -> None:
        self._refresh_graphical_wave_layers()
        if self.graphical_stereo_canvas is not None and hasattr(self, "pan_start_slider"):
            self.graphical_stereo_canvas.set_state(
                self.pan_start_slider.value() / (100.0 * PERCENT_SLIDER_SCALE),
                self.pan_end_slider.value() / (100.0 * PERCENT_SLIDER_SCALE),
                self.width_slider.value() / (100.0 * PERCENT_SLIDER_SCALE),
                self.auto_pan_depth_slider.value() / (100.0 * PERCENT_SLIDER_SCALE),
            )
        if self.graphical_pitch_canvas is not None and hasattr(self, "pitch_start"):
            self.graphical_pitch_canvas.set_state(self.pitch_start.value(), self.pitch_end.value(), abs(self.pitch_end.value() - self.pitch_start.value()) / float(48 * MIDI_SLIDER_SCALE))
        if self.graphical_vocal_canvas is not None and hasattr(self, "current_phoneme"):
            self.graphical_vocal_canvas.set_phoneme(self.current_phoneme)
        self._refresh_graphical_chain_editor()
        if self.graphical_status_label is not None:
            self.graphical_status_label.setText("Two-way sync active: graphical edits write sliders/model; slider, preset, recipe, and chain refreshes repaint this tab.")

    def _refresh_graphical_wave_layers(self) -> None:
        if self.graphical_wave_layer_list is None or self.graphical_wave_layer_list.layout() is None:
            return
        layout = self.graphical_wave_layer_list.layout()
        while layout.count():
            item = layout.takeAt(0)
            widget = item.widget()
            if widget is not None:
                widget.deleteLater()
        self.graphical_wave_canvases.clear()
        self.graphical_wave_cards.clear()
        if self.graphical_selected_wave_id not in self.wave_row_order:
            self.graphical_selected_wave_id = self.wave_row_order[0] if self.wave_row_order else None
        solo_wave = self._solo_wave_from_ui() if hasattr(self, "wave_solo_buttons") else None
        for wave_id in list(self.wave_row_order):
            row = GraphicalWaveCard(wave_id)
            row.waveSelected.connect(self._graphical_select_wave)
            muted = self.wave_mute_buttons.get(wave_id).isChecked() if wave_id in self.wave_mute_buttons else False
            soloed = solo_wave == wave_id
            self._set_graphical_wave_card_visuals(row, wave_id, muted, soloed)
            row_layout = QVBoxLayout(row)
            row_layout.setContentsMargins(0, 0, 0, 0)
            row_layout.setSpacing(0)

            actions = GraphicalWaveCard(wave_id)
            actions.setObjectName("graphicalWaveCardHeader")
            actions.waveSelected.connect(self._graphical_select_wave)
            actions_layout = FlowLayout(actions, margin=10, spacing=8)
            mute = QPushButton("Mute")
            solo = QPushButton("Solo")
            duplicate = QPushButton("Copy")
            remove = QPushButton("Remove")
            for button in (mute, solo, duplicate, remove):
                button.setObjectName("workspaceToolbarButton")
                button.setMinimumSize(QSize(72, 36))
                button.setSizePolicy(QSizePolicy.Minimum, QSizePolicy.Fixed)
                actions_layout.addWidget(button)
            mute.setCheckable(True)
            mute.setChecked(muted)
            solo.setCheckable(True)
            solo.setChecked(soloed)
            mute.clicked.connect(lambda checked=False, wt=wave_id: self._graphical_toggle_wave_mute(wt))
            solo.clicked.connect(lambda checked=False, wt=wave_id: self._set_wave_solo(wt, True))
            duplicate.clicked.connect(lambda checked=False, wt=wave_id: self._graphical_duplicate_wave(wt))
            remove.clicked.connect(lambda checked=False, wt=wave_id: self._graphical_remove_wave(wt))
            row_layout.addWidget(actions)

            body = GraphicalWaveCard(wave_id)
            body.setObjectName("graphicalWaveCardBody")
            body.waveSelected.connect(self._graphical_select_wave)
            body_layout = QVBoxLayout(body)
            body_layout.setContentsMargins(6, 6, 6, 6)
            body_layout.setSpacing(0)
            canvas = GraphicalWaveLayerCanvas(wave_id)
            canvas.levelEdited.connect(self._graphical_set_wave_levels)
            canvas.waveSelected.connect(self._graphical_select_wave)
            label = wave_label_for(self._settings_from_ui(), wave_id) if hasattr(self, "note_combo") else wave_id
            shape = wave_shape_for(self._settings_from_ui(), wave_id) if hasattr(self, "note_combo") else wave_id
            start_db = self.wave_start_sliders[wave_id].value() / DB_SLIDER_SCALE
            end_db = self.wave_end_sliders[wave_id].value() / DB_SLIDER_SCALE
            canvas.set_state(label, shape, start_db, end_db, muted, soloed)
            self.graphical_wave_canvases[wave_id] = canvas
            self.graphical_wave_cards[wave_id] = row
            body_layout.addWidget(canvas, 1)
            row_layout.addWidget(body, 1)
            layout.addWidget(row)

    def _refresh_graphical_chain_editor(self) -> None:
        selected_index = self.articulation_selected_chain_index
        if isinstance(selected_index, int) and 0 <= selected_index < len(self.articulation_chain_items):
            selected = selected_index
        else:
            selected = None
        if self.graphical_chain_canvas is not None:
            self.graphical_chain_canvas.set_items(self.articulation_chain_items, selected)
        if self.graphical_chain_mouth_canvas is not None:
            if selected is not None:
                p = self.articulation_chain_items[selected].phoneme_for_render()
                name = p.name
            else:
                p = self.current_phoneme
                name = p.name
            self.graphical_chain_mouth_canvas.set_motion_state(p, name, playhead_fraction=0.0)

    def _graphical_set_wave_levels(self, wave_id: str, start_db: float, end_db: float) -> None:
        if wave_id not in self.wave_start_sliders or wave_id not in self.wave_end_sliders:
            return
        self.wave_start_sliders[wave_id].setValue(int(round(float(start_db) * DB_SLIDER_SCALE)))
        self.wave_end_sliders[wave_id].setValue(int(round(float(end_db) * DB_SLIDER_SCALE)))
        self._update_wave_envelope_labels(wave_id)
        self._schedule_generate("graphical_wave_level")
        self._refresh_graphical_editor()

    def _graphical_add_wave_layer(self, checked: bool = False) -> None:
        del checked
        self._add_user_wave_row()
        self._refresh_graphical_editor()

    def _graphical_duplicate_loudest_wave(self, checked: bool = False) -> None:
        del checked
        if not self.wave_row_order:
            return
        loudest = max(self.wave_row_order, key=lambda wt: max(self.wave_start_sliders[wt].value(), self.wave_end_sliders[wt].value()))
        self._graphical_duplicate_wave(loudest)

    def _graphical_duplicate_wave(self, wave_id: str) -> None:
        if len(self.wave_row_order) >= MAX_WAVE_ROWS or wave_id not in self.wave_start_sliders:
            return
        before = set(self.wave_row_order)
        self._add_user_wave_row()
        new_ids = [wt for wt in self.wave_row_order if wt not in before]
        if not new_ids:
            return
        new_id = new_ids[-1]
        for src, dst in ((self.wave_start_sliders, self.wave_start_sliders), (self.wave_end_sliders, self.wave_end_sliders), (self.wave_time_sliders, self.wave_time_sliders), (self.wave_pan_sliders, self.wave_pan_sliders), (self.wave_width_sliders, self.wave_width_sliders), (self.wave_dance_sliders, self.wave_dance_sliders)):
            dst[new_id].setValue(src[wave_id].value())
        if wave_id in self.wave_shape_combos and new_id in self.wave_shape_combos:
            shape_index = self.wave_shape_combos[new_id].findData(wave_shape_for(self._settings_from_ui(), wave_id))
            self.wave_shape_combos[new_id].setCurrentIndex(max(0, shape_index))
        self._schedule_generate("graphical_duplicate_wave")
        self._refresh_graphical_editor()

    def _graphical_wave_card_object_name(self, wave_id: str, muted: bool, soloed: bool) -> str:
        if wave_id == self.graphical_selected_wave_id:
            return "waveCardSelected"
        if soloed:
            return "waveCardSolo"
        if muted:
            return "waveCardMuted"
        return "waveCard"

    def _set_graphical_wave_card_visuals(self, card: QWidget, wave_id: str, muted: bool, soloed: bool) -> None:
        selected = wave_id == self.graphical_selected_wave_id
        card.setObjectName(self._graphical_wave_card_object_name(wave_id, muted, soloed))
        if selected:
            glow = QGraphicsDropShadowEffect(card)
            glow.setBlurRadius(24)
            glow.setColor(QColor(92, 219, 149, 150))
            glow.setOffset(0, 0)
            card.setGraphicsEffect(glow)
        else:
            card.setGraphicsEffect(None)
        card.style().unpolish(card)
        card.style().polish(card)
        card.update()

    def _refresh_graphical_wave_card_styles(self) -> None:
        solo_wave = self._solo_wave_from_ui() if hasattr(self, "wave_solo_buttons") else None
        for wave_id, card in self.graphical_wave_cards.items():
            muted = self.wave_mute_buttons.get(wave_id).isChecked() if wave_id in self.wave_mute_buttons else False
            self._set_graphical_wave_card_visuals(card, wave_id, muted, solo_wave == wave_id)

    def _graphical_select_wave(self, wave_id: str) -> None:
        if wave_id not in self.wave_row_order:
            return
        self.graphical_selected_wave_id = wave_id
        self._refresh_graphical_wave_card_styles()
        if self.graphical_status_label is not None:
            self.graphical_status_label.setText(f"Selected wave layer: {wave_label_for(self._settings_from_ui(), wave_id)}")

    def _graphical_toggle_wave_mute(self, wave_id: str) -> None:
        button = self.wave_mute_buttons.get(wave_id)
        if button is None:
            return
        self._set_wave_muted(wave_id, not button.isChecked())
        self._refresh_graphical_editor()

    def _graphical_remove_wave(self, wave_id: str) -> None:
        if wave_id in self.user_wave_ids:
            self._remove_user_wave_row(wave_id)
            self._refresh_graphical_editor()
        elif self.graphical_status_label is not None:
            self.graphical_status_label.setText("Default wave layers are kept for compatibility; mute them instead of removing them.")

    def _graphical_set_stereo_pan(self, pan_start: float, pan_end: float) -> None:
        self.pan_start_slider.setValue(int(round(float(pan_start) * 100 * PERCENT_SLIDER_SCALE)))
        self.pan_end_slider.setValue(int(round(float(pan_end) * 100 * PERCENT_SLIDER_SCALE)))
        self._schedule_generate("graphical_stereo_pan")
        self._refresh_graphical_editor()

    def _graphical_set_stereo_width(self, width_value: float) -> None:
        self.width_slider.setValue(int(round(float(width_value) * 100 * PERCENT_SLIDER_SCALE)))
        self._schedule_generate("graphical_stereo_width")
        self._refresh_graphical_editor()

    def _graphical_set_pitch_values(self, start_value: int, end_value: int) -> None:
        self.pitch_start.setValue(int(start_value))
        self.pitch_end.setValue(int(end_value))
        self._schedule_generate("graphical_pitch_curve")
        self._refresh_graphical_editor()

    def _graphical_set_articulation_value(self, key: str, value: float) -> None:
        if key == "voiced":
            if self.articulation_voiced_checkbox is not None:
                self.articulation_voiced_checkbox.setChecked(bool(value >= 0.5))
            self._articulation_slider_changed(key)
            self._refresh_graphical_editor()
            return
        slider = self.articulation_sliders.get(key)
        if slider is None:
            return
        raw = int(round(float(value))) if key == "voice_pitch" else int(round(float(value) * 100.0))
        slider.setValue(max(slider.minimum(), min(slider.maximum(), raw)))
        self._articulation_slider_changed(key)
        self._refresh_graphical_editor()

    def _graphical_set_chain_duration(self, index: int, duration_ms: int) -> None:
        if 0 <= index < len(self.articulation_chain_items):
            self.articulation_chain_items[index].duration_ms = int(np.clip(duration_ms, 80, 5000))
            self._refresh_articulation_chain_cards()
            self._refresh_graphical_editor()

    def _graphical_set_chain_transition(self, index: int, transition_ms: int) -> None:
        if 0 <= index < len(self.articulation_chain_items):
            self.articulation_chain_items[index].transition_ms = int(np.clip(transition_ms, 0, 250))
            self._refresh_articulation_chain_cards()
            self._refresh_graphical_editor()

    def _graphical_set_selected_chain_curve(self, curve: str) -> None:
        if curve not in ARTICULATION_TRANSITION_CURVES:
            return
        selected_index = self.articulation_selected_chain_index
        if isinstance(selected_index, int) and 0 <= selected_index < len(self.articulation_chain_items):
            self.articulation_chain_items[selected_index].transition_curve = curve
            self._refresh_articulation_chain_cards()
            self._refresh_graphical_editor()

    def _graphical_scrub_chain(self, playhead_ms: float) -> None:
        if self.graphical_chain_mouth_canvas is None:
            return
        self.articulation_playhead_ms = float(max(0.0, playhead_ms))
        phoneme, current_name, next_name, transition_progress, playhead, transition_ms, in_transition = self._motion_state_at_ms(self.articulation_playhead_ms)
        self.graphical_chain_mouth_canvas.set_motion_state(phoneme, current_name, next_name, transition_progress, playhead, transition_ms, in_transition)


    def _build_speech_assets_panel(self, context: str = "timeline") -> QWidget:
        """Create a visible Speech Assets panel backed by the existing Speech Bin data model."""
        panel = QWidget()
        panel.setObjectName("speechAssetsPanel")
        if context == "articulation_timeline":
            apply_articulation_picker_sidebar_width_policy(panel)
        else:
            panel.setMinimumWidth(300)
            if context in {"timeline", "library"}:
                panel.setMaximumWidth(380)
        layout = QVBoxLayout(panel)
        layout.setContentsMargins(10, 10, 10, 10)
        layout.setSpacing(8)

        title = QLabel("Speech Assets")
        title.setObjectName("timelineInspectorTitle")
        subtitle = QLabel("Created phonemes, syllables, words, and phrases. Create Word saves here; select an asset to preview or add it to the Timeline.")
        subtitle.setObjectName("timelineInspectorText")
        subtitle.setWordWrap(True)
        layout.addWidget(title)
        layout.addWidget(subtitle)

        filters = QTabWidget()
        filters.setObjectName("speechAssetFilterTabs")
        for label, item_filter in (
            ("All", "all"),
            ("Phonemes", "phoneme"),
            ("Syllables", "syllable"),
            ("Words", "word"),
            ("Phrases", "phrase"),
        ):
            page = QWidget()
            page_layout = QVBoxLayout(page)
            page_layout.setContentsMargins(4, 6, 4, 4)
            page_layout.setSpacing(8)
            if item_filter == "word":
                actions = QHBoxLayout()
                add_word = QPushButton("Add Word")
                add_word.clicked.connect(lambda checked=False: self._timeline_add_first_speech_type_to_playhead("word"))
                clear = QPushButton("Clear")
                clear.clicked.connect(self._timeline_clear_speech_bin)
                actions.addWidget(add_word)
                actions.addWidget(clear)
                page_layout.addLayout(actions)
            count_label = QLabel("No created speech yet.")
            count_label.setObjectName("timelineInspectorText")
            count_label.setWordWrap(True)
            if context == "timeline" and item_filter == "all":
                self.timeline_speech_count_label = count_label
            page_layout.addWidget(count_label)
            scroll = WaveToyScrollArea(scroll_speed=0.9)
            list_widget = QWidget()
            list_widget.setObjectName("timelineSpeechBinList")
            if context == "timeline" and item_filter == "all":
                self.timeline_speech_bin_widget = list_widget
            scroll.setWidget(list_widget)
            page_layout.addWidget(scroll, 1)
            self.speech_asset_list_widgets.append((list_widget, item_filter))
            filters.addTab(page, label)
        layout.addWidget(filters, 1)
        return panel

    def _normalized_performance_snapshot(self, snapshot: PerformanceEditSnapshot) -> PerformanceEditSnapshot:
        tracks = [TimelineParameterTrack.from_json_dict(item) for item in snapshot.timeline_tracks if isinstance(item, dict)]
        return PerformanceEditSnapshot(
            timeline_tracks=[track.to_json_dict() for track in _deduplicated_timeline_tracks(tracks)],
            musical_timing_settings=MusicalTimingSettings.from_json_dict(snapshot.musical_timing_settings).to_json_dict(),
            selected_track_id=snapshot.selected_track_id,
            selected_point_index=snapshot.selected_point_index,
        )

    def _performance_edit_snapshot(self) -> PerformanceEditSnapshot:
        """Capture JSON-safe performance timeline state for in-memory undo/redo."""
        engine = self.performance_timeline_engine
        return self._normalized_performance_snapshot(
            PerformanceEditSnapshot(
                timeline_tracks=[track.to_json_dict() for track in engine.timeline_tracks],
                musical_timing_settings=self.musical_timing_settings.to_json_dict(),
                selected_track_id=engine.selected_track_id,
                selected_point_index=engine.selected_point_index,
            )
        )

    def _performance_snapshot_key(self, snapshot: PerformanceEditSnapshot, *, include_selection: bool = True) -> str:
        payload = self._normalized_performance_snapshot(snapshot).to_json_dict()
        if not include_selection:
            payload.pop("selected_track_id", None)
            payload.pop("selected_point_index", None)
        return json.dumps(payload, sort_keys=True, separators=(",", ":"))

    def _performance_affected_track_ids(self, before: PerformanceEditSnapshot, after: PerformanceEditSnapshot) -> List[str]:
        before_ids = {str(track.get("track_id")) for track in before.timeline_tracks if isinstance(track, dict)}
        after_ids = {str(track.get("track_id")) for track in after.timeline_tracks if isinstance(track, dict)}
        return sorted(track_id for track_id in before_ids | after_ids if track_id)

    def _push_performance_transaction(self, label: str, reason: str, before: PerformanceEditSnapshot) -> None:
        if self._performance_restoring_transaction:
            return
        before = self._normalized_performance_snapshot(before)
        after = self._performance_edit_snapshot()
        if self._performance_snapshot_key(before, include_selection=False) == self._performance_snapshot_key(after, include_selection=False):
            return
        label = str(label or "Performance Edit")
        reason = str(reason or label or "performance timeline edited")
        now = time.monotonic()
        can_coalesce = (
            label == "Musical Timing Change"
            and self.performance_undo_stack
            and not self.performance_redo_stack
            and self.performance_undo_stack[-1].label == label
            and now - self._last_performance_transaction_monotonic <= PERFORMANCE_TIMING_TRANSACTION_COALESCE_SECONDS
        )
        if can_coalesce:
            transaction = self.performance_undo_stack[-1]
            transaction.after_state = after
            transaction.affected_track_ids = self._performance_affected_track_ids(transaction.before_state, after)
            transaction.created_at = _utc_now_iso()
        else:
            transaction = PerformanceEditTransaction(
                label=label,
                reason=reason,
                before_state=before,
                after_state=after,
                affected_track_ids=self._performance_affected_track_ids(before, after),
            )
            self.performance_undo_stack.append(transaction)
            if len(self.performance_undo_stack) > self.performance_undo_stack_limit:
                self.performance_undo_stack = self.performance_undo_stack[-self.performance_undo_stack_limit:]
        self._last_performance_transaction_monotonic = now
        self.performance_redo_stack.clear()
        self.performance_last_undo_redo_label = f"Undo available: {transaction.label}"
        self._update_performance_undo_actions()

    def _begin_performance_transaction(self, label: str, reason: str | None = None) -> None:
        if self._performance_pending_transaction is None:
            self._performance_pending_transaction = (str(label or "Performance Edit"), str(reason or label or "performance timeline edited"), self._performance_edit_snapshot())

    def _commit_performance_transaction(self) -> None:
        if self._performance_pending_transaction is None:
            return
        label, reason, before = self._performance_pending_transaction
        self._performance_pending_transaction = None
        self._push_performance_transaction(label, reason, before)

    def _refresh_musical_timing_controls(self) -> None:
        """Reflect restored musical timing settings without creating more transactions."""
        widgets = [
            getattr(self, "musical_timing_enabled_checkbox", None),
            getattr(self, "musical_bpm_spin", None),
            getattr(self, "musical_time_signature_combo", None),
            getattr(self, "musical_snap_combo", None),
            getattr(self, "musical_count_in_checkbox", None),
            getattr(self, "musical_grid_checkbox", None),
        ]
        for widget in widgets:
            if widget is not None:
                widget.blockSignals(True)
        try:
            if getattr(self, "musical_timing_enabled_checkbox", None) is not None:
                self.musical_timing_enabled_checkbox.setChecked(self.musical_timing_settings.enabled)
            if getattr(self, "musical_bpm_spin", None) is not None:
                self.musical_bpm_spin.setValue(float(self.musical_timing_settings.bpm))
            if getattr(self, "musical_time_signature_combo", None) is not None:
                self.musical_time_signature_combo.setCurrentText(f"{self.musical_timing_settings.time_signature_numerator}/{self.musical_timing_settings.time_signature_denominator}")
            if getattr(self, "musical_snap_combo", None) is not None:
                self.musical_snap_combo.setCurrentText(self.musical_timing_settings.snap_subdivision if self.musical_timing_settings.snap_enabled else "Off")
            if getattr(self, "musical_count_in_checkbox", None) is not None:
                self.musical_count_in_checkbox.setChecked(self.musical_timing_settings.count_in_enabled)
            if getattr(self, "musical_grid_checkbox", None) is not None:
                self.musical_grid_checkbox.setChecked(self.musical_timing_settings.grid_visible)
        finally:
            for widget in widgets:
                if widget is not None:
                    widget.blockSignals(False)

    def _apply_performance_edit_snapshot(self, snapshot: PerformanceEditSnapshot, reason: str) -> None:
        snapshot = self._normalized_performance_snapshot(snapshot)
        tracks = [TimelineParameterTrack.from_json_dict(item) for item in snapshot.timeline_tracks if isinstance(item, dict)]
        bridge_tracks = [track for track in tracks if _is_timeline_bridge_track_id(track.track_id)]
        base_tracks = [track for track in tracks if not _is_timeline_bridge_track_id(track.track_id)]
        self._performance_restoring_transaction = True
        try:
            for track in bridge_tracks:
                if track.track_id == "stress_bridge_syllable_markers":
                    write_stress_timeline_track_to_syllable_stress_markers(track, self.syllable_stress_markers)
                elif track.track_id == "pitch_bridge_pitch_curve":
                    write_pitch_timeline_track_to_pitch_automation_points(track, self.pitch_automation_points)
            self.musical_timing_settings = MusicalTimingSettings.from_json_dict(snapshot.musical_timing_settings)
            self.performance_timeline_engine.set_musical_timing_settings(self.musical_timing_settings)
            self.performance_timeline_engine.set_tracks(base_tracks, reason=reason, sync_bridge_lanes=False)
            self._sync_timeline_bridges()
            self.performance_timeline_engine.set_selected_point(snapshot.selected_track_id, snapshot.selected_point_index)
            self.performance_timeline_engine.invalidate_runtime_cache(reason)
            self._sync_automation_tracks_from_timeline()
            self._sync_performance_state_from_engine()
            self.articulation_word_render_settings["musical_timing_settings"] = self.musical_timing_settings.to_json_dict()
            self._refresh_musical_timing_controls()
            if self.articulation_timeline_canvas is not None:
                self.articulation_timeline_canvas.set_musical_timing_settings(self.musical_timing_settings)
            self._mark_project_dirty(reason)
            self.articulation_word_render_audio = np.zeros((0, 2), dtype=np.float32)
            self.articulation_word_render_signature = None
            self.articulation_last_word_render_path = None
            self.articulation_last_word_render_created_at = None
            self._update_articulation_word_status()
            self._refresh_performance_tables()
            self._update_articulation_waveform_diagnostics_canvas()
            self._update_speech_diagnostics_panel(self.current_phoneme)
        finally:
            self._performance_restoring_transaction = False

    def _undo_performance_edit(self, checked: bool = False) -> None:
        del checked
        if not self.performance_undo_stack:
            self.performance_last_undo_redo_label = "Nothing to undo"
            self._update_performance_undo_actions()
            self._update_performance_status()
            return
        transaction = self.performance_undo_stack.pop()
        self.performance_redo_stack.append(transaction)
        self._apply_performance_edit_snapshot(transaction.before_state, f"undo: {transaction.reason}")
        self.performance_last_undo_redo_label = f"Undid: {transaction.label}"
        self._update_performance_undo_actions()
        self._update_performance_status()

    def _redo_performance_edit(self, checked: bool = False) -> None:
        del checked
        if not self.performance_redo_stack:
            self.performance_last_undo_redo_label = "Nothing to redo"
            self._update_performance_undo_actions()
            self._update_performance_status()
            return
        transaction = self.performance_redo_stack.pop()
        self.performance_undo_stack.append(transaction)
        self._apply_performance_edit_snapshot(transaction.after_state, f"redo: {transaction.reason}")
        self.performance_last_undo_redo_label = f"Redid: {transaction.label}"
        self._update_performance_undo_actions()
        self._update_performance_status()

    def _update_performance_undo_actions(self) -> None:
        if self.performance_undo_action is not None:
            label = self.performance_undo_stack[-1].label if self.performance_undo_stack else "Performance Edit"
            self.performance_undo_action.setText(f"Undo Performance Edit: {label}" if self.performance_undo_stack else "Undo Performance Edit")
            self.performance_undo_action.setEnabled(bool(self.performance_undo_stack))
        if self.performance_redo_action is not None:
            label = self.performance_redo_stack[-1].label if self.performance_redo_stack else "Performance Edit"
            self.performance_redo_action.setText(f"Redo Performance Edit: {label}" if self.performance_redo_stack else "Redo Performance Edit")
            self.performance_redo_action.setEnabled(bool(self.performance_redo_stack))

    def _performance_asset_snapshot(self) -> PerformanceAsset:
        self._sync_timeline_bridges()
        self.performance_asset.timeline_tracks = list(self.performance_timeline_engine.timeline_tracks)
        self.performance_asset.modified_at = _utc_now_iso()
        self.performance_asset.version = 2
        self._sync_automation_tracks_from_timeline()
        return self.performance_asset

    def _timeline_tracks_json(self) -> List[Dict[str, object]]:
        self._sync_timeline_bridges()
        return [track.to_json_dict() for track in self.timeline_tracks]

    def _automation_tracks_json(self) -> List[Dict[str, object]]:
        self._sync_automation_tracks_from_timeline()
        return [track.to_json_dict() for track in self.automation_tracks]

    def _sync_automation_tracks_from_timeline(self) -> None:
        self.automation_tracks = [track.to_automation_track() for track in self.timeline_tracks if track.track_kind == "automation"]

    def _sync_performance_state_from_engine(self) -> None:
        self.selected_automation_track_id = self.performance_timeline_engine.selected_track_id
        self.selected_timeline_point_index = self.performance_timeline_engine.selected_point_index
        self.performance_playhead_ms = self.performance_timeline_engine.playhead_ms

    def _performance_engine_playhead_changed(self, engine: PerformanceTimelineEngine) -> None:
        self._sync_performance_state_from_engine()

    def _performance_engine_selection_changed(self, engine: PerformanceTimelineEngine) -> None:
        self._sync_performance_state_from_engine()

    def _performance_engine_tracks_changed(self, engine: PerformanceTimelineEngine) -> None:
        self.timeline_tracks = engine.timeline_tracks
        self._sync_automation_tracks_from_timeline()
        self._sync_performance_state_from_engine()

    def _performance_engine_diagnostics_changed(self, engine: PerformanceTimelineEngine) -> None:
        self._sync_performance_state_from_engine()

    def _selected_timeline_track(self) -> TimelineParameterTrack | None:
        track = self.performance_timeline_engine.selected_track()
        if track is not None:
            self._sync_performance_state_from_engine()
            return track
        if self.timeline_tracks:
            self.performance_timeline_engine.set_selected_track(self.timeline_tracks[0].track_id)
            self._sync_performance_state_from_engine()
            return self.performance_timeline_engine.selected_track()
        self.performance_timeline_engine.clear_selection()
        self._sync_performance_state_from_engine()
        return None

    def _selected_automation_track(self) -> TimelineParameterTrack | None:
        return self._selected_timeline_track()

    def _sync_timeline_bridges(self) -> None:
        self.performance_timeline_engine.set_musical_timing_settings(self.musical_timing_settings)
        self.timeline_tracks = self.performance_timeline_engine.sync_bridges(self.pitch_automation_points, self.syllable_stress_markers)
        self.performance_asset.timeline_tracks = self.timeline_tracks
        self._sync_automation_tracks_from_timeline()
        self._sync_performance_state_from_engine()

    def _apply_bridge_track_edits(self, track: TimelineParameterTrack) -> None:
        self.performance_timeline_engine.apply_bridge_track_edits(track, self.pitch_automation_points, self.syllable_stress_markers)
        self.timeline_tracks = self.performance_timeline_engine.timeline_tracks
        self._sync_performance_state_from_engine()

    def _mark_performance_dirty(self, reason: str = "performance timeline changed") -> None:
        self.performance_timeline_engine.mark_tracks_dirty(reason)
        self._sync_automation_tracks_from_timeline()
        self._mark_project_dirty(reason)
        self.articulation_word_render_audio = np.zeros((0, 2), dtype=np.float32)
        self.articulation_word_render_signature = None
        self.articulation_last_word_render_path = None
        self.articulation_last_word_render_created_at = None
        self._update_articulation_word_status()
        self._refresh_performance_canvas()
        self._update_performance_status()
        self._update_articulation_waveform_diagnostics_canvas()

    def _default_automation_track_name(self, target_parameter: str) -> str:
        return target_parameter.replace("_", " ").title()

    def _performance_snap_enabled(self) -> bool:
        return bool(self.performance_snap_checkbox is not None and self.performance_snap_checkbox.isChecked())

    def _performance_grid_ms(self) -> int:
        settings = self.performance_timeline_engine.musical_timing_settings
        beat_ms = note_value_to_ms(settings.snap_subdivision, settings) if settings.enabled and settings.snap_enabled else settings.beat_unit_ms if settings.enabled else 250.0
        return max(1, int(round(beat_ms)))

    def _clamp_timeline_point(self, track: TimelineParameterTrack, point: TimelineParameterPoint) -> None:
        low, high = _timeline_value_range(track.target_parameter, track.track_kind)
        point.time_ms = int(max(0, round(float(point.time_ms))))
        point.value = float(np.clip(point.value, low, high))
        if point.curve not in AUTOMATION_CURVES:
            point.curve = "linear"

    def _add_automation_track(self, checked: bool = False) -> None:
        del checked
        targets = [target for lane_targets in AUTOMATION_TARGET_PARAMETERS.values() for target in lane_targets]
        target, ok = QInputDialog.getItem(self, "Add Timeline Track", "Target parameter:", targets, targets.index("accentuation_db"), False)
        if not ok or not target:
            return
        color = AUTOMATION_DEFAULT_COLORS[len(self.timeline_tracks) % len(AUTOMATION_DEFAULT_COLORS)]
        track = TimelineParameterTrack(
            name=self._default_automation_track_name(target),
            track_kind="automation",
            target_parameter=target,
            color=color,
            lane_order=len(self.timeline_tracks),
        )
        if target in {"accentuation_db", "pitch_bias_cents"}:
            track.points.append(TimelineParameterPoint(time_ms=0, value=0.0, curve="linear"))
        before = self._performance_edit_snapshot()
        self.timeline_tracks.append(track)
        self.performance_timeline_engine.set_tracks(self.timeline_tracks, reason="timeline track added")
        self.performance_timeline_engine.set_selected_point(track.track_id, 0 if track.points else None)
        self._sync_performance_state_from_engine()
        self._refresh_performance_tables()
        self._mark_performance_dirty("timeline track added")
        self._push_performance_transaction("Add Track", "timeline track added", before)

    def _delete_selected_automation_track(self, checked: bool = False) -> None:
        del checked
        track = self._selected_timeline_track()
        if track is None:
            QMessageBox.information(self, "Performance", "Select a timeline track first.")
            return
        if track.track_kind in {"stress", "pitch"} and str(track.track_id).startswith(("stress_bridge_", "pitch_bridge_")):
            QMessageBox.information(self, "Performance", "Bridge lanes are derived from existing stress or pitch data; delete the source data instead.")
            return
        before = self._performance_edit_snapshot()
        self.timeline_tracks = [item for item in self.timeline_tracks if item.track_id != track.track_id]
        self.performance_timeline_engine.set_tracks(self.timeline_tracks, reason="timeline track deleted")
        self.timeline_tracks = self.performance_timeline_engine.timeline_tracks
        self.performance_asset.timeline_tracks = self.timeline_tracks
        self.performance_timeline_engine.set_selected_point(self.timeline_tracks[0].track_id if self.timeline_tracks else None, None)
        self._sync_performance_state_from_engine()
        self._refresh_performance_tables()
        self._mark_performance_dirty("timeline track deleted")
        self._push_performance_transaction("Delete Track", "timeline track deleted", before)

    def _add_automation_point(self, checked: bool = False) -> None:
        del checked
        track = self._selected_timeline_track()
        if track is None:
            QMessageBox.information(self, "Performance", "Add or select a timeline track first.")
            return
        before = self._performance_edit_snapshot()
        next_time = (track.points[-1].time_ms + 250) if track.points else 0
        point = TimelineParameterPoint(time_ms=next_time, value=0.0, curve="linear")
        self._clamp_timeline_point(track, point)
        track.points.append(point)
        track.points.sort(key=lambda item: item.time_ms)
        self.performance_timeline_engine.set_selected_point(track.track_id, track.points.index(point))
        self._sync_performance_state_from_engine()
        self._apply_bridge_track_edits(track)
        self._refresh_performance_tables()
        self._mark_performance_dirty("timeline point added")
        self._push_performance_transaction("Add Point", "timeline point added", before)

    def _add_timeline_point_from_canvas(self, track_id: str, time_ms: int, value: float) -> None:
        track = next((item for item in self.timeline_tracks if item.track_id == track_id), None)
        if track is None:
            return
        before = self._performance_edit_snapshot()
        point = TimelineParameterPoint(time_ms=time_ms, value=value, curve="linear")
        self._clamp_timeline_point(track, point)
        track.points.append(point)
        track.points.sort(key=lambda item: item.time_ms)
        self._apply_bridge_track_edits(track)
        self._select_timeline_point(track.track_id, track.points.index(point))
        self._refresh_performance_tables()
        self._mark_performance_dirty("timeline point double-click added")
        self._push_performance_transaction("Add Point", "timeline point double-click added", before)

    def _remove_selected_automation_point(self, checked: bool = False) -> None:
        del checked
        track = self._selected_timeline_track()
        row = self.selected_timeline_point_index
        if row is None and self.automation_points_table is not None:
            row = self.automation_points_table.currentRow()
        if track is None or row is None or row < 0 or row >= len(track.points):
            QMessageBox.information(self, "Performance", "Select a timeline point first.")
            return
        before = self._performance_edit_snapshot()
        del track.points[row]
        self.performance_timeline_engine.set_selected_point(track.track_id, min(row, len(track.points) - 1) if track.points else None)
        self._sync_performance_state_from_engine()
        self._apply_bridge_track_edits(track)
        self._refresh_performance_tables()
        self._mark_performance_dirty("timeline point removed")
        self._push_performance_transaction("Delete Point", "timeline point removed", before)

    def _select_timeline_point(self, track_id: str, point_index: int | None) -> None:
        self.performance_timeline_engine.set_selected_point(track_id, point_index)
        self._sync_performance_state_from_engine()
        self._refresh_automation_points_table()
        if self.automation_track_table is not None:
            selected_row = next((idx for idx, track in enumerate(self.timeline_tracks) if track.track_id == track_id), -1)
            if selected_row >= 0:
                self.automation_track_table.selectRow(selected_row)
        clamped_point_index = self.selected_timeline_point_index
        if self.automation_points_table is not None and clamped_point_index is not None and clamped_point_index >= 0:
            self.automation_points_table.selectRow(clamped_point_index)
        self._refresh_performance_canvas()
        self._update_performance_status()
        self._update_articulation_waveform_diagnostics_canvas()

    def _move_timeline_point_from_canvas(self, track_id: str, point_index: int, time_ms: int, y: float) -> None:
        track = next((item for item in self.timeline_tracks if item.track_id == track_id), None)
        if track is None or not (0 <= point_index < len(track.points)) or self.performance_timeline_canvas is None:
            return
        tracks = self.performance_timeline_canvas._tracks()
        lane = self.performance_timeline_canvas._lane_rect(tracks.index(track), len(tracks)) if track in tracks else QRectF()
        before = None if self._performance_pending_transaction is not None else self._performance_edit_snapshot()
        point = track.points[point_index]
        point.time_ms = time_ms
        point.value = self.performance_timeline_canvas._value_for_y(track, y, lane)
        self._clamp_timeline_point(track, point)
        track.points.sort(key=lambda item: item.time_ms)
        self.performance_timeline_engine.set_selected_point(track.track_id, track.points.index(point))
        self._sync_performance_state_from_engine()
        self._apply_bridge_track_edits(track)
        self._refresh_performance_tables()
        self._mark_performance_dirty("timeline point dragged")
        if before is not None:
            self._push_performance_transaction("Move Point", "timeline point dragged", before)

    def _set_performance_playhead_ms(self, time_ms: int, *, scrub: bool = False) -> None:
        self.performance_timeline_engine.scrub_to_ms(time_ms) if scrub else self.performance_timeline_engine.set_playhead_ms(time_ms, reason="articulation playback")
        self._sync_performance_state_from_engine()
        if scrub:
            self.articulation_playhead_ms = float(self.performance_playhead_ms)
            if hasattr(self, "articulation_motion_timeline") and self.articulation_motion_timeline is not None:
                self.articulation_motion_timeline.set_playhead_ms(self.articulation_playhead_ms)
        self._refresh_performance_canvas()
        self._update_performance_status()
        self._update_articulation_waveform_diagnostics_canvas()
        self._update_speech_diagnostics_panel(self.current_phoneme)

    def _automation_track_row_selected(self, row: int, column: int = 0) -> None:
        del column
        if 0 <= row < len(self.timeline_tracks):
            self._select_timeline_point(self.timeline_tracks[row].track_id, self.performance_timeline_engine.selected_point_index)

    def _automation_track_table_changed(self, row: int, column: int) -> None:
        if not (0 <= row < len(self.timeline_tracks)):
            return
        item = self.automation_track_table.item(row, column) if self.automation_track_table is not None else None
        if item is None:
            return
        before = self._performance_edit_snapshot()
        label = "Rename Track" if column == 1 else "Mute Track" if column == 4 else "Toggle Track Visibility" if column == 5 else "Edit Track"
        track = self.timeline_tracks[row]
        if column == 1:
            track.name = item.text().strip() or track.name
        elif column == 4:
            track.muted = item.checkState() == Qt.Checked
        elif column == 5:
            track.visible = item.checkState() == Qt.Checked
        self._refresh_performance_canvas()
        self._mark_performance_dirty("timeline track edited")
        self._push_performance_transaction(label, "timeline track edited", before)

    def _automation_point_table_changed(self, row: int, column: int) -> None:
        track = self._selected_timeline_track()
        if track is None or not (0 <= row < len(track.points)):
            return
        item = self.automation_points_table.item(row, column) if self.automation_points_table is not None else None
        if item is None:
            return
        before = self._performance_edit_snapshot()
        label = "Move Point" if column == 0 else "Edit Point Value" if column == 1 else "Edit Point Curve" if column == 2 else "Edit Point"
        point = track.points[row]
        try:
            if column == 0:
                point.time_ms = int(max(0, round(float(item.text()))))
            elif column == 1:
                point.value = float(item.text())
            elif column == 2:
                curve = item.text().strip().lower()
                point.curve = curve if curve in AUTOMATION_CURVES else "linear"
        except ValueError:
            self._refresh_automation_points_table()
            return
        self._clamp_timeline_point(track, point)
        track.points.sort(key=lambda item: item.time_ms)
        self.performance_timeline_engine.set_selected_point(track.track_id, min(row, len(track.points) - 1))
        self._sync_performance_state_from_engine()
        self._apply_bridge_track_edits(track)
        self._refresh_automation_points_table()
        self._mark_performance_dirty("timeline point edited")
        self._push_performance_transaction(label, "timeline point edited", before)

    def _refresh_performance_tables(self) -> None:
        self._sync_timeline_bridges()
        self._refresh_automation_track_table()
        self._refresh_automation_points_table()
        self._refresh_performance_canvas()
        self._update_performance_status()

    def _refresh_performance_canvas(self) -> None:
        if self.performance_timeline_canvas is not None:
            self.performance_timeline_canvas.update()

    def _refresh_automation_track_table(self) -> None:
        if self.automation_track_table is None:
            return
        self.automation_track_table.blockSignals(True)
        self.automation_track_table.setRowCount(len(self.timeline_tracks))
        for row, track in enumerate(sorted(self.timeline_tracks, key=lambda item: item.lane_order)):
            values = [track.color, track.name, track.target_parameter, track.track_kind, "", "", str(len(track.points))]
            for column, value in enumerate(values):
                item = QTableWidgetItem(value)
                if column in {0, 2, 3, 6}:
                    item.setFlags(item.flags() & ~Qt.ItemIsEditable)
                if column == 4:
                    item.setFlags((item.flags() | Qt.ItemIsUserCheckable) & ~Qt.ItemIsEditable)
                    item.setCheckState(Qt.Checked if track.muted else Qt.Unchecked)
                    item.setText("Muted")
                if column == 5:
                    item.setFlags((item.flags() | Qt.ItemIsUserCheckable) & ~Qt.ItemIsEditable)
                    item.setCheckState(Qt.Checked if track.visible else Qt.Unchecked)
                    item.setText("Visible")
                self.automation_track_table.setItem(row, column, item)
        selected_row = next((idx for idx, track in enumerate(sorted(self.timeline_tracks, key=lambda item: item.lane_order)) if track.track_id == self.selected_automation_track_id), -1)
        if selected_row >= 0:
            self.automation_track_table.selectRow(selected_row)
        self.automation_track_table.resizeColumnsToContents()
        self.automation_track_table.blockSignals(False)

    def _refresh_automation_points_table(self) -> None:
        if self.automation_points_table is None:
            return
        track = self._selected_timeline_track()
        points = track.points if track is not None else []
        self.automation_points_table.blockSignals(True)
        self.automation_points_table.setRowCount(len(points))
        for row, point in enumerate(points):
            for column, value in enumerate([point.time_ms, point.value, point.curve]):
                item = QTableWidgetItem(str(value))
                self.automation_points_table.setItem(row, column, item)
        if self.selected_timeline_point_index is not None and 0 <= self.selected_timeline_point_index < len(points):
            self.automation_points_table.selectRow(self.selected_timeline_point_index)
        self.automation_points_table.resizeColumnsToContents()
        self.automation_points_table.blockSignals(False)

    def _update_performance_status(self) -> None:
        track = self._selected_timeline_track()
        compiled_tracks_now = self.performance_timeline_engine.compile_tracks()
        diagnostics = self.performance_timeline_engine.diagnostics()
        if self.automation_status_label is not None:
            accent_tracks = [item for item in self.timeline_tracks if item.target_parameter == "accentuation_db" and not item.muted]
            pitch_tracks = [item for item in self.timeline_tracks if item.target_parameter == "pitch_bias_cents" and not item.muted]
            value = self._selected_track_value_at_playhead()
            value_text = f" sampled={value:.3f}" if value is not None else " sampled=—"
            selected = f"Selected: {track.name} → {track.target_parameter}{value_text}" if track is not None else "No selected track"
            self.automation_status_label.setText(
                f"{len(self.timeline_tracks)} visible/editable timeline lane(s). {selected}. Playhead {self.performance_playhead_ms} ms. "
                f"Render applies {len(accent_tracks)} accentuation_db and {len(pitch_tracks)} pitch_bias_cents lane(s) non-destructively. "
                f"Runtime {diagnostics.get('backend')} • compiled {diagnostics.get('active_compiled_track_count')}/{diagnostics.get('compiled_track_count')} • "
                f"cache hit/miss {diagnostics.get('cache_hits')}/{diagnostics.get('cache_misses')} • "
                f"last envelope {diagnostics.get('last_generation_ms')} ms • hash {str(diagnostics.get('timeline_hash', ''))[:10]} • "
                f"{self.performance_last_undo_redo_label}"
            )
        if self.performance_runtime_inspector_label is not None:
            if track is None:
                self.performance_runtime_inspector_label.setText("Runtime inspector: no selected track.")
            else:
                compiled = next((item for item in compiled_tracks_now if item.track_id == track.track_id), compile_timeline_track(track))
                value = self.performance_timeline_engine.evaluate_track(compiled.track_id, self.performance_playhead_ms)
                values = [float(point.value) for point in compiled.points]
                low = min(values) if values else 0.0
                high = max(values) if values else 0.0
                value_text = f"{value:.3f}" if value is not None else "—"
                self.performance_runtime_inspector_label.setText(
                    f"Runtime inspector — {track.name} • target {track.target_parameter} • points {len(compiled.points)} • "
                    f"segments {len(compiled.segments)} • current {value_text} • "
                    f"min {low:.3f} • max {high:.3f} • muted {track.muted} • visible {track.visible} • "
                    f"source {compiled.source_hash[:10]}"
                )


    def _save_current_performance_to_library(self, checked: bool = False) -> None:
        del checked
        name, ok = QInputDialog.getText(self, "Save Performance", "Performance asset name:", text=self.performance_asset.name or self.current_project_name)
        if not ok:
            return
        performance = self._performance_asset_snapshot()
        performance.name = name.strip() or "Untitled Performance"
        payload = performance.to_json_dict()
        self._save_library_asset("performance", performance.name, payload, description="Unified performance timeline snapshot")
        self._mark_performance_dirty("performance saved to library")
        QMessageBox.information(self, "Performance Library", f"Saved performance asset: {performance.name}")

    def _save_selected_automation_curve_to_library(self, checked: bool = False) -> None:
        del checked
        track = self._selected_timeline_track()
        if track is None:
            QMessageBox.information(self, "Performance", "Select a timeline track first.")
            return
        payload = {"track": track.to_json_dict(), "points": [point.to_json_dict() for point in track.points]}
        self._save_library_asset("automation_curve", track.name, payload, description=f"Timeline curve for {track.target_parameter}")

    def _automation_value_at_ms(self, track: TimelineParameterTrack | AutomationTrack, time_ms: np.ndarray) -> np.ndarray:
        if isinstance(track, AutomationTrack):
            track = TimelineParameterTrack.from_automation_track(track)
        frame_count = len(time_ms)
        if frame_count <= 0 or not track.points or track.muted:
            return np.zeros(frame_count, dtype=np.float32)
        compiled = compile_timeline_track(track)
        return np.array([evaluate_compiled_track(compiled, float(ms)) or 0.0 for ms in time_ms], dtype=np.float32)

    def automation_value_for_parameter(self, parameter: str, time_ms: float) -> float:
        return self.performance_timeline_engine.automation_value_for_parameter(parameter, time_ms)

    def automation_envelope_for_parameter(self, parameter: str, duration_ms: float, sample_rate: int = SAMPLE_RATE) -> np.ndarray:
        return self.performance_timeline_engine.automation_envelope_for_parameter(parameter, duration_ms, sample_rate)

    def _selected_track_value_at_playhead(self) -> float | None:
        return self.performance_timeline_engine.selected_track_value(self.performance_timeline_engine.playhead_ms)

    def _voiced_region_mask_for_pitch_bias(self, audio: np.ndarray) -> np.ndarray:
        if audio.size == 0:
            return np.zeros(0, dtype=np.float32)
        mono = np.mean(audio, axis=1) if audio.ndim == 2 else np.asarray(audio, dtype=np.float32)
        frame = max(128, int(SAMPLE_RATE * 0.02))
        hop = max(64, frame // 2)
        rms_values: List[float] = []
        zcr_values: List[float] = []
        centers: List[int] = []
        for start in range(0, len(mono), hop):
            chunk = mono[start:start + frame]
            if len(chunk) < 2:
                break
            rms_values.append(float(np.sqrt(np.mean(chunk * chunk))))
            zcr_values.append(float(np.mean(np.abs(np.diff(np.signbit(chunk).astype(np.int8))))))
            centers.append(start + len(chunk) // 2)
        if not rms_values:
            return np.zeros(len(mono), dtype=np.float32)
        rms = np.array(rms_values, dtype=np.float32)
        zcr = np.array(zcr_values, dtype=np.float32)
        threshold = max(0.01, float(np.max(rms)) * 0.12)
        frame_mask = ((rms >= threshold) & (zcr <= 0.22)).astype(np.float32)
        mask = np.interp(np.arange(len(mono)), np.array(centers, dtype=np.float32), frame_mask, left=frame_mask[0], right=frame_mask[-1]).astype(np.float32)
        smooth = max(1, int(SAMPLE_RATE * 0.005))
        if smooth > 1:
            kernel = np.ones(smooth, dtype=np.float32) / float(smooth)
            mask = np.convolve(mask, kernel, mode="same").astype(np.float32)
        return np.clip(mask, 0.0, 1.0).astype(np.float32)

    def _apply_pitch_bias_to_voiced_regions(self, audio: np.ndarray, cents: float) -> np.ndarray:
        shifted = self._pitch_shift_audio_constant(audio, cents)
        mask = self._voiced_region_mask_for_pitch_bias(audio)
        if mask.size != len(audio) or not np.any(mask > 0.05):
            return audio.astype(np.float32)
        if audio.ndim == 2:
            mask2 = mask[:, None]
        else:
            mask2 = mask
        return (audio * (1.0 - mask2) + shifted * mask2).astype(np.float32)

    def _apply_performance_automation_to_audio(self, audio: np.ndarray) -> np.ndarray:
        base_diagnostics = {
            "active_automation_targets": [],
            "accentuation_db_min": 0.0,
            "accentuation_db_max": 0.0,
            "pitch_bias_cents_min": 0.0,
            "pitch_bias_cents_max": 0.0,
            "pitch_bias_active": False,
        }
        if audio.size == 0:
            self.latest_automation_diagnostics = base_diagnostics
            return audio.astype(np.float32)
        self._sync_timeline_bridges()
        active_tracks = [track for track in self.timeline_tracks if track.track_kind == "automation" and not track.muted and track.points]
        duration_ms = (len(audio) * 1000.0) / float(SAMPLE_RATE)
        db_envelope = self.performance_timeline_engine.automation_envelope_for_parameter("accentuation_db", duration_ms, SAMPLE_RATE)[:len(audio)]
        pitch_envelope = self.performance_timeline_engine.automation_envelope_for_parameter("pitch_bias_cents", duration_ms, SAMPLE_RATE)[:len(audio)]
        rendered = np.array(audio, dtype=np.float32, copy=True)
        targets = sorted({track.target_parameter for track in active_tracks if track.target_parameter in {"accentuation_db", "pitch_bias_cents"}})
        pitch_active = bool(np.any(np.abs(pitch_envelope) > 0.1))
        if pitch_active:
            active_values = pitch_envelope[np.abs(pitch_envelope) > 0.1]
            conservative_cents = float(np.clip(np.median(active_values), -300.0, 300.0)) if active_values.size else 0.0
            rendered = self._apply_pitch_bias_to_voiced_regions(rendered, conservative_cents)
        if np.any(np.abs(db_envelope) > 0.001):
            gain = np.power(10.0, np.clip(db_envelope, -24.0, 24.0) / 20.0).astype(np.float32)
            rendered *= gain[:, None] if rendered.ndim == 2 else gain
        diagnostics = {
            "active_automation_targets": targets,
            "accentuation_db_min": round(float(np.min(db_envelope)), 3) if db_envelope.size else 0.0,
            "accentuation_db_max": round(float(np.max(db_envelope)), 3) if db_envelope.size else 0.0,
            "pitch_bias_cents_min": round(float(np.min(pitch_envelope)), 3) if pitch_envelope.size else 0.0,
            "pitch_bias_cents_max": round(float(np.max(pitch_envelope)), 3) if pitch_envelope.size else 0.0,
            "pitch_bias_active": pitch_active,
            **self.performance_timeline_engine.diagnostics(),
        }
        self.latest_automation_diagnostics = diagnostics
        if self.continuous_diagnostics_latest is not None:
            self.continuous_diagnostics_latest.update(diagnostics)
        return np.clip(rendered, -1.0, 1.0).astype(np.float32)

